-- Poems batch 174
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('08d7a382-6ee9-4592-accc-4e32a391cefd','卞將軍墓','曾極','宋','宋诗','song-poetry','','[]','握節顔公拳透爪，歸元先軫面如生。',32,'全唐诗/poet.song.170000.json','["握節顔公拳透爪，歸元先軫面如生。", "晉陵發掘今無主，獨有忠魂占冶城。"]'),
('538b8ece-08d5-4c8f-9868-0d5114fedc7a','張麗華墓','曾極','宋','宋诗','song-poetry','','[]','伴侶聲沉王氣銷，香魂血涴有誰招。',32,'全唐诗/poet.song.170000.json','["伴侶聲沉王氣銷，香魂血涴有誰招。", "蓬科三尺光塵在，猶作臺城花月妖。"]'),
('84c30358-44bf-41b4-8d20-f0fc79cdbe7c','臺城','曾極','宋','宋诗','song-poetry','','[]','紫蓋橫天整復斜，興亡接翅似昏鴉。',32,'全唐诗/poet.song.170000.json','["紫蓋橫天整復斜，興亡接翅似昏鴉。", "舊時石闕摩雲處，荻屋荆扉一兩家。"]'),
('ff433c13-00a4-4501-9988-8791a581f69f','宋受禪壇','曾極','宋','宋诗','song-poetry','','[]','赤紙藤書宋鼎歸，寄奴柴燎告功時。',32,'全唐诗/poet.song.170000.json','["赤紙藤書宋鼎歸，寄奴柴燎告功時。", "普天大慶交新主，唯有徐公雙淚垂。"]'),
('ac484fae-7c64-4e2f-b56a-7a7b17c679f0','南唐郊壇','曾極','宋','宋诗','song-poetry','','[]','上帝神兵破石頭，別離歌管六宮愁。',32,'全唐诗/poet.song.170000.json','["上帝神兵破石頭，別離歌管六宮愁。", "燔柴空有高壇在，乞與千年麋鹿遊。"]'),
('63ab508d-eed9-4f03-a086-59e8da667239','李氏宮','曾極','宋','宋诗','song-poetry','','[]','埋愁無地奈君何，可是黄壚飲恨多。',32,'全唐诗/poet.song.170000.json','["埋愁無地奈君何，可是黄壚飲恨多。", "玉鏡臺前棄脂水，深泉流汞尚盈科。"]'),
('cbd68db2-333b-4829-a39f-4c8cb79ddfd9','華隠樓','曾極','宋','宋诗','song-poetry','','[]','松聲聽罷獨看雲，華隠樓中控鶴身。',32,'全唐诗/poet.song.170000.json','["松聲聽罷獨看雲，華隠樓中控鶴身。", "治國神方難自獻，祗將本草語時人。"]'),
('7673b659-addf-41bc-9527-8ad878c83fa4','華林園','曾極','宋','宋诗','song-poetry','','[]','羽葆來臨鼓吹停，華林暢飲倒長瓶。',32,'全唐诗/poet.song.170000.json','["羽葆來臨鼓吹停，華林暢飲倒長瓶。", "萬年天子瞢騰眼，錯認長星作酒星。"]'),
('ed9b6648-6e99-4915-b686-0b2a34e2c54f','養種園','曾極','宋','宋诗','song-poetry','','[]','百花堂裏賞芳菲，江左霸臣淚濺衣。',32,'全唐诗/poet.song.170000.json','["百花堂裏賞芳菲，江左霸臣淚濺衣。", "腸斷上林桃李樹，春風一半未全歸。"]'),
('e0ec41d1-cb17-4f46-9904-8f8666aca85e','潑墨池','曾極','宋','宋诗','song-poetry','','[]','二酉珍儲已徧窺，仙班寧肯列愚癡。',32,'全唐诗/poet.song.170000.json','["二酉珍儲已徧窺，仙班寧肯列愚癡。", "注經穴石須勤苦，留得千年潑墨池。"]'),
('d5609db9-ed8b-4e8a-8fc6-c5f192397c78','商飈館','曾極','宋','宋诗','song-poetry','','[]','商飈基在昔人非，草木猶爲富貴移。',32,'全唐诗/poet.song.170000.json','["商飈基在昔人非，草木猶爲富貴移。", "曾是六朝歌舞地，黄花一半染胭脂。"]'),
('951d78c6-f0d6-4132-9ef2-fe88d560ae47','夢筆驛','曾極','宋','宋诗','song-poetry','','[]','晉尚清談筆力衰，文章高下亦隨時。',32,'全唐诗/poet.song.170000.json','["晉尚清談筆力衰，文章高下亦隨時。", "景純不作文通死，五色毛錐付與誰。"]'),
('4fbc6f91-ef98-43b5-a124-3d5f25e9e75b','蛇盤驛','曾極','宋','宋诗','song-poetry','','[]','枳籬華屋半雕殘，列肆屠羊客卸鞍。',32,'全唐诗/poet.song.170000.json','["枳籬華屋半雕殘，列肆屠羊客卸鞍。", "霸氣銷沉形影歇，龍盤何事作蛇盤。"]'),
('5a6fb7b9-7a95-4e2f-982a-5158c874e51c','射雉場','曾極','宋','宋诗','song-poetry','','[]','不整軍容北射狐，却資媒翳取歡娛。',32,'全唐诗/poet.song.170000.json','["不整軍容北射狐，却資媒翳取歡娛。", "山梁飲啄關何事，浪費君王金僕姑。"]'),
('24656b5b-33b5-46a0-aa65-ab13596a2cb4','烏衣巷','曾極','宋','宋诗','song-poetry','','[]','吳兵曾駐黑雲都，江左夷吾此卜居。',32,'全唐诗/poet.song.170000.json','["吳兵曾駐黑雲都，江左夷吾此卜居。", "休把烏衣輕馬巷，懸鶉結駟總丘墟。"]'),
('10a019dd-f178-4077-9781-6a25764b2174','鍾山番人窟','曾極','宋','宋诗','song-poetry','','[]','千羣鐵騎遠來侵，鑿穴鍾山用意深。',32,'全唐诗/poet.song.170000.json','["千羣鐵騎遠來侵，鑿穴鍾山用意深。", "天塹連空遮不斷，烟塵直到海中心。"]'),
('937bc2da-8559-4d8d-8501-ad099ccf490a','展上公','曾極','宋','宋诗','song-poetry','','[]','浩劫循環無始終，年年玉李杲春空。',32,'全唐诗/poet.song.170000.json','["浩劫循環無始終，年年玉李杲春空。", "初成未占茲山頂，古老唯傳展上公。"]'),
('04dfeb99-cbd1-4680-b524-d86c01fe74f9','東晉','曾極','宋','宋诗','song-poetry','','[]','斷簡殘編迹可尋，諸賢興復不關心。',32,'全唐诗/poet.song.170000.json','["斷簡殘編迹可尋，諸賢興復不關心。", "未應全罪王夷甫，一任神州自陸沈。"]'),
('88181e57-453c-42d5-99f4-f7bd26138e13','漁父','曾極','宋','宋诗','song-poetry','','[]','智士旁觀當局迷，滄浪釣叟出陳詩。',32,'全唐诗/poet.song.170000.json','["智士旁觀當局迷，滄浪釣叟出陳詩。", "江頭風怒掀漁屋，底事全家醉不知。"]'),
('7ca3ea99-f557-4abe-8201-3669771dae4e','昇元閣鐸','曾極','宋','宋诗','song-poetry','','[]','摩挲石柱蘚痕斑，亡國如鴻去不還。',32,'全唐诗/poet.song.170000.json','["摩挲石柱蘚痕斑，亡國如鴻去不還。", "無復切雲三百尺，祗傳風鐸在人間。"]'),
('4b3a1fd8-718d-474d-993c-972c59ddb426','孫陵鵝眼錢','曾極','宋','宋诗','song-poetry','','[]','六代初終幾變遷，孫陵無樹起寒烟。',32,'全唐诗/poet.song.170000.json','["六代初終幾變遷，孫陵無樹起寒烟。", "青蚨細薄如榆莢，猶是當年買笑錢。"]'),
('53930068-84b5-4916-ab60-487450a93522','澄心堂','曾極','宋','宋诗','song-poetry','','[]','楮生玉面務深藏，未肯橫陳翰墨場。',32,'全唐诗/poet.song.170000.json','["楮生玉面務深藏，未肯橫陳翰墨場。", "一幅降牋何用許，價高緣寫宋文章。"]'),
('334f9fc0-d818-4f46-adbd-d684e78b48cc','德慶堂字','曾極','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','森然筆勢聚干將，氣軋鍾王未肯降。',32,'全唐诗/poet.song.170000.json','["森然筆勢聚干將，氣軋鍾王未肯降。", "惆悵當年鐵鈎鎖，可能無意鎖長江。"]'),
('d8359ada-6938-41e3-818c-962abd81f153','南唐金銅香爐','曾極','宋','宋诗','song-poetry','','[]','製作元從建業宮，形模奇古雜金銅。',32,'全唐诗/poet.song.170000.json','["製作元從建業宮，形模奇古雜金銅。", "烟昏塵暗君休笑，曾在紅羅扇影中。"]'),
('01434fa8-32ac-4656-af98-0da0bd32504e','南唐宮中殘獐','曾極','宋','宋诗','song-poetry','','[]','周廬巡徼列千兵，那得殘獐墮禁庭。',32,'全唐诗/poet.song.170000.json','["周廬巡徼列千兵，那得殘獐墮禁庭。", "鹿走棘生先有象，天文未必直狼星。"]'),
('2e1415f9-3300-46ab-8922-79ec81df3246','南唐遣使','曾極','宋','宋诗','song-poetry','','[]','談鋒亹亹折强隣，專對當年亦有人。',32,'全唐诗/poet.song.170000.json','["談鋒亹亹折强隣，專對當年亦有人。", "國老胸中兵百萬，不將全力靠江神。"]'),
('9f82012f-c0e9-4b5e-9387-0daaba387f6e','玉樹後庭花','曾極','宋','宋诗','song-poetry','','[]','結綺臨春成草莽，繁華都入暮烟中。',32,'全唐诗/poet.song.170000.json','["結綺臨春成草莽，繁華都入暮烟中。", "後庭玉樹迎秋色，猶带張妃臉上紅。"]'),
('9577dc1d-1744-4314-9dad-5dd303dd5d0b','三段石','曾極','宋','宋诗','song-poetry','','[]','凜然皇象法書存，重屋應無野火焚。',32,'全唐诗/poet.song.170000.json','["凜然皇象法書存，重屋應無野火焚。", "割據英雄餘一念，斷碑千載尚三分。"]'),
('a0e753ca-8972-45a4-983b-05b642ce3b1f','沒字碑','曾極','宋','宋诗','song-poetry','','[]','漫漫荒池浸綠蕪，殘碑一丈載龜趺。',32,'全唐诗/poet.song.170000.json','["漫漫荒池浸綠蕪，殘碑一丈載龜趺。", "當年刻畫書勳閥，雨打風吹字已無。"]'),
('941c2ab3-ac2f-4be5-8ef3-57fb77915d15','校官碑','曾極','宋','宋诗','song-poetry','','[]','風摧雨剝校官碑，集古先生竟不知。',32,'全唐诗/poet.song.170000.json','["風摧雨剝校官碑，集古先生竟不知。", "同是光和千歲刻，未容苦縣獨稱奇。"]'),
('44a1d859-0b03-4439-8062-d5fc73d357c5','石麒麟','曾極','宋','宋诗','song-poetry','','[]','短樊長塹起寒烟，知是何人古墓田。',32,'全唐诗/poet.song.170000.json','["短樊長塹起寒烟，知是何人古墓田。", "千歲石麟相對立，肘騣膊焰故依然。"]'),
('786c1f96-53b0-4ff2-a1c7-92ceddba4c8e','石步道中有石麒麟數十','曾極','宋','宋诗','song-poetry','','[]','地悴天荒丘隴平，難從野老問衰興。',32,'全唐诗/poet.song.170000.json','["地悴天荒丘隴平，難從野老問衰興。", "蒼烟落日低迷處，折足麒麟記壞陵。"]'),
('a6a843a8-91d3-4db9-bae8-8223976933e9','水精大珠','曾極','宋','宋诗','song-poetry','','[]','冰玉摩尼如鵠卵，大千世界倒懸中。',32,'全唐诗/poet.song.170000.json','["冰玉摩尼如鵠卵，大千世界倒懸中。", "何人提向江頭照，照見神州一半空。"]'),
('dd6c4ca6-b1bf-4b09-bb9c-7858693f2f30','輜車','曾極','宋','宋诗','song-poetry','','[]','婭姹吳音今古同，宮粧袨服已成空。',32,'全唐诗/poet.song.170000.json','["婭姹吳音今古同，宮粧袨服已成空。", "雕文結角輜車巧，猶有梁陳宮掖風。"]'),
('4f030a49-244e-4e63-83fc-6fe03ee42e96','决囚燈','曾極','宋','宋诗','song-poetry','','[]','五詳三覆始施刑，明滅蘭膏豈足憑。',32,'全唐诗/poet.song.170000.json','["五詳三覆始施刑，明滅蘭膏豈足憑。", "可惜當年殺嚴續，無人爲益决囚燈。"]'),
('64c48bf5-b0e0-42b9-b381-61799aa277e3','江南錄','曾極','宋','宋诗','song-poetry','','[]','自古嬰鱗或似狂，按誅潘佑事堪傷。',32,'全唐诗/poet.song.170000.json','["自古嬰鱗或似狂，按誅潘佑事堪傷。", "憑誰寄語徐常侍，不殺忠臣國未亡。"]'),
('f06d6c2b-847b-4cb0-b1a9-464ea48f8ced','蜀海棠','曾極','宋','宋诗','song-poetry','','[]','傳芳遠遠自西隣，錦傘高張熨眼新。',32,'全唐诗/poet.song.170000.json','["傳芳遠遠自西隣，錦傘高張熨眼新。", "花睡覺來紅淚落，年年如憶故宮春。"]'),
('b07a4dd9-48a1-4c0b-9c16-914aa4d39b34','鳳州柳','曾極','宋','宋诗','song-poetry','','[]','蜀主函封遣使時，芳根元自鳳州移。',32,'全唐诗/poet.song.170000.json','["蜀主函封遣使時，芳根元自鳳州移。", "柔荑醽醁今安在，唯有青絲拂地垂。"]'),
('d56d4c05-5659-4377-ae07-cc0d926bf548','南燭草木','曾極','宋','宋诗','song-poetry','','[]','駐采還年枉費功，羞將老色照青銅。',32,'全唐诗/poet.song.170000.json','["駐采還年枉費功，羞將老色照青銅。", "仙方石䭀無消息，南燭垂珠顆顆紅。"]'),
('9aeb8936-aa72-43a5-bfd1-cd3c0ff5b183','榠樝','曾極','宋','宋诗','song-poetry','','[]','子丹進饌色微黄，仙老調胹有禁方。',32,'全唐诗/poet.song.170000.json','["子丹進饌色微黄，仙老調胹有禁方。", "五和糝奇無處覓，榠樝新熟壓枝香。"]'),
('b61992ca-a545-4237-b0ca-82311d0f55af','青松路','曾極','宋','宋诗','song-poetry','','[]','致君堯舜事何難，投老鍾山賦考槃。',32,'全唐诗/poet.song.170000.json','["致君堯舜事何難，投老鍾山賦考槃。", "愁殺天津橋上客，杜鵑聲裏兩眉攢。"]'),
('86ad1496-6509-40b4-887a-739eae7e9a93','挽真西山二首  其一','曾極','宋','宋诗','song-poetry','','[]','雲出西山雨未成，已聞華表鶴飛鳴。',64,'全唐诗/poet.song.170000.json','["雲出西山雨未成，已聞華表鶴飛鳴。", "聲名未必少黄霸，禮樂正緣無孔明。", "天下已傳新宰相，胸中不改舊書生。", "寒蟾沒入少微去，從此泰階何日平。"]'),
('d023a354-1414-44bf-8ba5-03f1449c4b5a','挽真西山二首  其二','曾極','宋','宋诗','song-poetry','','[]','一片誠心并若丹，愛民何止十分寬。',64,'全唐诗/poet.song.170000.json','["一片誠心并若丹，愛民何止十分寬。", "不成中國相司馬，空使蒼生望謝安。", "廣益集思今已晚，以明佐聖古來難。", "治平一卷黄扉墨，留與君王拭淚看。"]'),
('23a97ab5-ac5d-4809-8478-f3ff0a2c278b','上朱晦庵','曾極','宋','宋诗','song-poetry','','[]','玄天默無言，妙契有伏義。',240,'全唐诗/poet.song.170000.json','["玄天默無言，妙契有伏義。", "爰初畫八卦，聖學乃肇基。", "於皇陶唐氏，□心折危微。", "魯叟述六經，爲世立範圍。", "正色斥詖淫，鄒孟獨先幾。", "道喪向千載，華風變醇醨。", "皇綱一以振，屬此文明時。", "真儒出河洛，堅白不磷緇。", "探我囊中膠，續彼桐上絲。", "徽音嗣正始，但惜和者稀。", "祥麟雖見獲，鳳鳥終來遲。", "珍重武夷翁，斯文今在茲。", "巖棲三十年，著書覺群迷。", "往者不可諫，來者猶可追。", "趨隅偶未諧，夙昔夢見之。", "散髮弄五絃，彈作南風詩。", "曲終起長嗟，絃絕有餘悲。", "止止不復彈，繆然歌采薇。", "鸞翮有時鎩，鴟鳶刺天飛。", "公乎抱高寒，歲晚將安歸。"]'),
('f85e4fa6-0c2d-4323-b0f3-f96403b6428c','蔡西山貶道州','曾極','宋','宋诗','song-poetry','','[]','四海朱夫子，徵君獨典刑。',48,'全唐诗/poet.song.170000.json','["四海朱夫子，徵君獨典刑。", "青雲伯夷傳，白首太玄經。", "有客憐孤憤，無人問獨醒。", "瑶琴空寶匣，絃斷不堪聽。"]'),
('0aa1b6eb-2ba2-4253-84dd-c4822acde9e3','文公先生挽詞','曾極','宋','宋诗','song-poetry','','[]','皇天開太極，庚戌聖賢生。',48,'全唐诗/poet.song.170000.json','["皇天開太極，庚戌聖賢生。", "六籍文將絕，千年道復明。", "淵源羅仲素，師友李延平。", "遶舍閩溪急，潺湲洛水聲。"]'),
('5a54ab48-aba3-4363-8e06-ebd3ba6d3648','濂溪','曾極','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','逍遥社裏周夫子，太極圖成晝掩關。',32,'全唐诗/poet.song.170000.json','["逍遥社裏周夫子，太極圖成晝掩關。", "欲驗箇中真動靜，終朝臨水對廬山。"]'),
('b3ce0293-4413-45ee-ace5-8f77d06d6415','送真泉州','曾極','宋','宋诗','song-poetry','','[]','隠然風節動朝行，屢叩龍墀貢皂囊。',64,'全唐诗/poet.song.170000.json','["隠然風節動朝行，屢叩龍墀貢皂囊。", "未促相如歸蜀道，翻令汲黯去淮陽。", "便藩自足榮萊服，邃殿誰當補舜裳。", "急召諸賢固根本，璽書早晚出明光。"]'),
('1a6cc2f9-d509-4a56-bc85-943354d36c70','寄陳正己','曾極','宋','宋诗','song-poetry','','[]','扊扅深閉斷經過，倒摺塵編且卧痾。',64,'全唐诗/poet.song.170000.json','["扊扅深閉斷經過，倒摺塵編且卧痾。", "九十日春晴景少，一千年事亂時多。", "吟成楚些翻愁絕，鬢染吳霜奈老何。", "心鐵正堅思急試，憶君中夜起悲歌。"]'),
('530469a9-8dfe-4022-99a4-1437aefa80a9','春望','曾極','宋','宋诗','song-poetry','','[]','樓上從容曉日明，春風隨處動郊坰。',64,'全唐诗/poet.song.170000.json','["樓上從容曉日明，春風隨處動郊坰。", "定知有象根沖漠，未信至真惟杳冥。", "萬化淳時雲靄靄，一元亨處雨零零。", "無言共倚闌干曲，綠滿原田水滿汀。"]'),
('699ee61d-1db3-42a3-9c2c-a1ffc315c8d8','約友人賞春','曾極','宋','宋诗','song-poetry','','[]','人生何事最爲親，不看春容不識春。',64,'全唐诗/poet.song.170000.json','["人生何事最爲親，不看春容不識春。", "岸柳細摇多意思，野花初綻足精神。", "精神識得施爲別，意思到時言語新。", "爲報同門須急賞，莫教春去始傷春。"]'),
('99479b9e-120d-4059-ab09-425dc6cc575c','游寒巖  其一','曾極','宋','宋诗','song-poetry','','[]','金玉其相一兩花，遐心空爲爾興嗟。',32,'全唐诗/poet.song.170000.json','["金玉其相一兩花，遐心空爲爾興嗟。", "山礬不用來修敬，只許江梅共一家。"]'),
('1db9e88f-225c-4af9-819b-731fd5589c8f','游寒巖  其二','曾極','宋','宋诗','song-poetry','','[]','黄瑶白璧綴幽花，珍重高人爲嘆嗟。',32,'全唐诗/poet.song.170000.json','["黄瑶白璧綴幽花，珍重高人爲嘆嗟。", "織女橫河溪月墮，杯盤狼籍水仙家。"]'),
('e30a9ae4-d3e7-41bf-9a31-8a487bb09ded','松','曾極','宋','宋诗','song-poetry','','[]','彙進群奸卒召戎，萌芽培養自熙豐。',32,'全唐诗/poet.song.170000.json','["彙進群奸卒召戎，萌芽培養自熙豐。", "當時手植留遺愛，只有巖前十八公。"]'),
('d6e67c44-8bd4-409d-832d-2e8b54a7db2c','清凉廣惠禪寺','曾極','宋','宋诗','song-poetry','','[]','鳴鞘響斷苑牆平，敲戛惟聞風玉聲。',32,'全唐诗/poet.song.170000.json','["鳴鞘響斷苑牆平，敲戛惟聞風玉聲。", "三百年間陵谷變，寒潮不到石頭城。"]'),
('f20bb4f6-7be7-48e6-9b51-f7d78edf655e','往舂陵作','曾極','宋','宋诗','song-poetry','','[]','杖策行行訪楚囚，也勝流落嶠南州。',64,'全唐诗/poet.song.170000.json','["杖策行行訪楚囚，也勝流落嶠南州。", "鬢絲半是吳蠶吐，襟血全因蜀鳥流。", "徑窄不妨隨繭栗，路長那更聽鈎輈。", "家山千里雲千疊，十口生離兩地愁。"]'),
('526b82c7-e2c6-454f-8759-0b6d3f7680f6','題識山堂','曾極','宋','宋诗','song-poetry','','[]','抉開雲氣從天末，喚得爐峰入坐閒。',32,'全唐诗/poet.song.170000.json','["抉開雲氣從天末，喚得爐峰入坐閒。", "似見二林春靄靄，殊聞三疊水潺潺。"]'),
('07242de9-9938-46d4-8459-f16a8a57f47b','寄陳正己','曾極','宋','宋诗','song-poetry','','[]','十載憂迫髮半華，東山有意凈胡沙。',64,'全唐诗/poet.song.170000.json','["十載憂迫髮半華，東山有意凈胡沙。", "公車戰策三千牘，腹笥兵書五十家。", "好佩青萍光奪月，莫驚赤羽氣成霞。", "嗟予本亦輕生者，欲渡黄海擲馬撾。"]'),
('8212f4b4-11b7-45cc-9b2f-82ef2f662cd9','題太平宮','曾極','宋','宋诗','song-poetry','','[]','前朝失太平，仙館寄空名。',48,'全唐诗/poet.song.170000.json','["前朝失太平，仙館寄空名。", "日日有秋色，房房聞水聲。", "碑傳吳叟畫，殿厄建炎兵。", "舊物雲關在，新宮再落成。"]'),
('30625693-b10e-476d-919f-d64716fc757d','六朝','曾極','宋','宋诗','song-poetry','','[]','倒指六朝事，江城不忍登。',48,'全唐诗/poet.song.170000.json','["倒指六朝事，江城不忍登。", "燕巢非故宅，兔窟徧諸陵。", "亹亹稱王霸，嗟嗟感廢興。", "青山龍虎在，金氣又消凝。"]'),
('bd33a514-8d94-4ac5-bdfb-59cd8fc7bd36','大唐','曾極','宋','宋诗','song-poetry','','[]','仁義晉陽主，神功致太平。',48,'全唐诗/poet.song.170000.json','["仁義晉陽主，神功致太平。", "子孫承事業，婦寺竊權衡。", "府衛兵先壞，租庸調不行。", "未幾三百載，逆賊入宮城。"]'),
('5c205fb2-69a0-49d3-94a1-34b9400134b9','五代','曾極','宋','宋诗','song-poetry','','[]','弒篡起交爭，中原戰血腥。',48,'全唐诗/poet.song.170000.json','["弒篡起交爭，中原戰血腥。", "王庭更五姓，民戶乏孤丁。", "耕織常年弛，干戈甚日停。", "聖人祈早降，香霧達高冥。"]'),
('230c230a-fcb9-4493-bea0-6329f01ef26c','三十六宮','曾極','宋','宋诗','song-poetry','','[]','曲閣便房三十六，欲迴舞袖不容身。',32,'全唐诗/poet.song.170000.json','["曲閣便房三十六，欲迴舞袖不容身。", "黄金壁带今安有，笑殺宣和大內人。"]'),
('de613b2b-f4ae-4ff5-b74d-c0b206f145d5','雨華臺','曾極','宋','宋诗','song-poetry','','[]','晝可騎虹夜摘星，山根萬瓦碧磷磷。',32,'全唐诗/poet.song.170000.json','["晝可騎虹夜摘星，山根萬瓦碧磷磷。", "雨臺不爲雲光老，一洗南朝戰伐塵。"]'),
('f23f4cb0-1f92-4c8f-aa76-0a5aa1caa42e','和李璧凌丹亭','曾極','宋','宋诗','song-poetry','','[]','思陵宸翰麗昭回，閣下金□長紫苔。',32,'全唐诗/poet.song.170000.json','["思陵宸翰麗昭回，閣下金□長紫苔。", "試向凌丹尋妙墨，何時真見白雲來。"]'),
('ec096c26-7263-4e01-8e12-42687cb664ae','凌丹亭','曾極','宋','宋诗','song-poetry','','[]','路轉峰回杳靄中，石壇幡影表真風。',32,'全唐诗/poet.song.170000.json','["路轉峰回杳靄中，石壇幡影表真風。", "憑誰貌取清虛老，與對濂溪太極翁。"]'),
('15080a9c-b2fa-43ce-b1e9-49e85387cdba','挽蔡西山先生','曾極','宋','宋诗','song-poetry','','[]','天子中年後，名家信有初。',48,'全唐诗/poet.song.170000.json','["天子中年後，名家信有初。", "身罹鈎黨禍，學稿啟蒙書。", "木直宜先伐，蘭芳竟自鋤。", "首陽千駟馬，後世定何如。"]'),
('4fff04be-83df-44c3-86c2-5fae72d05b0e','紅泉精舍','曾極','宋','宋诗','song-poetry','','[]','十里長松一幅巾，溫湯浄濯滿衣塵。',64,'全唐诗/poet.song.170000.json','["十里長松一幅巾，溫湯浄濯滿衣塵。", "石門隔斷世間事，仙窟能容鶴上人。", "已主謝公爲北道，更依華子作西鄰。", "紅泉可酒兼宜茗，便合躬耕老此身。"]'),
('1eec8fc3-c87e-4cdf-92c9-a0c03aa3c2a4','和謝康樂華子岡韻','曾極','宋','宋诗','song-poetry','','[]','隠仙無定在，館宇非一山。',120,'全唐诗/poet.song.170000.json','["隠仙無定在，館宇非一山。", "華子出商洛，巢雲府渴泉。", "嬴顛劉蹶際，師生自爲賢。", "頗哀區中人，峰嶺起新阡。", "决絕目下事，駕鴻凌紫煙。", "身隠焉用文，滅跡隠空筌。", "雲仍散洲渚，世漁業相傳。", "笭箵挂虎落，舴艋當門前。", "蹇予厭世議，企石聽潺湲。", "山空月明時，足音自跫然。"]'),
('2ad4e32a-3c17-4a7d-ab21-f1ecab8e33ef','遊華子岡紅泉碧澗','曾極','宋','宋诗','song-poetry','','[]','去城纔半驛，深谷自逶迤。',48,'全唐诗/poet.song.170000.json','["去城纔半驛，深谷自逶迤。", "藤絡崩崖石，松垂倒地枝。", "寒山縮毛髮，碧澗照須眉。", "霜氣全消歇，空存太傅祠。"]'),
('72891cf0-fc37-4371-81b8-9901b814a259','雜興  其一','張鎡','宋','宋诗','song-poetry','','[]','聖學律萬世，玉振仍金聲。',48,'全唐诗/poet.song.170000.json','["聖學律萬世，玉振仍金聲。", "大賢務矯俗，始以和自名。", "智者稽所終，流弊固難行。", "求圓能捨規，魯男烏可輕。"]'),
('fee4d150-67e6-4de1-a160-83c66cd6c466','雜興  其二','張鎡','宋','宋诗','song-poetry','','[]','城河固金湯，穀帛堆丘山。',84,'全唐诗/poet.song.170000.json','["城河固金湯，穀帛堆丘山。", "雷風走號令，足以威百蠻。", "秦人昔恃此，燒書無愧顔。", "叢祠夜篝火，赤蛇先據關。", "誰知小國魯，抗衡齊晉間。", "獨能秉王禮，足以銷鄰姦。", "舞干服三苗，可仰其可攀。"]'),
('d541ad0f-1d26-4f06-87d6-9b553e31f858','雜興  其三','張鎡','宋','宋诗','song-poetry','','[]','原子何所得，所得在養心。',48,'全唐诗/poet.song.170000.json','["原子何所得，所得在養心。", "澹然處窮閻，蓬蒿絕車音。", "結駟者誰子，排門願同襟。", "乃知能辯者，於道未爲深。"]'),
('58254c88-5659-4cc7-9b01-22782706f8a4','雜興  其四','張鎡','宋','宋诗','song-poetry','','[]','日暮前道遠，紛紛倒行多。',48,'全唐诗/poet.song.170000.json','["日暮前道遠，紛紛倒行多。", "胡不秉明燭，整駕歷前坡。", "既衰不戒得，有如聖言何。", "平公七十翁，師曠猶琢磨。"]'),
('377da720-073b-4460-9aa7-26df50e91f9b','雜興  其五','張鎡','宋','宋诗','song-poetry','','[]','管仲相齊國，童子猶羞稱。',48,'全唐诗/poet.song.170000.json','["管仲相齊國，童子猶羞稱。", "確守害霸說，三王亦可成。", "寸短有所長，貪賢况誠切。", "莫問九合功，詠此宜擊節。"]'),
('0c2aa045-a00a-4f81-bcf2-e8d7e607e5e6','雜興  其六','張鎡','宋','宋诗','song-poetry','','[]','文仲蔽展禽，難逃竊位名。',96,'全唐诗/poet.song.170000.json','["文仲蔽展禽，難逃竊位名。", "張湯法家流，推賢被嘉聲。", "公道日月如，無私天下行。", "治古本根此，所以休甲兵。", "嗟嗟祁大夫，舉善何其宏。", "曰讎吾甚惡，曰子非私情。", "一旦俱薦引，晉伯由此成。", "後世益多嫌，山林老公卿。"]'),
('8612d2df-3e9d-4101-b365-46fddc5862c1','雜興  其七','張鎡','宋','宋诗','song-poetry','','[]','伯牙善鼓琴，知音一子期。',48,'全唐诗/poet.song.170000.json','["伯牙善鼓琴，知音一子期。", "已得慰生平，絕絃勿復悲。", "深沉揚執戟，玄文準伏羲。", "千年未願賞，豈欲求當時。"]'),
('8fddf31a-fa07-4062-9ec0-9e9a18700a94','雜興  其八','張鎡','宋','宋诗','song-poetry','','[]','泱泱古齊邦，中有秉節臣。',72,'全唐诗/poet.song.170000.json','["泱泱古齊邦，中有秉節臣。", "其國不能舉，燕師知寵珍。", "生不食君祿，勢或去諸鄰。", "莫往徑絕脰，用愧軒冕人。", "當年處高位，十萬當逡巡。", "所以休明時，朝廷足嘉賓。"]'),
('99eee2a6-b962-4317-9af5-6bd9e9c705d2','雜興  其九','張鎡','宋','宋诗','song-poetry','','[]','善人所至處，鳳儀氣芝蘭。',48,'全唐诗/poet.song.170000.json','["善人所至處，鳳儀氣芝蘭。", "同德自相求，肯因休顯看。", "後來世道交，祗趨勢與官。", "廉頗共翟公，雅抱常自寬。"]'),
('d02a097c-2bda-448c-83eb-7abff92a03bc','雜興  其一○','張鎡','宋','宋诗','song-poetry','','[]','小器酌升斗，渠寧同釜鍾。',60,'全唐诗/poet.song.170000.json','["小器酌升斗，渠寧同釜鍾。", "心公德始宏，一介稱能容。", "將軍見何卑，偏忌相如功。", "卓哉全璧賢，懷才肯爭鋒。", "悔過猶可稱，服善交情終。"]'),
('bfb04685-77a5-4913-add2-c95c4c9dea1e','雜興  其一一','張鎡','宋','宋诗','song-poetry','','[]','吳起棄骨肉，用釋魯君疑。',72,'全唐诗/poet.song.170000.json','["吳起棄骨肉，用釋魯君疑。", "蕭何買田宅，更要漢祖知。", "結繩可息爭，書契計已癡。", "反覆者人心，周防良足悲。", "曾參殺人謗，三至母信移。", "君臣不易逢，終始貴難離。"]'),
('b929dd53-7670-43d0-b911-38286442490a','雜興  其一二','張鎡','宋','宋诗','song-poetry','','[]','金珠不解憂，麴糵堪適情。',72,'全唐诗/poet.song.170000.json','["金珠不解憂，麴糵堪適情。", "隘哉沉湘人，獨以醒自名。", "生居禁酒國，焉得壺觴傾。", "閉門求一醉，無乃干天刑。", "若伊曠懷襟，道在寧營營。", "詳觀中聖言，當與智者評。"]'),
('16e1f79f-1b19-4123-8a96-64f5b1629a01','雜興  其一三','張鎡','宋','宋诗','song-poetry','','[]','堂陛分古始，高卑定常儀。',96,'全唐诗/poet.song.170000.json','["堂陛分古始，高卑定常儀。", "拳拳三顧頻，未敢臣其師。", "至寶價婆娑，塵面誰復窺。", "有人果善酬，何苦不售爲。", "木牛流馬機，小智那足奇。", "甄別蘭與艾，忠誠真弗欺。", "功大天實吝，滯迹烏能知。", "臣主施報恩，足爲萬世規。"]'),
('b117b5dc-4dfb-4032-abea-d090838fc391','雜興  其一四','張鎡','宋','宋诗','song-poetry','','[]','有虎南山南，有石北山畔。',48,'全唐诗/poet.song.170000.json','["有虎南山南，有石北山畔。", "虎石人未辨，箭發石遂貫。", "一朝兩生心，見石不見虎。", "若向虎石求，引滿徒自苦。"]'),
('970241b3-4a73-4d4a-bece-47a1f234d637','雜興  其一五','張鎡','宋','宋诗','song-poetry','','[]','河南牧羊兒，不識奇字書。',84,'全唐诗/poet.song.170000.json','["河南牧羊兒，不識奇字書。", "君王事邊頭，無亦官帑虛。", "慨然分家資，補國何勤渠。", "詎有忠於君，而謂不學歟。", "毋令敗羣語，緱氏果有餘。", "惜哉封禪主，更欲取名譽。", "歲晚責緣飾，宜其返田閭。"]'),
('b15090a4-e112-4949-ba6b-fd84b48d47aa','雜興  其一六','張鎡','宋','宋诗','song-poetry','','[]','真才當自重，躍冶非良金。',60,'全唐诗/poet.song.170000.json','["真才當自重，躍冶非良金。", "世儒識拔鮮，志士違本心。", "慷慨自鋪陳，庶幾有知音。", "但恐北風扇，虛言難保任。", "快哉東方生，可喜未可欽。"]'),
('f3915376-194a-4ede-a738-c4b7b260b141','雜興  其一七','張鎡','宋','宋诗','song-poetry','','[]','聖道由書傳，秉畀火于秦。',48,'全唐诗/poet.song.170000.json','["聖道由書傳，秉畀火于秦。", "漢興反秦暴，見儒猶駡嗔。", "董子惟有志，耿耿誰與陳。", "使時三策行，焉老諸侯賓。"]'),
('64f0cf83-ceb9-4e1c-bcce-6546908ab804','雜興  其一八','張鎡','宋','宋诗','song-poetry','','[]','子雲閉門學，非願雕蟲稱。',48,'全唐诗/poet.song.170000.json','["子雲閉門學，非願雕蟲稱。", "於道實有省，爵位豈所營。", "洙泗嗟已遠，惜不偕羣英。", "太玄法言書，莫誚徒擬經。"]'),
('b1d5ea66-c05c-4aaf-8c8b-ccd0ff11a491','雜興  其一九','張鎡','宋','宋诗','song-poetry','','[]','漢代嘉唐虞，欲以儒理國。',72,'全唐诗/poet.song.170000.json','["漢代嘉唐虞，欲以儒理國。", "公孫談治道，純駁互失得。", "廣大語尤害，開邊心莫極。", "無怪淮南謀，日夜憚汲直。", "東閣禮諸賢，脫粟自爲食。", "欲以此自文，後世有真識。"]'),
('deb20e04-207b-4a7d-b07e-bcc6ca04e448','雜興  其二○','張鎡','宋','宋诗','song-poetry','','[]','言貌難取人，宣尼竊丁寧。',48,'全唐诗/poet.song.170000.json','["言貌難取人，宣尼竊丁寧。", "如何汝南許，輒擅月旦評。", "觀其察曹瞞，一言盡生平。", "勿謂鑒裁乏，一門稱弟兄。"]'),
('7857a67f-9143-4a7b-9f54-1a00a3881ff1','雜興  其二一','張鎡','宋','宋诗','song-poetry','','[]','林宗真傑士，甑墮識孟敏。',48,'全唐诗/poet.song.170000.json','["林宗真傑士，甑墮識孟敏。", "初無一語交，肺腑已窺盡。", "人才處東京，郭許能汲引。", "幾時不生賢，弗遇即泯泯。"]'),
('6d289485-7434-4da5-a9f4-fa340d06a0bf','雜興  其二二','張鎡','宋','宋诗','song-poetry','','[]','道德釀搢紳，睟容無點塵。',72,'全唐诗/poet.song.170000.json','["道德釀搢紳，睟容無點塵。", "望之鄙吝消，矧得累夕親。", "緬思闕里化，四教隆諸身。", "濟濟三千徒，變蒙盡爲仁。", "賢聖雖不同，氣類當等倫。", "叔度亦我師，千載風如新。"]'),
('8cdd66d9-92a8-4fc6-a824-b3b432c595d2','雜興  其二三','張鎡','宋','宋诗','song-poetry','','[]','達士樂貧賤，本非沽激心。',48,'全唐诗/poet.song.170000.json','["達士樂貧賤，本非沽激心。", "豈真昧生死，而計樂淺深。", "辛勤畢婚嫁，塵慮寧更侵。", "高蹤五岳遊，乘風擬相尋。"]'),
('a1ba0360-0646-4506-99a9-c21941d4995f','雜興  其二四','張鎡','宋','宋诗','song-poetry','','[]','山川萬代留，人物有時盡。',84,'全唐诗/poet.song.170000.json','["山川萬代留，人物有時盡。", "慷慨羊叔子，登臨重嗟憫。", "功名垂櫜來，老去載倉囷。", "焉有利在民，轉盼聲即泯。", "非真弔古往，借言聊自引。", "湛也窮其心，欲嘿不能忍。", "惜昧無去來，徒知幻與影。"]'),
('62771436-7f67-4ed1-b405-f9781b2f317d','雜興  其二五','張鎡','宋','宋诗','song-poetry','','[]','征南勳業手，顧乃玩簡策。',60,'全唐诗/poet.song.170000.json','["征南勳業手，顧乃玩簡策。", "麟經日月垂，左氏實有力。", "爲渠作忠臣，訓義訂今昔。", "後來縫掖子，開卷隨有益。", "果能作蹄筌，此學不妨癖。"]'),
('c69d2399-6f7a-4550-9fa6-c917df6be0a5','雜興  其二六','張鎡','宋','宋诗','song-poetry','','[]','龍泉伴太阿，潛伏知幾秋。',60,'全唐诗/poet.song.170000.json','["龍泉伴太阿，潛伏知幾秋。", "光氣不容揜，夜夜衝斗牛。", "一朝掘青苔，雙龍獲兼收。", "拭以華陰土，百神見之愁。", "若使無張雷，恐非劍所羞。"]'),
('ee8e16e9-e7eb-4032-afde-7b4b982ae160','雜興  其二七','張鎡','宋','宋诗','song-poetry','','[]','天一即生水，語性何潔清。',48,'全唐诗/poet.song.170000.json','["天一即生水，語性何潔清。", "未嘗使人貪，酌之失廉稱。", "夷齊素高蹈，想非常飲冰。", "仁鄙成自取，處默先內明。"]'),
('e0b9dd5c-7540-4ad5-aa1f-1502ef1d3e71','雜興  其二八','張鎡','宋','宋诗','song-poetry','','[]','南渡人物中，第一數安石。',84,'全唐诗/poet.song.170000.json','["南渡人物中，第一數安石。", "經營江左民，成敗固先識。", "苻堅擁百萬，朝野總憂色。", "長驅不量德，在法真餌敵。", "談笑付兒輩，茲豈試一擲。", "捷至偶折屐，胸中未易測。", "議者謂矯情，妄意窺悃愊。"]'),
('e8c6503f-d457-45b6-b148-84e89c2cf01c','雜興  其二九','張鎡','宋','宋诗','song-poetry','','[]','聖狂霄壤分，其端在一念。',72,'全唐诗/poet.song.170000.json','["聖狂霄壤分，其端在一念。", "去惡向忠義，如病用良砭。", "方貽害於人，蛟虎羣兇焰。", "及其懲艾餘，大節秉無欠。", "卓絕補過功，炳炳照鉛槧。", "乃知春秋意，惡惡待終厭。"]'),
('4cf340b2-cf82-4af8-8e3f-f0f9c668e71b','雜興  其三○','張鎡','宋','宋诗','song-poetry','','[]','實修名自來，猶影長隨身。',72,'全唐诗/poet.song.170000.json','["實修名自來，猶影長隨身。", "惑者偏忌嫉，終之反累人。", "况馳死後譽，何關一丘塵。", "所以識達早，托醉全吾真。", "歸興因蓴鱸，口腹何足陳。", "到今吳江水，秋至清粼粼。"]'),
('c03fd78f-6c8b-4507-a55a-e61bf711ecc4','雜興  其三一','張鎡','宋','宋诗','song-poetry','','[]','淵明膝上桐，一絲不肯挂。',48,'全唐诗/poet.song.170000.json','["淵明膝上桐，一絲不肯挂。", "彈聲聒天地，無人知此話。", "謂琴只這是，世間何用絃。", "謂在有無中，其然豈其然。"]'),
('00c8ea1b-4957-4013-a9f3-5bbfde50309f','雜興  其三二','張鎡','宋','宋诗','song-poetry','','[]','太沖十年功，僅了三都賦。',60,'全唐诗/poet.song.170000.json','["太沖十年功，僅了三都賦。", "藩溷著紙筆，欲以疏吾句。", "文章流至是，已失古人步。", "喜怒哀樂情，一發中韶濩。", "不見風雅篇，豈效女功蠹。"]'),
('2f58bdf4-7beb-4611-a670-8de24692da4b','雜興  其三三','張鎡','宋','宋诗','song-poetry','','[]','掄才如百藥，治效各不同。',84,'全唐诗/poet.song.170000.json','["掄才如百藥，治效各不同。", "儻能區別性，當聚和扁功。", "武德定亂後，諸公悉登庸。", "帝久知所長，未欲任己聰。", "品題資確論，毫髮無蔽蒙。", "三傑隆漢業，六英夾唐宗。", "無人可能國，我欲振古風。"]'),
('bd3f71a4-d1a6-467c-806b-36f77479cbcc','雜興  其三四','張鎡','宋','宋诗','song-poetry','','[]','至藝得於天，音律誰同明。',72,'全唐诗/poet.song.170000.json','["至藝得於天，音律誰同明。", "道上車鐸逢，地底黄鍾成。", "偉哉創業主，用才極其精。", "太常識斯人，吾知不負丞。", "忽疑貞觀間，四海幾措刑。", "遐想登后夔，巍巍治難名。"]'),
('4929c10d-a849-4c82-9a69-9654e1501fb7','雜興  其三五','張鎡','宋','宋诗','song-poetry','','[]','馬生客新豐，悠然酌斗酒。',48,'全唐诗/poet.song.170000.json','["馬生客新豐，悠然酌斗酒。", "若謂傲旁人，曠士亦何有。", "有志曾未識，偶與麴糵友。", "異時依風雲，黄壚一回首。"]'),
('932edfde-dda9-40dd-9192-f55407c36414','雜興  其三六','張鎡','宋','宋诗','song-poetry','','[]','照乘復垂棘，固足爲國寶。',72,'全唐诗/poet.song.170000.json','["照乘復垂棘，固足爲國寶。", "朝有宣力賢，愛惜莫草草。", "成湯昔在上，剪髮救枯稿。", "念民有念己，頃刻動穹昊。", "太宗療功臣，亦本爲民保。", "斷鬚疾其愈，大勝琮璧禱。"]'),
('f793c074-cb73-4b88-ad3e-41a6128fc2df','雜興  其三七','張鎡','宋','宋诗','song-poetry','','[]','秦王既集統，作樂昭治功。',72,'全唐诗/poet.song.170000.json','["秦王既集統，作樂昭治功。", "前日威武地，今還見聲容。", "一時聳觀瞻，唯貪激英雄。", "鄭公獨俛首，孰能察聖衷。", "暮年伐遼東，事幾敗乃翁。", "良臣不在傍，有悔應無窮。"]'),
('14540eb0-68ea-440f-b200-b6abe68f9f19','雜興  其三八','張鎡','宋','宋诗','song-poetry','','[]','唐家盛詞華，培本自武德。',96,'全唐诗/poet.song.170000.json','["唐家盛詞華，培本自武德。", "投戈闢文館，英士來翼翼。", "訪政討典墳，分夜亡倦極。", "當時瀛洲目，意氣寧偪仄。", "言詩到李杜，騷雅並區域。", "爲文至韓柳，秦漢等風力。", "後世不推原，第賞紙上墨。", "焉知昔人心，求效非頃刻。"]'),
('c818af0e-dd66-418a-bdaf-e158056fd32c','雜興  其三九','張鎡','宋','宋诗','song-poetry','','[]','風月屬漁樵，真味豈能領。',72,'全唐诗/poet.song.170000.json','["風月屬漁樵，真味豈能領。", "雍容補國手，斯宜理烟艇。", "樂天未歸時，極口獻忠鯁。", "十上九不行，回身避機穽。", "酒徒與詩伴，共煮香山茗。", "流傳畫九人，公貌粹而整。"]'),
('b1db01c2-6b75-4e46-afad-8ade59b2b99c','秦女行','張鎡','宋','宋诗','song-poetry','','[]','妾家秦關中，白玉爲重堂。',144,'全唐诗/poet.song.170000.json','["妾家秦關中，白玉爲重堂。", "堂前翠簾鈎，一一金鴛鴦。", "暖艷照綺席，新聲按笙簧。", "妾小不解事，戲劇珠樓旁。", "蜂蕊擷穠杏，鶑枝蔭垂楊。", "阿母喜秀慧，鞶絲教縫裳。", "年齒漸長成，自製紅襦長。", "弄杼織繁錦，錯綜飛鳳凰。", "體柔生玉膩，國色凝天香。", "不假粉黛妍，差作時世粧。", "悅己求得逢，晨夕勞衷腸。", "苟合必易散，良賈宜深藏。"]'),
('6c6adfd2-ec7d-4d6d-89bf-b29a9e32ae0c','錦池芙蓉盛開與譚德稱何國叔曾無逸王季嘉呂浩然張以道小集以東坡詩細思却是最宜霜分韻得却字','張鎡','宋','宋诗','song-poetry','','[]','道人有園居，其門可羅爵。',180,'全唐诗/poet.song.170000.json','["道人有園居，其門可羅爵。", "夫何諸賢傑，疎野盡闊略。", "聯鑣過柴荆，慰藉淡與泊。", "爾時木芙蓉，酣酣縱雲萼。", "呼酒亟對之，不復次杯酌。", "西風吹雨小，池波晚烟閣。", "紅癡高髼鬆，翠閙競參錯。", "談叢及笑粲，大勝世俗樂。", "翹摇鵬鳳羣，著我慙瘦鶴。", "區中有此不，今古一開拓。", "山林豈細故，人願要天諾。", "侵尋霄霏舉，乃獨趣丘壑。", "探韻睨大巫，疾走宜退却。", "簪花謝慇懃，敢避句惡弱。", "從今數名芳，消真屢成約。"]'),
('f86c20ba-85be-4b8e-b1f3-85a7c2642c79','足疾愈約客遊湖上園','張鎡','宋','宋诗','song-poetry','','[]','平生志四方，豈願守三窟。',216,'全唐诗/poet.song.170000.json','["平生志四方，豈願守三窟。", "超凌風中驥，振迅霜後鶻。", "無何足受濕，步履遽臲卼。", "投鍼痛循筋，濯藥熱透骨。", "重纏韈中絖，嬾顧囊內笏。", "長懷駱賓王，曠邁困沉泊。", "胸蟠經綸業，與氣共振拔。", "紛紛灞上旅，太半貴肥腯。", "儻其尚細謹，俗眼愈超忽。", "臨壚指醇酒，洗滌去泥淈。", "器宏事果遂，闊步黄金闕。", "宿來病殊減，砌域可踔越。", "拘攣日既深，得差興尤發。", "湖山想貽笑，相忘兩逾月。", "霜花著紅小，幽香逗疎樾。", "風晴春一似，携具任倉卒。", "招邀二三子，才思湧難竭。", "却愁費吾詩，筆端口方訥。"]'),
('0b32bb43-a822-40a2-bd4c-04916d48f370','觀舊寫照有感','張鎡','宋','宋诗','song-poetry','','[]','趙茂寫我真，今朝喜重見。',168,'全唐诗/poet.song.170000.json','["趙茂寫我真，今朝喜重見。", "相望十五載，容貌盡更變。", "恰如逢故人，省認向時面。", "自憐歲月去，亟若弦上箭。", "其間憂與病，往往幾歷遍。", "寒暑外侵薄，思慮內縈纏。", "幻形類草木，熟能永葱蒨。", "髮幸纔半白，登臨未衷倦。", "逍遥溪復壑，安穩寢并膳。", "十年每一畫，能用幾何絹。", "會看烏帽下，滿垂銀色線。", "莫嫌老易來，身健儘堪羨。", "頼有難畫者，炎天飛雪片。", "浩劫且長存，那隨時序轉。"]'),
('4730000b-d14c-4cef-9560-09b44d50b082','次韻清閟對月','張鎡','宋','宋诗','song-poetry','','[]','氍毹恣懶倦，晚夢聊一中。',72,'全唐诗/poet.song.170000.json','["氍毹恣懶倦，晚夢聊一中。", "夢游玉蟾宮，朱扉釘金銅。", "天寬珮聲微，非關夜無風。", "覺來動惋嘆，緒猥紛愁攻。", "人間無了期，得失爭雞蟲。", "竹邊念小童，有酒清如空。"]'),
('dd5978c5-92c6-4262-ad8b-3572c7f497ef','重午','張鎡','宋','宋诗','song-poetry','','[]','林間忘時節，今朝忽重午。',180,'全唐诗/poet.song.170000.json','["林間忘時節，今朝忽重午。", "雨過天未昧，輕陰障初暑。", "追思兒童日，爭先纏綵縷。", "葵榴映昌歜，梅李參角黍。", "書堂給休假，歡呼屢跳舞。", "但喜逢佳辰，那知歲如許。", "遄經六六回，勞生竟何補。", "幸早安靜樂，飛潜伴鱗羽。", "猶憐艾作人，獰瞠儼當戶。", "想其亦自畏，勢險正騎虎。", "孰若平地我，不隨時仰俯。", "門前鷗鷺波，宅畔花柳圃。", "晨看一卷經，暮飲三杯醑。", "詩成時落韻，格調任踰矩。", "大勝汨羅人，獨醒徒自苦。"]'),
('ab76c486-c34b-4063-a875-28074d5fd297','中秋後一夜觀月','張鎡','宋','宋诗','song-poetry','','[]','昨夜月色佳，孤坐不及賞。',168,'全唐诗/poet.song.170000.json','["昨夜月色佳，孤坐不及賞。", "深嘆一歲中，此景無復兩。", "冒冷試出戶，霧氣方漭沆。", "金行既中分，宇宙萃澄漺。", "堂堂大圓鏡，倒攝山河像。", "或云有桂樹，强作枝葉想。", "疇能窮兆朕，聊爾付惚怳。", "曾無驚鵲飛，但聽悲蟲響。", "氣舒厭偪仄，望極增嘆仰。", "今夕看尤好，流光透帷幌。", "祗欠些子緣，照物尚晶爽。", "盆池局牆角，刺歷認菰蔣。", "病餘不舉酒，安得詩思廣。", "何當揖浮丘，跨鶴離塵坱。"]'),
('0e18890c-e7b7-4246-8b69-db9f12432384','重九日病酒不飲而園菊已芳薄莫吟繞亦有佳興因和淵明九日閒居詩一首聊見嚮慕之意云','張鎡','宋','宋诗','song-poetry','','[]','心境本一如，美惡緣妄生。',108,'全唐诗/poet.song.170000.json','["心境本一如，美惡緣妄生。", "惟今尋常日，强以重九名。", "入秋雨澤慳，連朝更晴明。", "木葉未苦凋，禽鳥皆春聲。", "寓形天宇內，自顧非壯齡。", "年年登高時，無菊酒漫傾。", "何如茲歲好，金英照軒榮。", "遠懷柴桑翁，合處無疑情。", "不飲還醺然，妙寄由天成。"]'),
('98826b9e-91ea-43f0-a1d2-1384538e6c01','夜興','張鎡','宋','宋诗','song-poetry','','[]','老火頓掃迹，顥氣凝清英。',144,'全唐诗/poet.song.170000.json','["老火頓掃迹，顥氣凝清英。", "病悰少棲泊，循簷聽風聲。", "桂魄未及圓，列緯已讓明。", "銀潢誰决流，靜向蒼旻傾。", "引領欲縱望，衆屋高崢嶸。", "又成興局促，萬里孤遐征。", "陰牆想露漙，夕蔓粘青螢。", "怯冷獨歸戶，搔頭對長檠。", "咨嗟分賦薄，煮藥過半生。", "隨緣但順受，境逆或漸平。", "年年中秋夜，裴回曉鐘鳴。", "屈指行復來，得失當除乘。"]'),
('01000f7d-cdaf-4bf9-a7f8-038c9b7a6b04','癸卯立秋後一日鑿井竹間','張鎡','宋','宋诗','song-poetry','','[]','茲歲苦告晹，旱熯彌五旬。',276,'全唐诗/poet.song.170000.json','["茲歲苦告晹，旱熯彌五旬。", "老火秋益焚，陽螭燎朱鱗。", "小寢屢亭午，牀移瞰墀垠。", "迎南有風到，汛掃方無塵。", "髯奴挈缾水，云此乞諸鄰。", "同居雖楹連，列位難地均。", "舊井蔭一亭，經夏汲取頻。", "霤澤既稍愆，土脈幾就湮。", "倏思書齋外，牆西種叢筠。", "而間事墾掘，泉眼當津津。", "涓辰甲戌良，霜鍤穿苔茵。", "下浚十尺餘，疏泥出膠墐。", "靈泉果旁溢，清泠潔如銀。", "板松實爲底，環塼虛至脣。", "汞沙赤顆塊，石英紫璘皴。", "投置可蠲疾，釀麴尤甘醇。", "青絲繫銅壺，挹玩醒心神。", "當年負暄老，猶將獻嚴宸。", "九重方焦勞，渴饑念黎民。", "昨暮雨一篩，四野艱敷勻。", "今晨直言詔，庶政勤咨詢。", "諫聽將必行，純誠動蒼旻。", "沾蘇徧原畝，丕昭吾君仁。"]'),
('eedbe978-2a54-450f-9716-ac98cf7625bc','賀尤禮侍兼修史侍講直學士院四首  其一','張鎡','宋','宋诗','song-poetry','','[]','禮云風斷烟，鬨議十九失。',48,'全唐诗/poet.song.170000.json','["禮云風斷烟，鬨議十九失。", "片言灼龜鑑，鉅典資以秩。", "抗志非太高，砭艾起時疾。", "何翅位宗伯，宇內頼調一。"]'),
('dd822f85-6a41-47e4-94ee-44ec57c09422','賀尤禮侍兼修史侍講直學士院四首  其二','張鎡','宋','宋诗','song-poetry','','[]','斯文未摇落，右序啟哲人。',48,'全唐诗/poet.song.170000.json','["斯文未摇落，右序啟哲人。", "胸中悟復悟，筆底新又新。", "幻爲九色絲，鑾坡演明綸。", "兵民總疲羸，夜直煩前陳。"]'),
('c5db1983-6f7a-4c42-8000-47ba44e5783c','賀尤禮侍兼修史侍講直學士院四首  其三','張鎡','宋','宋诗','song-poetry','','[]','化權亞史法，委巷汩凡例。',48,'全唐诗/poet.song.170000.json','["化權亞史法，委巷汩凡例。", "良由私愛怨，或使疑信二。", "姦諛人力勝，危欲蔽忠義。", "絕識超大千，簡冊當吐氣。"]'),
('681d373c-1f94-40f7-9a32-b9b497750e83','賀尤禮侍兼修史侍講直學士院四首  其四','張鎡','宋','宋诗','song-poetry','','[]','道傳至孔孟，人主不己任。',48,'全唐诗/poet.song.170000.json','["道傳至孔孟，人主不己任。", "空言課講說，日用惑已甚。", "聖朝重橫經，仁澤天下飲。", "公談故紙外，句句格精祲。"]'),
('5719ce36-4eb1-4a71-b95d-b1667e402a2f','小疾書興','張鎡','宋','宋诗','song-poetry','','[]','卷懷無與適，著冠試徐行。',168,'全唐诗/poet.song.170000.json','["卷懷無與適，著冠試徐行。", "廊西小堂幽，叢篁雜荷聲。", "吹衣怯風猛，簾垂一床橫。", "坐餘忽屢嘆，安閒吾半生。", "無端局官簿，隨羣覬浮榮。", "出入與日俱，何嘗惠黎氓。", "今晨疾在告，反覺意氣平。", "爐烟結復開，遠度松梢明。", "晴久色愈耐，枝疎韻尤清。", "香去松不隨，香來松不迎。", "倏然歸太虛，無心計虧盈。", "一著要我决，豈在他人評。", "還尋鷗鷺伴，靜樂烏可名。", "眼前俗物空，秋老共身輕。"]'),
('66cd7457-1a7b-4a2b-adf9-5b278b070a66','次韻陸南宮晨起有感','張鎡','宋','宋诗','song-poetry','','[]','駡坐非真豪，挂冠豈實高。',120,'全唐诗/poet.song.170000.json','["駡坐非真豪，挂冠豈實高。", "畸跡烟雨埋，客氣利祿鏖。", "曷若大丈夫，本志輕旂旄。", "無擇眼界平，芬馨等羶臊。", "機息箭自空，詎復論弓櫜。", "先生博達姿，閡世江河滔。", "器吞子貢璉，才奪東方袍。", "出處日兩忘，居朝隠蓬蒿。", "一代能幾人，稱提付郎曹。", "飯熟菜亦香，但教齒牙牢。"]'),
('ae72c67e-4b07-4e73-8349-168b040bc73b','次韻陳唐卿縣尉','張鎡','宋','宋诗','song-poetry','','[]','耽詩固無益，損慮更招咎。',144,'全唐诗/poet.song.170000.json','["耽詩固無益，損慮更招咎。", "技癢搔不療，銘坐口還又。", "出門索朋儔，培我本根厚。", "頑石夸瓊瑰，朽壤被絺繡。", "歸來三歎息，誰脫章句囿。", "堂堂柱下史，退食燕清晝。", "門前車馬閙，有客老且瘦。", "無求見容貌，話味若飲酎。", "從容得句帙，細讀前竟後。", "令人發深省，咀嚼盡華茂。", "要須即所見，快手撤蒙陋。", "蘭香出深林，著意烏可嗅。"]'),
('147fe27b-53b4-4297-a79a-92df35d4e985','自廣巖避暑西庵','張鎡','宋','宋诗','song-poetry','','[]','推枕欣朝凉，開戶畏炎日。',216,'全唐诗/poet.song.170000.json','["推枕欣朝凉，開戶畏炎日。", "駕言城西遊，滯懣去如失。", "山空秋易知，石近雲屢出。", "穿松得古寺，隨喜聽講律。", "士女蜂蟻來，蟠香散經帙。", "囂思攝正念，頗識動化術。", "蔬飯有餘飽，徐行縱閒逸。", "隣庵亦窈深，綠杉間疎密。", "殿宇煥新築，不待方丈室。", "相留屏俗情，話澹喜促膝。", "修筠入支徑，池亭面崷崒。", "從容十數刻，佳趣領無佚。", "風床捲青簟，露井放寒繂。", "藕花雜蒲稍，芳氣遠如一。", "紛塵愜虛靜，詩成任荒率。", "殷雷喚飛雨，爽氣定盈溢。", "興酣在景晚，歸騎莫馳疾。", "新霜更須來，携樽摘林橘。"]'),
('880ea54f-a1d6-4119-80ed-3e8fcf403e4e','自安福過真珠園梅坡','張鎡','宋','宋诗','song-poetry','','[]','舒憂早踰關，延晤盡名侶。',144,'全唐诗/poet.song.170000.json','["舒憂早踰關，延晤盡名侶。", "林亭果幽賞，得計良自許。", "高鳴迭酬唱，陽春誰激楚。", "坐移遊好園，振策盼芳渚。", "曾茅舊剪結，冰艷靜誰與。", "幾年楊巨源，句妙聽鐘敔。", "謫仙繼前躅，凌厲蒼霄舉。", "吾人潘逍遥，清新出機杼。", "揆予才獨後，乙乙抽繭緒。", "肆瞻宇宙宏，氣類混出處。", "盍簪忍輕散，快意樽中醑。", "相看豈時情，襟期耐寒暑。"]'),
('442eb32f-94b6-4b39-8b49-41f0b572e5f8','往逸村雪中上船','張鎡','宋','宋诗','song-poetry','','[]','東皇喜我出，恐無賦詩題。',156,'全唐诗/poet.song.170000.json','["東皇喜我出，恐無賦詩題。", "夜呼姑射仙，盡把雪覆泥。", "迎晨倚戶觀，凍雀戀樹棲。", "霙疎雜霰濕，未暇平高低。", "體物非所長，意蕩著語稽。", "收興入輿幔，護寒擁裘綈。", "迢遥下谿步，登舟蘚橋西。", "摇兀略坐定，艣聲已緣隄。", "客船與漁篷，漸遠離排擠。", "皓色山上見，素光水中迷。", "隔路望小家，緋桃篠枝齊。", "茅簷果自樂，何必深堂閨。", "春郊正須遊，带酒尋村雞。"]'),
('0c953f5b-d897-4a30-b678-50cd0dcb2746','徑山綽上人寄新雪','張鎡','宋','宋诗','song-poetry','','[]','重闉初履霜，深山已堆雪。',120,'全唐诗/poet.song.170000.json','["重闉初履霜，深山已堆雪。", "牛鳴數舍地，氣序何驟冽。", "禪宮舊龍居，長夏扇可徹。", "千崖蔽森蓊，雙徑穿巀嵲。", "所以方冬時，集霰即飛屑。", "廊階遊鴿處，爪跡應凍絕。", "立齊老僧腰，此話忌輕說。", "掃贈滿棕筥，凝明勝瑶玦。", "梅風落葉窗，我固傍高潔。", "疇能報清投，煎茶沃詩舌。"]'),
('1d10f064-ebfb-46c6-8846-449037a63934','莊器之賢良居鏡湖上作吾亦愛吾廬六詩見寄因次韻述桂隠事報之兼呈同志  其一','張鎡','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，地僻猶深山。',132,'全唐诗/poet.song.170000.json','["吾亦愛吾廬，地僻猶深山。", "山亦前後有，遠望碧玉環。", "繄昔近市居，局促幾泥蟠。", "買園闢荒榛，運量百畝寬。", "勤勞藝且築，就緒五載間。", "葛巾雅相宜，何心傲蟬冠。", "流光隙中駛，霜鬢映蒼顔。", "恬愉無競外，幸免歷世患。", "旁人笑野拙，枉是家長安。", "開門面陂澤，岸岸蒲蓼灣。", "此身夫何疑，郊島乃瘦寒。"]'),
('2b9cf5a1-457b-4cef-9f60-5b5e034362be','莊器之賢良居鏡湖上作吾亦愛吾廬六詩見寄因次韻述桂隠事報之兼呈同志  其二','張鎡','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，萬木紛秀挺。',72,'全唐诗/poet.song.170000.json','["吾亦愛吾廬，萬木紛秀挺。", "一一親主盟，非特時管領。", "緬懷蠻觸氏，隕腐爭奪境。", "躍然起予衷，大類困澆茗。", "掃空市虎疑，照破杯蛇影。", "步寬更容人，園中無陿徑。"]'),
('f2cd4dc6-3be9-4c4a-b7a2-2b75d0d43d4c','莊器之賢良居鏡湖上作吾亦愛吾廬六詩見寄因次韻述桂隠事報之兼呈同志  其三','張鎡','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，第一桂多種。',108,'全唐诗/poet.song.170000.json','["吾亦愛吾廬，第一桂多種。", "西香郁天地，不假風迎送。", "花開與花落，真境未嘗動。", "羣芳亦時有，幻巧雲錦綜。", "廓然清浄觀，豈復計疏壅。", "紅紅白白處，政自見日用。", "江山雖阻修，此樂朝暮共。", "逢場任竿木，何許非戲弄。", "一笑和君詩，是亦夢中夢。"]'),
('f8226605-eb11-4da8-a442-f342243d28d4','莊器之賢良居鏡湖上作吾亦愛吾廬六詩見寄因次韻述桂隠事報之兼呈同志  其四','張鎡','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，試聽談向背。',96,'全唐诗/poet.song.170000.json','["吾亦愛吾廬，試聽談向背。", "維南匯平湖，浙水實分派。", "兩峰屹三塔，形勢遠襟带。", "城中那有此，到處憐湫隘。", "拏舟信所之，詎復防厲揭。", "猿鹿騖幽曠，引遯終遠害。", "抱垣更通津，漁釣欲寄快。", "都緣跡不羈，徹老心自在。"]'),
('ab5060cb-f270-4c47-ab5f-c5fa9382ee0d','莊器之賢良居鏡湖上作吾亦愛吾廬六詩見寄因次韻述桂隠事報之兼呈同志  其五','張鎡','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，精舍出其右。',72,'全唐诗/poet.song.170000.json','["吾亦愛吾廬，精舍出其右。", "南山祝吾君，身自樂畎畝。", "福田非住相，初不藉耕耨。", "衆生睹善法，政合遠奔走。", "誰知在家僧，特未斷葷酒。", "更有一般獃，望南看北斗。"]'),
('71dc956f-cef5-406b-9d61-e73c264fb018','莊器之賢良居鏡湖上作吾亦愛吾廬六詩見寄因次韻述桂隠事報之兼呈同志  其六','張鎡','宋','宋诗','song-poetry','','[]','吾亦愛吾廬，門前賣時蔬。',96,'全唐诗/poet.song.170000.json','["吾亦愛吾廬，門前賣時蔬。", "滿擔風露香，選擇未始無。", "蘇子覓二頃，楊翁營一區。", "兩者况見成，自顧慚晨晡。", "不妨瘦如竹，何急肥似壺。", "向來鍊句癡，工拙分毫銖。", "如今布袍下，識字村田夫。", "諸公信余言，相從莫踟躕。"]'),
('d5501cd3-9523-4e3a-a361-d55033d79da6','俞玉汝以詩編來因次卷首韻','張鎡','宋','宋诗','song-poetry','','[]','我生癖耽詩，極力參古意。',240,'全唐诗/poet.song.170000.json','["我生癖耽詩，極力參古意。", "寥寥千百年，所取僅三四。", "此言或是癡，的確有見地。", "大雅既不作，少陵得深致。", "楚騷久寂寞，太白重舉似。", "堂堂豫章伯，與世不嫵媚。", "峭峭後山老，深古復靜麗。", "長篇雜短章，末學敢睥睨。", "儻非四公者，孰畢此能事。", "俞君江南英，懶效决科計。", "俗子造其廬，覓句獨擁鼻。", "雪風灞橋路，想見形夢寐。", "貽我青雲編，三讀增畏愧。", "未嘗膠山林，亦復到城市。", "石頑木鑽透，悟處定不二。", "清風濯炎暑，使我破蕪穢。", "情悰猥能同，外此誰臭味。", "請加精進心，道遠烏足喟。", "駸駸不停規，今古本無異。", "詩來我知往，因以當交質。"]'),
('390b15d1-6c78-4754-9165-4e2542e2a3b9','次張以道韻','張鎡','宋','宋诗','song-poetry','','[]','耽幽畏奔逐，何翅畏暑寒。',132,'全唐诗/poet.song.170000.json','["耽幽畏奔逐，何翅畏暑寒。", "豈真傲世人，亦各性所安。", "弄水小漁艇，尋詩蹇馿鞍。", "相宜清晝永，嬉娛絕嗟嘆。", "方苞紅玫瑰，紛萌翠琅玕。", "胡爲悉棄置，隨人强蹣跚。", "頭顱每自知，終難繼貂冠。", "超情混俗久，漫若草敗蘭。", "委身羈馽中，黽勉聊自寬。", "習氣猶未除，搜句雕腸肝。", "偷閒時一遊，園池有荷槃。"]'),
('a476109d-06b3-4409-8451-0d2f66d34064','寄題莊器之招隠樓','張鎡','宋','宋诗','song-poetry','','[]','得時則爲人，此固丈夫志。',264,'全唐诗/poet.song.170000.json','["得時則爲人，此固丈夫志。", "生前必功名，說實起後世。", "君看禹稷徒，烏有覬望意。", "偶然事逢手，勢若破竹易。", "所以極萬代，偉績不可槩。", "紛紛務勉强，指日苟聲利。", "等觀今昔爲，迷悟由性異。", "莊侯海內士，豈特靜者類。", "深歎末俗競，懶赴殊科試。", "力田抄飯白，結屋傍山翠。", "受用已有餘，推此更廣施。", "名樓曰招隠，來者定弗棄。", "我恨聞命晚，已買城北地。", "湖濱林麓幽，市遠車馬避。", "想像輞川寬，庶幾盤谷邃。", "雖非千步門，肯換一品位。", "桃蒸春浪活，桂馥秋風至。", "其時思故友，命駕驚晝睡。", "堂堂無他言，握手笑相視。", "吾儕東西隔，橘枳本同味。", "中年各菟裘，要非太早計。", "何須並牆居，而後願始遂。"]'),
('603737fd-e4e1-4892-9948-962e3993a642','次韻答張以道茶谷閒步','張鎡','宋','宋诗','song-poetry','','[]','藝此百畝園，池亭粗供遊。',132,'全唐诗/poet.song.170000.json','["藝此百畝園，池亭粗供遊。", "新從小堂陰，經營學山丘。", "攢叢數百樹，如對曠士流。", "奇石皆有情，聽詩疑點頭。", "方池正當前，風定清若油。", "照影畫不成，葉茂枝相樛。", "心靜境自來，非關苦尋搜。", "知我與罪我，此話同春秋。", "委順付天命，萬事杯中浮。", "莫疑頭上絲，曾因利榮愁。", "若無忘斯言，長年共無憂。"]'),
('fc5b08ba-392b-419c-b58c-7b08daf70056','宿餘杭普救蘭若同訥義二僧訪法喜寺尋登綠野亭','張鎡','宋','宋诗','song-poetry','','[]','平生樂遊觀，幾欲遍區宇。',240,'全唐诗/poet.song.170000.json','["平生樂遊觀，幾欲遍區宇。", "足力有限量，勝處空默數。", "餘杭舊名邑，相距纔步武。", "蘇翁綠野詠，方冊每欣睹。", "朅來始經行，解擔日蹉午。", "招提略憇倦，鑪熏散雲縷。", "上人別累年，省識但能祖。", "應憐憂患跡，官路還踽踽。", "將勤設瓜果，就蔭指柵楰。", "少焉湯浴罷，作意訪奇古。", "相從到鄰寺，儒宮換堂廡。", "揆昔列鐘魚，俄此登簋簠。", "萬法迭成壞，紛紛競誰主。", "旋陟陂上亭，傾摧幾風雨。", "老柳不復見，危闌試憑俯。", "青山幸縈繞，寧暇問秦禹。", "水流天接處，桑塍間蔬圃。", "種蓮止坳塘，炊煙莽村聚。", "咨嗟雜慰快，擬去還眷憮。", "一笑詩已成，馳奔遽忘苦。"]'),
('d2df59ad-b070-43de-ab1f-bb47142c951c','戲效樂天體','張鎡','宋','宋诗','song-poetry','','[]','去日不可再，來日焉可虛。',192,'全唐诗/poet.song.170000.json','["去日不可再，來日焉可虛。", "直待百事足，漫把四大拘。", "黄河幾曾清，白髮莫旋烏。", "全福貴安然，真樂難强圖。", "朴直自許我，才能不如渠。", "已盟方寸心，免苦六尺軀。", "登臺值明時，擊壤容匹夫。", "輕車歷野寺，小船泛晴湖。", "金鯽池內觀，白猿洞前呼。", "孤山未學林，長堤且懷蘇。", "珍實不滿器，醇醪只携壺。", "更带兩耳鐺，旋煮四腮魚。", "意均飽暖適，迹或升沉殊。", "達人曠大觀，萬象歸一途。", "丹鼎鷄變化，佛性狗有無。", "快答此話頭，擬議計即疎。"]'),
('1adf6ae5-8664-4f65-a014-2b62e5254b40','集古今山林閒適詩以林泉嘯咏名之','張鎡','宋','宋诗','song-poetry','','[]','夜窗涉塵編，山林詩輒取。',48,'全唐诗/poet.song.170000.json','["夜窗涉塵編，山林詩輒取。", "悠然忘世故，正味若醇酒。", "渠能道我言，不必出吾口。", "抄成長自隨，真爲歲寒友。"]'),
('1aee5921-e497-4fff-b9aa-d1f2510a6175','偶成','張鎡','宋','宋诗','song-poetry','','[]','出門苦喧闐，歸舍喜消逸。',48,'全唐诗/poet.song.170000.json','["出門苦喧闐，歸舍喜消逸。", "新篁解重籜，尚带溪粉濕。", "投鑷坐無語，風來動書帙。", "留客不須歸，今夕月方出。"]'),
('2c21f726-e61f-4278-a13d-abc475f57815','不睡','張鎡','宋','宋诗','song-poetry','','[]','溽暑快新霽，濕風生夕凉。',96,'全唐诗/poet.song.170000.json','["溽暑快新霽，濕風生夕凉。", "屋解掛月盤，瀲灧冰玉光。", "飛蟲細可數，夜氣收莽蒼。", "境勝玩不足，橫筇據胡牀。", "孤生念濩落，靜思還慘傷。", "山林平時心，政坐多激昂。", "習懶性已成，投閒計爲長。", "明宵恐陰雨，不睡庸何妨。"]'),
('80e07142-903e-491c-91df-2eb7e85cee7c','同張以道出遊近郊成古詩十六韻','張鎡','宋','宋诗','song-poetry','','[]','今辰天宇佳，風光宛如春。',192,'全唐诗/poet.song.170000.json','["今辰天宇佳，風光宛如春。", "園廬豈不樂，景熟興未伸。", "與客策蹇馿，城東訪幽人。", "幽人本非約，意往隨清真。", "市小度啁哳，秋郊迥無塵。", "楓林纈居前，蔬畦翠橫陳。", "烟濃山愈淡，徐步望更新。", "田翁出荆扉，笑揖似所親。", "坐對俱不疑，一榻三烏巾。", "胸中絕城塹，眼界空越秦。", "紛紛癡濁世，等別生顰嗔。", "青旗正飄摇，小店恰與隣。", "相邀開縹甕，橙梨共珍醇。", "悠然會陶然，此適屬隠淪。", "我家幸匪遠，要辦來常頻。", "平橋指歸途，野囀依叢筠。"]'),
('a44ac923-ba8c-48f2-9e45-5e964c6a0a6b','酌道傍古松下錢王水對山絕頂微露塔尖聞有僧院名益錢','張鎡','宋','宋诗','song-poetry','','[]','山圍當車巾，佳興坌滿前。',168,'全唐诗/poet.song.170000.json','["山圍當車巾，佳興坌滿前。", "盤松儼如畫，蓋疊疎蘿纏。", "沙平恰席許，坐蔭宜鋪氈。", "扶筇瞰根穴，湛碧泓寒泉。", "霏空雨方來，衆綠爭欣然。", "炎銷道旁地，此倍凝陰烟。", "摩挲復潄滌，毛骨俱澄鮮。", "輪囷復清冷，肯受代謝遷。", "何必絕塵世，高潔自永年。", "錢王德民深，姓氏水爲傳。", "遥瞻窣堵坡，背立蒼巒巔。", "人言有廢寺，欲到愁攀緣。", "諸天散香華，顧我應惻憐。", "被役不爲饑，凡質何繇僊。"]'),
('4f61d409-8ce6-4cd2-bd3a-1896d7890437','次韻傅景夏見贈兼簡徐季益','張鎡','宋','宋诗','song-poetry','','[]','懶情妨勇志，闇識乖明時。',240,'全唐诗/poet.song.170000.json','["懶情妨勇志，闇識乖明時。", "昔人嗟遠矣，有夢那見之。", "百計諧余衷，第一證以詩。", "合處即券鑰，寧問渠爲誰。", "端居偪仄胸，旦旦荆榛披。", "又如涸轍魴，縱漾清塘陂。", "宗旨要領會，法律忌脫遺。", "泚筆漫擬古，深扃愧無奇。", "寒松凜顔采，恥競桃李姿。", "疲馬借康莊，敢對騏驎馳。", "自娛成自虐，苦心到肝脾。", "孰真念本願，頗或譏繁詞。", "君侯忽我予，臭味幾夙期。", "何時結幽磐，開徑通雙扉。", "花明鶑錦薌，竹暗蜂烟霏。", "應緣更數載，遮莫俗驚窺。", "偉編昨珍投，如病和扁醫。", "月臺氣醇茂，共社當肩隨。", "火龜莫視兆，叶吉庸奚疑。", "解頤持此先，詎須匡鼎來。"]'),
('9a7c2ce0-59e4-40d1-86fe-fd5f65263d7b','近詩殊少閒行綠陰下喜成雜言以自勉繼此當日課云','張鎡','宋','宋诗','song-poetry','','[]','去冬詩絕稀，作意待好春。',216,'全唐诗/poet.song.170000.json','["去冬詩絕稀，作意待好春。", "春至病始甦，强賦情少真。", "梅花到海棠，不過數十首。", "其間豈無興，有筆慵開口。", "每逢風日美，心醉人不知。", "林間行若狂，藉草或移時。", "芳花倏掃蹤，轉作滿園葉。", "油然翠欲流，剪若陰初疊。", "老夫愛深處，穿樹開生路。", "香不是風香，吹來復吹去。", "扶筇仰面看，青子枝間團。", "引客任摘嘗，庸詎疑整冠。", "閒來坐根石，遠望渾無隙。", "大似天女機，重重綠蘿織。", "黄蜂恐我嗔，擬住退逡巡。", "向夏吟更懶，却防蜂笑人。", "從今當健走，古囊勤抖擻。", "莫作蒼蠅鳴，常如獅子吼。"]'),
('fc8b624d-7e18-4b32-a20b-f1e4a377d294','看澗水自警','張鎡','宋','宋诗','song-poetry','','[]','昔往靈隠山，寺前貪看水。',288,'全唐诗/poet.song.170000.json','["昔往靈隠山，寺前貪看水。", "木陰鑑暉彩，泓渟絕塵滓。", "游鯈慣餠餌，敲欄聚如蟻。", "坐翫豈不佳，直須波浪起。", "開閘放三板，驚雷奔壑底。", "如油石上苔，老澱光瀰瀰。", "衣裳任濺灑，輕飈颯盈耳。", "歸來尚入夢，睡覺思未已。", "纍年罕遊山，深居遠廛市。", "林卉漸叢茂，窮幽併餘美。", "疏澗彌百尋，縈紆带蘋芷。", "因風作微瀾，綠皺偏可喜。", "有時日向晚，灣處閒徙倚。", "簟紋韡縠皴，風平一齊止。", "瑠璃瑩不動，最愛中間裏。", "擬將拄杖探，恐破難整理。", "擬將瓦礫投，恐涴難揩洗。", "夾岩桃樹影，迎望青迤邐。", "飛禽既歸宿，獨留老居士。", "足痺未忍去，更欲置床几。", "長繩繫羲輪，不容落西汜。", "倏思家中景，非同借來比。", "已拚閒到老，從老閒至死。", "自此晴便看，其看豈涯涘。"]'),
('c9c1880a-2344-4181-b8c0-27badadde006','秋日夙興','張鎡','宋','宋诗','song-poetry','','[]','晨起浴倍佳，爽疏洞膚髮。',120,'全唐诗/poet.song.170000.json','["晨起浴倍佳，爽疏洞膚髮。", "靈蕪鬰寶鼎，清忱睇天闕。", "三十六帝座，一一神遠謁。", "旋瞻雲始盈，灑雨響飃忽。", "餘霏集欄廡，林翠忻蔭樾。", "高枝閑稀星，萬葉被濕月。", "吟喁蛩蚻輩，草際競窸窣。", "觀生物我齊，豈計辨與訥。", "羲車唱羣動，靜思苦易歇。", "摩挲山頭石，汝相筋稱骨。"]'),
('ca84bb17-0db7-4028-9d83-d3233920e70f','讀蕭何傳有感','張鎡','宋','宋诗','song-poetry','','[]','漢祖肇炎圖，三傑咸輔翼。',144,'全唐诗/poet.song.170000.json','["漢祖肇炎圖，三傑咸輔翼。", "功成及酬賞，相國獨第一。", "發蹤指示語，誰曰匪其實。", "焉知英主心，方謹操縱術。", "勳高疑益深，固異亭長日。", "守關忠弗念，置衛防百出。", "堂堂明且審，自計亦無失。", "護軍給餉饋，入秦收圖籍。", "用智既有餘，保身豈難必。", "遜封散宏財，非真召平力。", "汙名起田宅，猶愈受斧鑕。", "終加恭謹辭，賢哉史臣筆。"]'),
('b8949b6c-785c-43f3-83e7-8eb62a53378f','次韻酬銛上人二首  其一','張鎡','宋','宋诗','song-poetry','','[]','修客衣襜如，喔咿守閽傍。',48,'全唐诗/poet.song.170000.json','["修客衣襜如，喔咿守閽傍。", "聞閒掩耳避，令人憶柴桑。", "銛乎問水濱，其道尊空王。", "坐來薝蔔林，不聞有別香。"]'),
('d7f2c9b7-bcb5-421b-9c92-d3958baef0dc','次韻酬銛上人二首  其二','張鎡','宋','宋诗','song-poetry','','[]','孰知苾蒭流，而能建安作。',48,'全唐诗/poet.song.170000.json','["孰知苾蒭流，而能建安作。", "燈檠味雋永，曾不带葵藿。", "已撞禪月鐘，請振普化鐸。", "從伊啞羊呼，高厚中沃若。"]'),
('20eaa0bd-f214-496a-8f50-82c80e6cbbb1','移石種竹橘','張鎡','宋','宋诗','song-poetry','','[]','野性樂閒寂，况值秋氣清。',192,'全唐诗/poet.song.170000.json','["野性樂閒寂，况值秋氣清。", "旋即東牆隈，削苔方甃平。", "石立稍退步，薜荔纏珠纓。", "橘香湖海趣，竹翠山林情。", "二物昔所嗜，未暇同經營。", "環種近百竿，葉葉琴筑聲。", "對植纔兩樹，顆顆金玉明。", "交枝與叢稍，拂巾須緩行。", "其間兩席地，幽致吾主盟。", "靜極坐累刻，焉有世慮縈。", "人生會心處，小大景不爭。", "長年興無涯，風月隨陰晴。", "抽萌及吐蕊，預喜春林榮。", "客來開茗鑪，禮意固匪輕。", "作詩漸忘言，此語亦老成。", "杜門安蹇拙，何急謀虛名。"]'),
('5b3301eb-fc1a-4b63-bd58-2c5d751f6fa6','椶筍詩','張鎡','宋','宋诗','song-poetry','','[]','庭階少幽蔚，樹石聊森陳。',120,'全唐诗/poet.song.170000.json','["庭階少幽蔚，樹石聊森陳。", "海椶最先來，相看兩經春。", "風枯黄髮短，雨老蒼皮皴。", "葉添朝暮層，尚欠著語新。", "陰霖欻幾月，芳苞吐輪囷。", "嘗聞膚毳間，若筍味可珍。", "使其姿柔媚，未必藏甘淳。", "耐饞不忍剖，是乃吾術仁。", "詩人例虛談，夸衒毋諄諄。", "緣木而得魚，慮貽俗子嗔。"]'),
('b2e2b68c-0f6a-4428-b8f4-55ef43bced7d','分韻賦薝蔔得松字','張鎡','宋','宋诗','song-poetry','','[]','呼酒快勸客，教取白玉鍾。',96,'全唐诗/poet.song.170000.json','["呼酒快勸客，教取白玉鍾。", "趁此清浄枝，向我几案供。", "葉豐發油綠，香心刻黄琮。", "向來紅紫陣，喧喧引雄蜂。", "露斑衣上痕，枉負七尺筇。", "日暮詩興薄，幽禪苦魔攻。", "猶勝坐肩輿，排門抗塵容。", "我祖已封侯，便當隨赤松。"]'),
('ec4bb75b-49f3-46cf-8981-349aaf748be9','送綽上人歸後菴','張鎡','宋','宋诗','song-poetry','','[]','春風吹倒人，禪師出山來。',72,'全唐诗/poet.song.170000.json','["春風吹倒人，禪師出山來。", "相陪坐幾月，口邊生塵埃。", "夏風吹長樹，禪師歸山去。", "爲嫌城裏熱，再三留不住。", "學詩無後先，到此如狂顛。", "有問是誰格，且疑三十年。"]'),
('e4bf142f-fb20-4013-9834-81dbc27aa561','我園','張鎡','宋','宋诗','song-poetry','','[]','我園樂復樂，不知夜短長。',48,'全唐诗/poet.song.170000.json','["我園樂復樂，不知夜短長。", "露下楊柳濕，月明蒿艾香。", "歸途林影橫，忍踏瑣碎光。", "衡門尚未掩，犬吠循東牆。"]'),
('db052ebf-9d5a-43d4-9264-cda53ac581f9','回放翁書','張鎡','宋','宋诗','song-poetry','','[]','鷗盟慙久寒，駒足誰苦縶。',84,'全唐诗/poet.song.170000.json','["鷗盟慙久寒，駒足誰苦縶。", "霜雪兩歲暮，轉首飛箭急。", "脂車乏敏手，愛字翻舊笈。", "三山白浄水，樹屋影𧤏𧤏。", "梅花百枝寄，寧當一顧揖。", "官冷坐名熱，天道會張翕。", "多憂莫白頭，丹鉛火常集。"]'),
('570ff1ac-f352-4796-806d-f036b839a691','次韻張子儀郎中','張鎡','宋','宋诗','song-poetry','','[]','南湖葵柳岸，綠多紫紅稀。',60,'全唐诗/poet.song.170000.json','["南湖葵柳岸，綠多紫紅稀。", "有客送詩來，適與葵柳宜。", "得處洞真藴，非我其爲誰。", "坐觀行亦看，意會神蕩怡。", "憫彼世上人，紛紛方外茲。"]'),
('e711ab22-8c99-4b2c-9bab-776fc42a3d66','月色','張鎡','宋','宋诗','song-poetry','','[]','月色夜逾浄，虛庭當我前。',48,'全唐诗/poet.song.170000.json','["月色夜逾浄，虛庭當我前。", "風裳變白玉，何煩佩褊褼。", "曼倩去已久，誰同醉陶然。", "空懷依隠心，三叫芙蕖邊。"]'),
('f4217527-2de1-4532-8228-bc78075a55c6','題畫雲山團扇','張鎡','宋','宋诗','song-poetry','','[]','若箇大圓鏡，處處山河影。',48,'全唐诗/poet.song.170000.json','["若箇大圓鏡，處處山河影。", "誰謂懶拙翁，而能作斯景。", "繄予說是語，未免臚窺井。", "若解目前機，不應言不領。"]'),
('8853b2dc-106a-4a6f-8419-b574f602b4cc','前有一尊酒行','張鎡','宋','宋诗','song-poetry','','[]','霖雨半月今夕晴，風堂人稀燈燭明。',350,'全唐诗/poet.song.170000.json','["霖雨半月今夕晴，風堂人稀燈燭明。", "凉蟲咽咽傍牆竹，聽久但促孤愁生。", "愁生欲伏誰驅遣，渾汗翠液玻瓈軟。", "五斗一石非所長，興來亦覺滄溟淺。", "我生早患難，對酒無可娛。", "辛勤識字不得力，漫事爾雅箋蟲魚。", "痛心曩昔親庭趨，從容侍飲情有餘。", "醉譚先烈從巡初，豈但勇力清疆隅。", "公侯將相隨指呼，親挾日馭升天衢。", "墓碑神龍護寶書，勳庸槩見中全疎。", "機危謀大世莫睹，頼有帝訓昭難渝。", "用心若比某人輩，相懸萬里非同途。", "坐間歷歷言在耳，風木纏悲淚鉛水。", "茫然此事莫輕論，不如盡付金樽裏。", "神仙恍惚休强尋，壯士易老難爲心。", "要須出處任天運，况我自判歸山林。", "一杯復一杯，無客誰同斟。", "案間幸有李白舊詩數百首，試讀精爽飛雲岑。", "安得同渠游，霓裾碧瑶簪。", "回頭却謝髠卓輩，棄置禮法幾荒淫。", "何如高吟泣鬼神，模寫造化歸無垠。", "誰能狸膏金距學鷄鬭，起捉簷柱矯首落落看星辰。"]'),
('951e9d57-4e7e-496d-aa1c-197b17e120a8','冒雨往玉照堂觀梅戲成長篇','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幽人占斷煙波景，不但春風翠紅整。',368,'全唐诗/poet.song.170000.json','["幽人占斷煙波景，不但春風翠紅整。", "繞堂交互玉崚嶒，月中日下光迷影。", "連年勾引客來看，傳得梅聲滿世間。", "西湖處士英爽在，大叫稱屈撾天關。", "拜言臣生太清苦，孤山昏曉搜寒句。", "水邊籬畔識疎斜，若說栽梅臣實祖。", "五湖散人張志和，讀霓不中原夫科。", "門前水擅南湖號，也種梅花數百窠。", "貪吟豈悟無閒字，置之度外猶餘事。", "掩臣梅譽最難堪，薦菊泉荒空廟祀。", "帝曰往哉女雨師，張園梅開正及時。", "風標霧鎖兩旬日，今歲且使遊行稀。", "從來奇觀偏宜罕，何妨別具看花眼。", "不須緣木及守株，時來一釂玻瓈醆。", "晴多每厭蜂蝶狂，妖濃不類南枝香。", "未如就作水仙戲，水精纓珮鮫綃裳。", "素鱗宮闕龍牙牀，瑶麟琪鳳森騫翔。", "洗湔塵坌凝冰霜，是名清浄富貴鄉。", "舉瓢無庸酌天漿，芳槽壓酒銀淋浪。", "桃花流水名漸彰，一醉百榼嗤斗量。", "和靖此樂恐未嘗，大癡小黠聲利場。", "得失分定休自忙，詩成鯉魚爲傳將。", "一閲嗔妬俱已忘，却須信我計頗長。"]'),
('bbc57c31-23e1-4acb-ae0f-3bef8e1d0178','千葉黄梅歌呈王夢得張以道','張鎡','宋','宋诗','song-poetry','','[]','笛聲吹起南湖水，散作奇葩滿園裏。',290,'全唐诗/poet.song.170000.json','["笛聲吹起南湖水，散作奇葩滿園裏。", "被春收入玉照堂，不逐餘芳弄紅紫。", "一春開霽能幾時，江梅正多人來稀。", "光風屈指已過半，頼有緗蕊森高枝。", "今朝拄杖偏宜到，暖碧紅烟染林草。", "悠然試就花下行，便有疎英點烏帽。", "細看寶靨輕金塗，密網粲綴萬斛珠。", "一香舉處衆香發，幻巧更吐冰霜鬚。", "叵羅盛酒如春沼，不待東風自開了。", "呼童撼作晴雪飛，雪飛爭似花飛好。", "上都賞翫爭出城，日高三丈車馬塵。", "誰能擺脫熱官與銅臭，肯學花底真閒人。", "時平空山老壯士，不得滅秦報君死。", "鷄鳴撫劍起相歎，夢領全師渡河水。", "吾曹恥作兒女愁，何如且插花滿頭。", "一盞一盞復一盞，坐到落梅無始休。", "無梅有月尤堪飲，醉卧蒼苔石爲枕。", "醒來明月別尋花，桃岸翻霞杏堆錦。"]'),
('4eb4fa5d-32f5-45c8-8cf6-b3dce96c6b20','廬陵李英才自製墨與梅花寫真艮齋誠齋又許其能詩十月七日携畫見訪且索拙語因成古風以贈','張鎡','宋','宋诗','song-poetry','','[]','我家種梅三百樹，惱人不特香如霧。',192,'全唐诗/poet.song.170000.json','["我家種梅三百樹，惱人不特香如霧。", "階前花影二更來，月光到處縱橫住。", "幾回欲畫嗟未曾，李君能事乃爾能。", "素綃竊我當時景，更引夜月花邊升。", "濡毫暈水厭凡墨，掃烟自就千枝燈。", "客衣緇盡不復恨，但喜占藝清如冰。", "圭玄漆響用不盡，博金價定無虧增。", "又聞覓句頗清熟，社中宗匠交口稱。", "雲臺萬事無心計，只學希夷多愛睡。", "醒時非畫亦非詩，恣向虛空寫千偈。", "君船再過嵎中未，烏丸併望新篇寄。", "醉來染試陋溪藤，滿壁蛟龍風捲地。"]'),
('b33c1f5e-1b94-47b6-acea-bafab02de6af','劉宗古畫過海壽星','張鎡','宋','宋诗','song-poetry','','[]','南極煌煌山川精，輝明淵耀爲天經。',152,'全唐诗/poet.song.170000.json','["南極煌煌山川精，輝明淵耀爲天經。", "化成仙人渡滄溟，黑風不作魚龍腥。", "冉冉風氣如雲停，峩冠曳带從竛竮。", "脩髯炯目玉鍊形，神光轉映浮中庭，穹龜坐踞捐輜軿。", "遼東令威姓維丁，翔空欲下摇霜翎。", "予方厭世爭腐腥，棲心元域全攖寧。", "此圖誰將揭素屏，細觀混體通百靈。", "誅馘飛毒命門扃，清音透頂聞雷霆。", "披蘿重岡斸松苓，我命在我同千齡。"]'),
('eb5f25db-074f-4d42-ada9-d9f5d2b53818','跋周昉畫錫宴圖','張鎡','宋','宋诗','song-poetry','','[]','汾陽賸建扶危功，清議那有魚軍容。',192,'全唐诗/poet.song.170000.json','["汾陽賸建扶危功，清議那有魚軍容。", "倖人恃寵自矜伐，似可唾去極力攻。", "今也束带比肩立，絕口不問如盲聾。", "水衡有錢誰敢費，設席授几爲爾供。", "金鵝罩底果何品，異饌定不人間同。", "翠環玉勺未分勸，坐列有序隨卑崇。", "君恩天大且籠蓋，天意不假人方窮。", "鳳凰五章爲世瑞，亦許梟獍鳴雌雄。", "西山靈木作上藥，道旁惡草翻茸茸。", "方圓白黑正殊調，端在處者全吾躬。", "魯叟當年諾陽虎，望之計拙排顯恭。", "我披此畫屢歎息，杜老謀深言至公。"]'),
('c7bb214d-694c-4cc1-83be-0de6f6b5a434','馬賁以畫花竹名政宣間其孫遠得賁用筆意人物山水皆極其能余嘗令圖寫林下景有感因賦以示遠','張鎡','宋','宋诗','song-poetry','','[]','世間有真畫，詩人幹其初。',112,'全唐诗/poet.song.170000.json','["世間有真畫，詩人幹其初。", "世間有真詩，畫工掇其餘。", "飛潜與動植，模寫極太虛。", "造物惡泄機，藝成不可居。", "爭如俗子通身俗，到處堆錢助癡福。", "斷無神鬼泣篇章，豈識山川藏卷軸。", "我因耽詩鬢如絲，爾緣耽畫病欲羸。", "投筆急須將絹裂，真畫真詩未嘗滅。"]'),
('0af37887-a7dd-4265-b7a2-df8d8aaa0a8d','舊藏文與可墨竹未有對者叔祖閣學以一枝爲惠','張鎡','宋','宋诗','song-poetry','','[]','崔黄拂素桃李開，春閨融豔蜂蝶猜。',192,'全唐诗/poet.song.170000.json','["崔黄拂素桃李開，春閨融豔蜂蝶猜。", "范郭揮毫水石具，古愁宛奧關山迴。", "近代名家工寫物，妍媚嶙峋空傑出。", "此君孤稟歲寒姿，不入尋常丹粉律。", "江南鈎鎖殊拘攣，直幹蟠鬰羞雲煙。", "湖州書飽翻老墨，放枝落紙爭流傳。", "有來一幅垂虛壁，冷葉疎莖伴幽寂。", "眼空四海無與儔，出手知公不勞力。", "世間快意非人爲，曩昔經營心坐馳。", "從容會合若符節，辛苦反悟皆兒癡。", "從今相對成三友，憎愛俱損保長久。", "茂林分蔭已無窮，更合新詩同不朽。"]'),
('7d5937d7-421b-47c6-85f0-27376a6da04f','朱師關畫梅溪春曉圖','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅溪之水何清哉，萬頃玉碧天邊來。',230,'全唐诗/poet.song.170000.json','["梅溪之水何清哉，萬頃玉碧天邊來。", "兩山拱挹各異狀，上有磅礴巨石散落生莓苔。", "松蘿籠蒙共糾結，带映萬蕊紛瑶瑰。", "香繁粉豔露凝濕，下視凡卉真輿臺。", "露裾褊褼彼仙子，褰裳矯首遥相俟。", "心清悟物思相羊，指點八極供翱翔。", "胎仙舞空爲前導，紫芝煜煜更芬芳。", "時當初霽放曉色，赫日滉漾咸池光。", "羅浮幽夢奚煩數，西湖漫賦橫斜句。", "相逢弭棹定情親，翠杓瑶罌恣傾舉。", "東鴉西兔從飛馳，維北有斗南有箕。", "化工精妙得師旨，寫入縑素不使捐毫釐。", "何當著身此溪上，溪清梅白森相向。", "吾與二子成三人，共看桑田乾海浪。"]'),
('62263f4a-8454-4120-8398-17d2087073ab','書鎖樹諫圖','張鎡','宋','宋诗','song-poetry','','[]','中國人材未嘗絕，季龍何苦稱豪傑。',84,'全唐诗/poet.song.170000.json','["中國人材未嘗絕，季龍何苦稱豪傑。", "一朝得志忘穹廬，侈心不遏洪河决。", "沙丘未破身先爇，義士敢忘膏斧鉞。", "所幸嚮來涉經史，敢過知非猶可說。", "噫!固知禮義之本根人心，何如露臺惜百金。"]'),
('f7e15f46-a00e-4782-81c0-bf7d37ec60c6','奉祠雲臺題陳希夷畫像','張鎡','宋','宋诗','song-poetry','','[]','張子爲人懶無對，遮手一官追行輩。',224,'全唐诗/poet.song.170000.json','["張子爲人懶無對，遮手一官追行輩。", "撲緣埃壤半年餘，亡補公家真合退。", "病羸應念故園荒，連緘力扣中書堂。", "琳宮分秩問天得，給舍便喜書敕黄。", "沉疴返舍倏去體，涸鮒順水回春塘。", "壁間先掛陳處士，案上更置銅爐香。", "易編與我爲四友，一段因緣殊不偶。", "從容何止兩歲期，自此相依當耐久。", "清腴氣貌儼如生，入京尚想騎馿行。", "世間大事硬漢了，物有所重有所輕。", "後來一曲愈可尚，不暇隨人作卿相。", "急歸依舊白雲鄉，忍使猿驚空蕙帳。", "東吳西華遥相望，海霧天風正摧盪。", "無邊花月自依春，來伴南湖詩酒舫。"]'),
('fcc0ceec-44c0-478f-978e-61570846ba6d','陸編修送月石硯屏','張鎡','宋','宋诗','song-poetry','','[]','何年商顥澄中秋，中光列籍稀校讎。',368,'全唐诗/poet.song.170000.json','["何年商顥澄中秋，中光列籍稀校讎。", "冰輪充滿不復玷，玉斧棄置無煩修。", "蝦蟇遁走兔老黠，歷歷可認渾銀樓。", "揚光厭倦落凡眼，臭黄漲霧紛蜉蝣。", "收芒轉彩向林壑，孕秀石腹非雕鎪。", "夜深輝怪想出沒，肯混瓦礫埋荒幽。", "地神竦踴競持護，山鬼睥睨潜驚媮。", "扶疎檜影亦透入，非假幻化人能不。", "誰將作屏伴几硯，窗日互耀摇雙眸。", "三山放翁實贈我，鎮紙恰稱金犀牛。", "翁今鉅宋清廟器，咸鐘韶磬鏗鳴球。", "所學况不負天子，報國豈暇官資謀。", "子虛賦傳賜科第，始計兵說裨宸旒。", "傾城寵易妬亦速，巴蜀寄宦甌閩遊。", "仙風俠氣愈卓越，錦袍玉局當朋儔。", "平生專車祗文藁，江漢萬古詞源流。", "崑崙坱圠大巧在，乃欲繪畫真堪羞。", "精神聞道尚遒緊，恨未面覿肝腸投。", "此屏遠送有深意，絕勝龜甲圍香篝。", "用張舍避立必直，銘戒要我參李尤。", "拙詩酬貺忘不韙，是亦一癡何從瘳。", "菱租魚市仰高詠，乘輿未果隨子猷。", "來春流水鱖肥好，看我坐釣書船頭。"]'),
('650461f9-d2eb-4c6b-b321-352415757887','太平印歌','張鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','修溪檢校閒桃李，暗記蒼苔唯屐齒。',256,'全唐诗/poet.song.170000.json','["修溪檢校閒桃李，暗記蒼苔唯屐齒。", "野鴛時看立汀沙，个字分明尤足喜。", "金駝銀鼻豈關念，夢月當窗印寒水。", "閨門瓜戍忽臨期，交與銅章令滌視。", "篆文春蚓紅縈纏，背刻太平興國年。", "因記太宗全盛日，車書萬里恢山川。", "吳王納地初改郡，錢塘國勢猶依然。", "治中選任不輕予，縱受往往皆前賢。", "顧我何人來冒綴，迂愚縮朒仍孤顇。", "買臣雖陋會稽懷，靖節殊慙彭澤棄。", "職分猶得按西湖，岸址防侵除葑穢。", "汎舟何事最官况，屬玉鵁鶄總徒隸。", "無煩移牒水仙王，徑寫新篇就印章。", "給露洗開千樹色，支風吹發萬荷香。", "持歸桂隠真堪樂，世界清凉似巖壑。", "更將此印印渠詩，是我前生那得知。"]'),
('88d5d312-0f63-4575-8a50-686fac73839a','渭川獵','張鎡','宋','宋诗','song-poetry','','[]','鳴冬朔風聲披靡，原樹莽蒼枯欲死。',128,'全唐诗/poet.song.170000.json','["鳴冬朔風聲披靡，原樹莽蒼枯欲死。", "出門四望來無人，何許翁閒守寒水。", "胸中百萬總活法，閉口不言心自喜。", "姓名絕念公侯前，草野耕夫略相比。", "一朝千乘從空來，照天戈甲光皚皚。", "罾羅不爲彲羆設，果應龜墨收奇才。", "鷹揚元勳塞兩儀，遣爾後嗣恢宏基。", "魯公如棠但射魚，縱得齒革何能爲。"]'),
('1bcd530e-51b3-4a2d-8bae-ff369e15197b','夜坐放歌書興','張鎡','宋','宋诗','song-poetry','','[]','列星光芒遠近同，天河橫來壓孤篷。',224,'全唐诗/poet.song.170000.json','["列星光芒遠近同，天河橫來壓孤篷。", "溪容一碧看未盡，轉入客子詩筒中。", "筒中滿貯千張紙，一路山川供役使。", "古來霅水足高人，吾宗首說玄真子。", "都緣抱負經濟才，有口掛壁常懶開。", "樵青漁童與共載，大勝俗侶成羣來。", "可憐當時只名重，野鶴乘軒失威鳳。", "雖聞肖像登九重，收奬空言亦何用。", "過五百年孫更癡，布裘椶屩骨格宜。", "特來乃祖舊遊處，三叫庶幾親見之。", "見之不見俱莫問，人生只合將閒論。", "倘來簪紱付兒嬉，聖賢用晦初未悶。", "拍舷還望星與河，此身或是張志和。", "一杯更醉投床睡，明日歌聲猶震地。"]'),
('c7fe9547-c70c-4d25-b114-2f3fb064a9a6','看雲','張鎡','宋','宋诗','song-poetry','','[]','老夫自從歸南湖，兩眼用處不敢虛。',192,'全唐诗/poet.song.170000.json','["老夫自從歸南湖，兩眼用處不敢虛。", "對人豈暇作青白，尚乃懶閲燈前書。", "只將看山并看水，山愛煙晴水風起。", "今朝所向更出奇，極目陰雲滿空裏。", "千千百百巨石堆，一一十十猛獸來。", "春濤忽捲大海動，曉陣漸壓孤城摧。", "當中一抹如龍卧，頭角深藏鱗鬣大。", "濛鴻杳渺却斜明，高烏爭飛欲驚墮。", "須臾變化疑有神，億萬里碧無點塵。", "以知傑觀我已得，模寫詎肯煩他人。", "歸來爲渠急揮掃，自笑粗狂乏新巧。", "莫言雲去沒人知，處處是雲雲是詩。"]'),
('3a596040-e6a2-44d7-8c54-fd0d17d38428','夜看月邊行雲','張鎡','宋','宋诗','song-poetry','','[]','衆人看月愛月明，老夫看月愛雲行。',168,'全唐诗/poet.song.170000.json','["衆人看月愛月明，老夫看月愛雲行。", "青天澄霽月當夜，但有爽快無幽情。", "今宵半月從西上，雲向東移滿虛曠。", "初如玉鏡插蒼崖，次若銀盤沉雪浪。", "忽當濃處全收芒，星斗遠近粲復藏。", "須臾缺處還飛光，林宇高下且陰凉。", "鮮飆颯颯吹我裳，恍然輕舉凌空翔。", "只緣中心無一事，始與世人看有異。", "睡足閒居好滋味，投床徑自齁齁地。", "明夜月明來共醉，多情更看雲裝綴，縱使無雲亦休睡。"]'),
('67646b1b-6e03-4677-910f-b9fd842a2bb8','寄春膏牋與何同叔監簿因成古體','張鎡','宋','宋诗','song-poetry','','[]','蘇州粉牋美如花，萍文霜粒古所誇。',200,'全唐诗/poet.song.170000.json','["蘇州粉牋美如花，萍文霜粒古所誇。", "近年專製淺蠟色，軟玉瑩膩無纖瑕。", "盤門繫纜高橋住，呼僮徑訪孫華鋪。", "琱鎪紅碧任成堆，春膏且問如何去。", "乃知剡溪桃花黄，楮君同譜生殊鄉。", "買來論擔不計數，直候東風花草香。", "其時霢霂吹微雨，潤物無聲略膠土。", "展開千幅向曉空，漬染都勻始輕杵，擣成一色堅且明。", "幽具本豈鑽公卿，要供海內覓句客。", "覓句只今誰有名，月湖老仙居胄監。", "詩好工夫到平淡，寄分聊當野人芹。", "莫充諫藁恐被焚，便將演綸登北門。"]'),
('297c70ca-c8ca-4590-8287-17144bb4b68c','出山追述所見','張鎡','宋','宋诗','song-poetry','','[]','我家正對風煙住，飽看陰晴變朝暮。',224,'全唐诗/poet.song.170000.json','["我家正對風煙住，飽看陰晴變朝暮。", "清秋非但入詩脾，挽向溪山深處去。", "溪山深處是湖州，水合雲凝不斷頭。", "曬稻坡前移拄杖，罩魚灘際泊扁舟。", "入城要盡登臨目，駝橋繫纜因留宿。", "舊遊十載夢驚回，堤邊老柳依然綠。", "凌晨取道峴山前，漥樽就拊穹崖巔。", "縈紆遥指道場路，挂席徑造尋幽禪。", "彎環港轉茭田上，鶑簧激烈千松嶂。", "竹輿飛入翠光中，寶閤朱扉恣舒望。", "當年祖訥伏於菟，躡屐旋薙荆榛居。", "至今夜半吼寒月，守護凈境嚴驅除。", "呼燈談話倏度夕，粥盃共赴雲堂集。", "日高振袂過隣峰，老衲相看但長揖。"]'),
('acd653fa-6554-4227-ace2-42e4a3327c99','讀仙書','張鎡','宋','宋诗','song-poetry','','[]','飛樓半天真人居，玉幢金蕤龍虎輿。',88,'全唐诗/poet.song.170000.json','["飛樓半天真人居，玉幢金蕤龍虎輿。", "層門十丈擁翠樹，枝磨有聲作靈語。", "邪劣未除嗟異路，紫雲翻袍兩儀舞，赤巾使者呼女鬟。", "吟風颯颯鵝笙寒，迎月殿高句難攀。", "踏珠出水如出霧，三十六鳳空銀灣。"]'),
('6152a67a-161f-43d6-a0b1-e75036ee949d','馬當山水府廟','張鎡','宋','宋诗','song-poetry','','[]','江長九月秋氣豪，霜明岸老天愈高。',128,'全唐诗/poet.song.170000.json','["江長九月秋氣豪，霜明岸老天愈高。", "羣真下集水仙府，丁東佩玉聞雲璈。", "修塗隨處愜奇觀，况此樓殿臨烟臯。", "割牲釃酒禱靈貺，順風掛席輕狂濤。", "褊褼數鶴摩空舞，戛然長鳴更凄楚。", "飛來木末獨移時，不逐昏鴉亂洲嶼。", "人言馬當船過難，我喜浩興超然間。", "便須擊楫自此去，指呼萬騎恢河關。"]'),
('becc43f6-374d-41c2-929a-cd2990482a2c','醉後偶書','張鎡','宋','宋诗','song-poetry','','[]','繩床不解雙足頑，藜杖易厭前庭慳。',144,'全唐诗/poet.song.170000.json','["繩床不解雙足頑，藜杖易厭前庭慳。", "茱萸顆小梅孕白，玳瑁文皺苔移斑。", "一鐙左計坐北牖，萬騎縱獵思南山。", "便呼滕六雨好雪，風捲平郊無賸葉。", "鞚飛轉旋疾於鷹，箭勁弓鳴獸旁截。", "芳醪鮮肉娛賓友，撾鼓掁絃催舞袖。", "橫行未絕五原邊，不死終歸三輔右。", "望南再拜稱君壽，愚臣豈解酬恩厚。", "古來相際必風雲，今日名王宜有後。"]'),
('454e3b86-5203-4fd4-b211-ceffb59907c6','王荆文公有客至當飲酒篇姜邦傑廣其意賦詩見示有云有客固當飲無客飲更歌有客與無客頹然同一科僕因和答一首','張鎡','宋','宋诗','song-poetry','','[]','客至當飲酒，客去亦飲酒。',186,'全唐诗/poet.song.170000.json','["客至當飲酒，客去亦飲酒。", "有客與無客，酒杯不離手。", "昔賢立意固可嘉，今賢廣之尤足誇。", "人生都無四萬日，炊黍未辦鬢已華。", "功名富貴軟鐵漢，四萬日中先太半。", "穉衰憂病睡工夫，餘剩不能供罋算。", "何當筠籠罩住兔與烏，請渠同道黄金壺。", "皇王帝霸果何事，醉眼一覷皆虛無。", "春風今年春雨粗，池中水通門前湖。", "垂楊洲旁繫板舫，艷杏橋上行巾車。", "纔晴肯放此樂緩，客有與無俱不管。", "詩成書紙或書牆，後五十年墳草長。"]'),
('49b9c8d3-e05a-484e-bed2-e693d3766358','三愛吟','張鎡','宋','宋诗','song-poetry','','[]','有手須把酒，有口須吟詩。',199,'全唐诗/poet.song.170000.json','["有手須把酒，有口須吟詩。", "更留未老脚，上山當及時。", "我生除此百不愛，儘著餘年了三債。", "一歲縱教醉百回，三日始一眉頭開。", "百年藉使吟萬首，十日得三果何有。", "足健且長閒，當能遍巖藪。", "君不見王逸少，誓墓不出窮名山。", "謂宜以樂終，不願縛足名宦間。", "又不見陶淵明，快飲不負頭上巾。", "嗤笑魯中叟，彌縫闕失成灰塵。", "又不見杜少陵，作詩饑凍猶忘愁。", "未得驚人句，自言到死不肯休。", "人生三物間，所願常周流。", "此身已復專林壑，賦詩飲酒須行樂。"]'),
('194232e9-8f18-4544-963c-716a51c07f98','謝豈菴餉澄粉圓子','張鎡','宋','宋诗','song-poetry','','[]','老蚌嘗聞生合浦，射彩飛芒互吞吐。',258,'全唐诗/poet.song.170000.json','["老蚌嘗聞生合浦，射彩飛芒互吞吐。", "都緣晝夜兩跳丸，縈繞須彌照寰宇。", "金鴉遠逐銀蟾蜍，傳孕億萬皆成珠。", "荒寒海際人罕見，第取服用充珍娛。", "吾宗皎皎青雲器，神餐玉方曾屢試。", "細淘瓊粉滴成泥，幻出勻圓乃無異。", "開奩驚睨未敢傾，蔗霜作伴眼爲明。", "始知可助非時供，餦餭糜糗難爭衡。", "當年魏珠徑寸照乘日，不聞堪鬻資人食。", "漢臯所遇若鷄卵，解贈未竟佩亦失。", "寒宵書窗黄葉鳴，焉有李白力士鐺。", "敲冰然竹喚沙釜，未喜蟹目先蠅聲。", "須臾湯沸投香顆，一顆光浮膩仍夥。", "絕勝車載薏苡歸，誤與文犀遭譖禍。", "但聞頗勞纖指功，慰饕塞饞那可窮。", "從今休遣長須送，我自煨芋聽松風。"]'),
('0281d44c-b519-49cf-8db1-873a49d77402','鴉舅辭','張鎡','宋','宋诗','song-poetry','','[]','自從結廬依北城，入夏常聽鴉舅聲。',176,'全唐诗/poet.song.170000.json','["自從結廬依北城，入夏常聽鴉舅聲。", "五更欲盡日未上，繞樹往往偕鷄鳴。", "想欣綠草露光濕，漸喜茂蔭晨輝清。", "道人披衣起危坐，睡思頓去毛骨輕。", "既免待旦赴朝集，祗欲和月隨農耕。", "人言外甥多似舅，爾甥天資太濁陋。", "固宜相見屢施拳，使瞻在前忽在後。", "衣裾峭整紫翠長，更學燕燕玄爲裳。", "鵲并鸜鵒定通譜，名曰鵯鵊字未詳。", "我園聽鶑兼撫鶴，閒亭本是無心作。", "未能授館專爲君，萬竹千松且同樂。"]'),
('602d5214-ae9b-400c-bc1d-03d5c0b7ac42','茂洪赴漕試歸苦目疾','張鎡','宋','宋诗','song-poetry','','[]','潘侯兩鬢光如月，盡日看山常拄笏。',128,'全唐诗/poet.song.170000.json','["潘侯兩鬢光如月，盡日看山常拄笏。", "經營菽水纔有餘，赴調無心况干謁。", "少年習氣秋來發，較藝文場肆猖獗。", "揚沙風起晝昏冥，點漆歸來似泥淈。", "我生正欠封侯骨，硯破編殘徒矻矻。", "與君發願繡佛前，綺語機心回樸訥。", "內觀靈府窮丹闕，虛室生明照毛髮。", "却將目力寫新詩，巖電千年不埋沒。"]'),
('3742a16a-8031-4ebf-a289-f4cb7f5550da','還至吳淞茂洪用余臨平詩韻放魚因思舊行大江嘗縱巨魚再和爲答','張鎡','宋','宋诗','song-poetry','','[]','太倉雲路天黏水，櫛比漁家接沙觜。',64,'全唐诗/poet.song.170000.json','["太倉雲路天黏水，櫛比漁家接沙觜。", "巨艘買放截江鱗，舉網遮空暗窗紙。", "錢多魚賤俱放懷，成貫不數成船來。", "今朝縱汝真小惠，好去瞿塘灧澦堆。"]'),
('1fcdfefa-8022-4f1c-8e5b-7f7e82af4d2f','美人曲','張鎡','宋','宋诗','song-poetry','','[]','美人娟娟似秋月，宮中女兒妬欲殺。',64,'全唐诗/poet.song.170000.json','["美人娟娟似秋月，宮中女兒妬欲殺。", "惡言忽入恩愛移，自是君王不情察。", "深宮夜冷調秦箏，曲曲翻成哀怨聲。", "願得風吹落君耳，回心照妾相思情。"]'),
('44a2dbff-d8c1-4123-94ed-8360f1baf8d8','叔祖閣學生朝以丹砂鑄酒盃爲壽','張鎡','宋','宋诗','song-poetry','','[]','真人玉練超塵質，尚假金鹽煮堅石。',160,'全唐诗/poet.song.170000.json','["真人玉練超塵質，尚假金鹽煮堅石。", "要知草伏砂最難，護氣延年本仙術。", "神爐秘炭呼祝融，日月出沒奔朱龍。", "至今受化感靈藥，異寶具體專奇功。", "鑄盃獻公酌沆瀣，雕盤棗實如瓜大。", "飛瓊鼓簧雙成笙，醉色渥丹天所愛。", "東風吹萬纔兩旬，誕序更數三千春。", "丹砂爲金金生沙，坐閲東海揚車塵。", "全才備德難具陳，紫樞黄閣旋洪鈞。", "願從宏芘托此身，舉杯論文日相親。"]'),
('e2e88c4d-9d18-4d89-ae77-78e34cdc2ada','叔祖待制移居新市華閣初成適逢誕日尊幼畢集鎡獨阻奉觴因遐想賦詩爲壽','張鎡','宋','宋诗','song-poetry','','[]','西清老人新樓居，下瞰四澤如江湖。',128,'全唐诗/poet.song.170000.json','["西清老人新樓居，下瞰四澤如江湖。", "憑高挹景未比畫，人望樓上真仙圖。", "楊花燕子句排露，鵾絃鳳竹聲驕粗。", "先生已腰白玉带，我今且漉黄金壺。", "朝來歡聲動里閭，連帥高蓋將軍車。", "松髯峰準照華棟，共說熊夢當年符。", "高情和氣今誰右，海山星斗稱爲壽。", "一門鼎食繼前勳，容我窗間吟遠岫。"]'),
('00974481-3b81-49e5-8141-3444f1495eb4','當塗叔祖生朝以顧亮畫雙松鹿雀爲壽','張鎡','宋','宋诗','song-poetry','','[]','維崧之顛仙所巢，凡卉不敢爭分淆。',208,'全唐诗/poet.song.170000.json','["維崧之顛仙所巢，凡卉不敢爭分淆。", "千年雙幹騰老蛟，露月沐浴風枝敲。", "雪霜貿貿青愈苞，天授非論地肥磽。", "翼而翔飛足而跑，倘輕來此遭譏嘲。", "偉哉兩鹿義漆膠，生鐵挺角銅爲骹。", "於菟可阱熊可庖，爾獨不受人鞭捎。", "如鳳在藪麟在郊，俯仰自得盤林坳。", "神雀亦喜辭黄茅，飛鳴豈復喧啁啁。", "丹葩照映山靈教，欲銜獻仙薦杯殽。", "南園胸中洞六爻，大藩鎮護無鳴髇。", "報穰祝畢停迎貓，行取相印符竹拋。", "長生陰德丹臺抄，我欲歌頌追雲璈。", "往壽此畫猶毫髾，阻修頼有精誠交。"]'),
('1e191570-0734-4805-967f-ccef2cb5b513','南園叔祖生日','張鎡','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','當途老稚遮不住，京口屯雲饑待哺。',128,'全唐诗/poet.song.170000.json','["當途老稚遮不住，京口屯雲饑待哺。", "平生四海廟廊姿，八處蕃宣俱暇豫。", "紹興元勳如日懸，承家有人光後先。", "驥行萬里要老大，天公已與青松年。", "愚孫窮好祗林藪，日汲菊潭清釀酒。", "欲往壽翁道阻修，遥問長江借升斗。", "人間樂事唯逍遥，蓬萊方丈非迢迢。", "詩成喚鶴銜將去，認取南陽卧龍處。"]'),
('608d4adc-4bd4-4808-9322-64c526594bc7','呈尤侍郎陸禮部','張鎡','宋','宋诗','song-poetry','','[]','今春少晴天，雨聲常綿延。',320,'全唐诗/poet.song.170000.json','["今春少晴天，雨聲常綿延。", "曉來羲車展雲出，射我屋瓦生蒼烟。", "憶昔既冠時，壯志平幽燕。", "先王手扶太極起，餘事未竟騎星躔。", "誓將膽與腸，剖析帝座前。", "出師先定董郭薦，此老妙處心默傳。", "甲庚子亥繫宿業，古來局殺英與賢。", "蒼華蕭蕭葯裹側，不覺轉盼霜滿顛。", "因念夢境中，此亦非小緣。", "枉教心無片餉息，形氣自賤欲火然。", "一根返源六根了，如何不遣情勾牽。", "今朝好春風，歌鳥如管弦。", "花香舒錦機，次第鋪我園。", "柳柔曳金繩，高下拂我船。", "伸臂攬六龍，莫過桑榆邊。", "披猖車尾霞，丹碧如旂旜。", "幻作萬石酒，爛醉三千年。", "世間生死俱掃空，况復戲弄冕與軒。", "江西揚子雲，道院方晝眠。", "來書拆半月，欲報懶欲忺。", "許我詩五十，方得見六篇。", "清腴似陶謝，尤覺詞精便。", "尤陸二丈人，和答尚未全。", "賤子焉敢繼，口誦心膂鎸。"]'),
('d95e3240-10e8-4cea-9ed8-81ab2e4be045','陳子西投贈長句走筆次韻奉酬','張鎡','宋','宋诗','song-poetry','','[]','作詩我恨無新功，良田所積未始豐。',144,'全唐诗/poet.song.170000.json','["作詩我恨無新功，良田所積未始豐。", "君侯何事有此癖，判却不費平生窮。", "容臺故人作書至，百篇古體緘幐中。", "剪裁雲霧閒孔翠，此尚人力虧天工。", "請君直道當下語，莫擬世俗紛華蟲。", "古人規繩亦謝去，豈不自已光圓融。", "大千沙界大千海，置之足上升天宮。", "到頭只是舊時我，不妨自就聲律籠。", "若能言下便領得，老夫衣鉢當傳公。"]'),
('e59270bb-9c88-4104-9e74-b9dfb01cf2aa','簡虞子建','張鎡','宋','宋诗','song-poetry','','[]','虞君借屋王城裏，閉門端從窮經史。',288,'全唐诗/poet.song.170000.json','["虞君借屋王城裏，閉門端從窮經史。", "遊謁俱非射利徒，名公往往爲知己。", "年來清貧漸到骨，造命由天常自委。", "屬客雖慳北海樽，出街尚矜東郭履。", "我交英彥固不少，易足如君誠鮮矣。", "連朝雪片大似掌，平地未尺俄復止。", "今晨暘光炙瓦壟，旋滴虛簷聲不已。", "竹間鳥雀快飛鳴，庭下兒童爭跳喜。", "叩關過我未及款，首問雪詩曾有幾。", "自云危樓開破牖，盡見山屏羣玉倚。", "遠從臺館聽笙簫，更煮鮭魚傾濁醴。", "呼兒誦我湖上句，聊當清歌摇醉耳。", "初聞不覺忽自哂，過奬翻令增愧耻。", "屢稱非僞弗許辯，更愛無心真絕比。", "紛紛馳谷跨深坑，苟祿貪榮顙流泚。", "辛勤縱得席暫暖，爭坐成羣又催起。", "豈若高蹈身不與，裹布羹蔬藉溫美。", "乘閒書紙本非詩，切勿多傳召嗤鄙。"]'),
('6f4d3ce0-a72a-4d05-a4fd-db5a0992758e','簡喻叔奇工部沈無隠寺簿','張鎡','宋','宋诗','song-poetry','','[]','園居懶成癖，駕言何所之。',336,'全唐诗/poet.song.170000.json','["園居懶成癖，駕言何所之。", "出門無妨看好雪，粉地玉天相範圍。", "氣增坐車熱，旋換白鹿騎。", "不須携古囊，詩句隨雪飛。", "故人昨遷官，過我睡掩扉。", "登堂謝不敏，款話俄移時。", "咨詢玉照三百樹，縱未放花堪舉巵。", "當約香山翁，共了此段奇。", "喜歸步林曲，問梅梅有辭。", "相看兩經年，非無主人知。", "去春偶晴多，昏曉無不宜。", "靜來藜杖橫，笑去綸巾欹。", "琉璃巨鍾深數指，月底四弦驚鵲起。", "興濃何必斷吟鬚，快寫新詞歌皓齒。", "燭遥照路不照花，三更露壓星斗斜。", "明床氈穩半酣寢，頭上最愛香雲遮。", "明朝再來看，亦復送落霞。", "尤物到了奇，飄英覆泥沙。", "非徒隨步白錦茵，轉首綠蔭森交加。", "于今雪見五六白，斂衽何辭讓渠色。", "但催佳客犯寒來，我自有花開頃刻。", "言餘試摇枝上凍，已覺欣欣芳萼動。", "或如紅豆或如椒，若說供詩儘禁用。", "星郎農簿辭林鳳，素有聲名過屈宋。"]'),
('6893129f-fbc1-4ea7-ac8d-6cc693fd7639','次韻曾侍郎','張鎡','宋','宋诗','song-poetry','','[]','世上曾誰歌白雪，慨歎風人聲屢咽。',160,'全唐诗/poet.song.170000.json','["世上曾誰歌白雪，慨歎風人聲屢咽。", "旋蟲時叩豈無聞，盡發宮商方應節。", "江西源正非旁流，文清詩名不易收。", "師承吏業特餘事，一門玉律誇中州。", "了知著脚最高處，不局晚唐脂粉路。", "涪翁時異屹相望，龍勺彝樽滿堂聚。", "昔人詞賦上三都，未必獻納裨皇居。", "且今司刑掌邦賦，羔羊化行無詐狙。", "孤生奚貪芻豢說，一飯跏趺諸想滅。", "案頭何用寶傳燈，自有公家論語說。"]'),
('72afd3d1-d41a-4d72-a322-cedbb062b27d','蚊','張鎡','宋','宋诗','song-poetry','','[]','連夜雨作污渠泥，枯莖蠹葉紛滿蹊。',288,'全唐诗/poet.song.170000.json','["連夜雨作污渠泥，枯莖蠹葉紛滿蹊。", "塘坳蠕蠕長科斗，罋腹攘攘翔醯鷄。", "濕生別種蛆蛭類，倒擲橫跳浮却墜。", "晴風一旦略噓吹，便解飛騰添足翅。", "初即陽光緩緩遊，鼓隊趨羣屋角頭。", "雪片有聲飄作陣，楊花無樹輥成毬。", "爾自與人風馬牛，緣何耳邊鳴啾啾。", "鳴啾啾，未爾罪，撲鬢噆膚驅不退。", "有時深夜呵殿來，惱亂書燈猶作祟。", "何人當年假爾名，曰蚊豈爲文足稱。", "斕斑不過脚似豹，勇健未必拳如鷹。", "蚊吾語汝汝切聽，爾詎不聞大鵬舉翼辭南溟，上九萬里如雲興。", "爾又不聞鳳凰來儀虞帝庭，九章備體參四靈。", "奚曾逐逐專囂塵，固知比擬非其倫。", "我園牆陰容爾停，自全且效腐草螢。", "吸露大勝血肉腥，口業既免報漸輕。", "不然薰燎滅爾形，吾言匪妄如日星。"]'),
('ed76cdf3-7a04-4f89-a848-e47635673b41','船回過德清','張鎡','宋','宋诗','song-poetry','','[]','溪平如簟不織紋，夕陽紅葉參差分。',72,'全唐诗/poet.song.170000.json','["溪平如簟不織紋，夕陽紅葉參差分。", "蘆邊孤篷飯炊芹，風力引上縈長雲。", "天將此意慰所欣，我倦不飯興自醺。", "思懶豈復筆下勤，一默中有詩無垠，林木振動山應聞。"]'),
('ca4b4dd7-0971-4ada-876f-484917bad04f','夜宿龍井廣福寺分韻得來字','張鎡','宋','宋诗','song-poetry','','[]','陽烏翅焦雲崔嵬，避熱馬轉南山隈。',192,'全唐诗/poet.song.171000.json','["陽烏翅焦雲崔嵬，避熱馬轉南山隈。", "邊湖興熟厭頻往，幽討林落穿莓苔。", "澗聲引步陟層嶺，亭矗路側雙扉開。", "泓泉湛碧透坤軸，合有龍卧專風雷。", "撫欄立瞰眩奇閟，潄挹未敢持深盃。", "瘦筇趨寺更幽寂，苴補不到簷楹摧。", "老僧肅揖選凉坐，借床過夜容裴回。", "神靈變異亦喜客，跂脈現狀潛鱗鰓。", "從容瞻敬忽無靚，應憫墮世餘氛埃。", "堂中遺像成三老，英爽長在遊天垓。", "認題掃壁說前輩，今昔玩視俱悠哉。", "出門因愛月正午，桂子秋到須重來。"]'),
('e1bd8008-fa4e-4f91-82d1-b1cedad53a64','七月望煙波觀對月','張鎡','宋','宋诗','song-poetry','','[]','我生好奇難比論，流水古木期終身。',208,'全唐诗/poet.song.171000.json','["我生好奇難比論，流水古木期終身。", "卜居城隅易得趣，窗戶日與青山親。", "出門陂湖舊湮涸，連歲乃爾成奫淪。", "結亭據要雖屢賞，物景尚厭非清真。", "商飈入序才兩夕，猛雨盡洗炎歊塵。", "今晨已復暑不奈，揮汗幾欲捐衣巾。", "晚風引履到雲鏡，蕭爽意象生無垠。", "須臾從地出偉觀，光潔萬丈推冰輪。", "波明上下互發越，彌望但怪鎔黄銀。", "烟蘆窣颯雜蟲響，漁艇隠約收絲緡。", "人生何用計俗眼，强起口笑勝眉顰。", "急傾巨醆叫李白，今古不問交精神。", "相隨擬造廣寒闕，共醉更住三千春。"]'),
('f1d62499-931f-4540-adf3-e818f6e24577','題寒綠軒','張鎡','宋','宋诗','song-poetry','','[]','甫里先生窮到老，剩有詩文記林草。',192,'全唐诗/poet.song.171000.json','["甫里先生窮到老，剩有詩文記林草。", "杞苗菊葉果何佳，自喜春風顔色好。", "現菴主人同吾張，故家文獻出大梁。", "相過肯對桂隠榻，握手書社傾肝腸。", "頃年客處東瀕海，灌畦不仰園官菜。", "小窗寒綠獨專名，實與天隨同所愛。", "所愛既同人亦同，豈較早晏時遭逢。", "極知趣尚寓小物，過眼斥鷃高飛鴻。", "閒關館舍人稀到，簷前席地聊從好。", "維杞與菊復移栽，擷可烹茶羹可芼。", "曉煙夕露清無邊，盡掃萬古紅紫緣。", "對之飲水骨亦仙，屠沽兒家休擊鮮。"]'),
('db28cc5e-9259-4b98-9f04-b3990e34a64c','登城歌','張鎡','宋','宋诗','song-poetry','','[]','二月二十八，花開滿林鶑恰恰。',254,'全唐诗/poet.song.171000.json','["二月二十八，花開滿林鶑恰恰。", "春光誰遣插翅飛，雪色情知添鬢髮。", "暄風隨我登古城，遠樹如簇山如縈。", "一川渺瀰青鏡平，雲翳不定天疑行。", "去船住船縱復橫，日輝迸射光晶晶。", "逆聽萬古蒼蠅聲，眼穿故國喚不應。", "鼎湖龍升朝帝廷，還領舊物蘇函靈。", "維先忠烈爲列星，侍堯受命行專征。", "今上移軍復四京，實遵天時協羣情。", "不戰自可屈人兵，版圖悉更郡縣名。", "蛇荒鳥夷頒朔正，禮樂制度重修明。", "漏泉沛澤江海傾，小臣筆力鴻毛輕。", "願書詔命奔驛程，滌洗罪眚哀孤惸。", "霜露所墜皆驩盈，此意一笑從誰評。", "舊遊安期丹想成，未須遣鶴來相迎。", "我方居園學長生，後五百歲歸蓬瀛。"]'),
('30247c99-8bec-4832-b5e1-05463ac99002','韓子師尚書致仕','張鎡','宋','宋诗','song-poetry','','[]','丈夫出處無兩岐，彊自分別兒童癡。',296,'全唐诗/poet.song.171000.json','["丈夫出處無兩岐，彊自分別兒童癡。", "鹿門龐老不願仕，名與諸葛爭驅馳。", "天子從臣豈易得，履聲已到黄金墀。", "堂堂文譽動宸極，奕世長策歸論思。", "攀轅卧轍昔人事，前日作州重見之。", "萬口祝公猶在耳，拜後爵土同封蘄。", "緒餘間發有如此，功業盛著庸何疑。", "仙風却與松喬期，泛苕涉霅尋幽奇。", "洞天白石人未省，翦茅植樹親指麾。", "山靈地嫗許時秘，恰與八座供娛嬉。", "人間臺榭難頓著，臨勝向背真天施。", "霞晨霧夕更護耀，鷗朋鷺導欣逶迤。", "鄉來韓必今復來，飛雲入步長相隨。", "上章乞身世亦有，髮落齒撼將何爲。", "公未五十方朱顔，勇退奚俟謀耆龜。", "九重嘉賞寵殊職，百辟動色欽清規。", "鎡也塵鞅方羈縻，先德未報鬢已絲。", "高節凜凜端可師，扣門糧休千里齎，一舸叫月從鴟夷。"]'),
('9f09848a-26fa-4879-b6e1-6d35151ac8c7','張戶部惠山楊梅','張鎡','宋','宋诗','song-poetry','','[]','嘗聞魏伯陽，鑄丹會稽山。',216,'全唐诗/poet.song.171000.json','["嘗聞魏伯陽，鑄丹會稽山。", "功成試其徒，未欲汎與餐。", "紿言丹入口，命盡不可還。", "一人篤信道，快餌肯作難。", "翁復起諸死，携手升雲鸞。", "臨行作奇戲，留使後世看。", "聊將一粒變萬顆，擲向青林化珍果。", "彷彿芙蓉箭鏃形，澀如鶴頂紅如火。", "只隨翁字姑號陽，姓楊乃是訛偏旁。", "迄今年深少人識，地嫗山君應記得。", "木生曲直味宜酸，此獨甘香勝蜜團。", "吾宗望郎忽馳送，色映筠籃光欲動。", "想因見此列宿躔，曾遣冰壺纖指弄。", "我方水際呼清風，葛巾高掛千丈松。", "爲公摘荷盛薦酒，此樂城中那更有。"]'),
('1d7bc55b-0a4b-4546-93f8-11b2b0e25c54','石首春魚梅魚三物形狀如一而大小不同爾因賦長篇','張鎡','宋','宋诗','song-poetry','','[]','遐陬編戶居海濱，不但生涯仰蝦蟹。',224,'全唐诗/poet.song.171000.json','["遐陬編戶居海濱，不但生涯仰蝦蟹。", "煮鹽成雪雪成堆，清曝羣魚趨市賣。", "其間石首最得名，隨潮百萬鼙鼓聲。", "長艫巨艑鬭截取，急逐風便來王城。", "頭中有物從何得，精衛含冤口拋石。", "此魚腹小不容舟，只把石吞那患迮。", "錯將轉上泥丸宮，又疑當年潄石翁。", "臨流快嚥透入腦，化作鱗鬣金巃嵷。", "子孫詵詵仍亹亹，曰春曰梅俱可喜。", "醉鄉貪衒風味高，失身盤膾杯羹裏。", "先生趁晴携酒觴，柳色正似鵝兒黄。", "與渠豈暇考族譜，便結保社南湖傍。", "軟炊玉飯乘燕艇，撐對柴門亂花徑。", "併呼三子伴漁童，食肉諸公自時政。"]'),
('0ea78532-262e-43ee-9f44-396f44a98857','宿吳江華嚴院','張鎡','宋','宋诗','song-poetry','','[]','宿雲蔽空溪溟濛，我船曉繫紅蓼叢。',224,'全唐诗/poet.song.171000.json','["宿雲蔽空溪溟濛，我船曉繫紅蓼叢。", "宿雨滑道樹瀝漉，我車早轉青泥衝。", "破程約涉一舍外，遠目未快千山供。", "岸傍小店換馬去，氈裘障冷披蒙茸。", "須臾巾蓋不容展，莽莽暗霧逢逢風。", "偕行客輿屢掀簸，適值官騎來憧憧。", "刀弓負带競硉矹，驙駟𩧄驖騅騟驄。", "爭前迭進步殊窘，迫暮始望橋垂虹。", "石塘百丈捍駭浪，間有灘磧紛魚筒。", "鴉羣黑白混鷗起，帆影亂點遥波中。", "筆床茶竈住此地，得句未必慙龜蒙。", "浮圖屋老且投宿，解擔正聽黄昏鐘。", "紗籠炙燈照佛古，展席布榻便吾慵。", "酒邊紙盡莫翻寫，睡覺紅日生於東。"]'),
('5c6b6b59-cc6b-40df-90fe-2c538c5285c0','山堂紀實','張鎡','宋','宋诗','song-poetry','','[]','莓苔牆下斑斕長，烟霏谷口依稀上。',160,'全唐诗/poet.song.171000.json','["莓苔牆下斑斕長，烟霏谷口依稀上。", "晨輝逕奔鳥聲來，夕影屢逢蟾魄晁。", "杖拖瘦路鳴敲鏗，天台廬阜著脚行。", "中林穩置盤陀石，並坐不與孤雲爭。", "疎紅疊翠如先有，霜藤蔓緣驚蛇走。", "枝枝葉葉巧相攙，歲寒俱是論心友。", "菴前臺上晴最嘉，數杯薄酒聊隨茶。", "客來勸主主勸客，醉倒冠履從欹斜。", "且道如今誇甚處，見成不是虛排句。", "堂前新展假山詩，約齋老子堂中住。"]'),
('a6b7a615-f183-4a46-a96e-8afa17bae2a0','種菊','張鎡','宋','宋诗','song-poetry','','[]','今年植菊良寡謀，叢萎滿望如田疇。',160,'全唐诗/poet.song.171000.json','["今年植菊良寡謀，叢萎滿望如田疇。", "黄深白淺欠旌別，未表勁浄專高秋。", "初移風雨連朝惡，纔到暄晴驟開却。", "鋪氈未暇坐觀嬉，携筇粗放行吟樂。", "遊蜂冶蝶撥不開，粉趐雲動鳴輕雷。", "霜前姿性本介潔，肯受浼辱寧摧頹。", "道人猶揀鮮鮮蕊，銅缾換浸重添水。", "一聲清磬曉窗深，香邊坐斷三千偈。", "歌緣酒分從束輕，正色已定十種名。", "來年自種先獻佛，不應直爲杯中物。"]'),
('89921977-6ed0-4d76-991a-7727a35cac71','楊秘監爲余言初不識譚德稱國正因陸務觀書方知爲西蜀名士繼得秘監與國正唱和詩因次韻呈教','張鎡','宋','宋诗','song-poetry','','[]','人心懷感初因喜，感到極時還墮淚。',150,'全唐诗/poet.song.171000.json','["人心懷感初因喜，感到極時還墮淚。", "亦猶雕琢用功深，自發詩中平淡意。", "更須絕處悟一回，方知迷夢喚醒采。", "今誰得此微妙法，誠齋四集新板開。", "我嘗讀之未盈卷，萬彙紛綸空裏轉。", "君不見嚴陵使君斂眉頭，清虛山水吟兩秋。", "又不見國學先生離文句，變現佛魔麾總去。", "相逢三翁同肺腸，江西吳蜀如一鄉。", "只憐我似臭革囊，任翁薰染終難香。"]'),
('78b58334-f4f0-4696-a32a-d51941a49078','張郎中尤少卿相繼過訪未果往謝先成古詩寄呈','張鎡','宋','宋诗','song-poetry','','[]','高標無過張戶部，督賦文移多似雨。',192,'全唐诗/poet.song.171000.json','["高標無過張戶部，督賦文移多似雨。", "侵晨徑造夢蝶床，冷坐譚詩捐俗語。", "博聞無過尤少卿，議禮辨析紛如爭。", "破午遠到煨芋室，抵掌談事非今情。", "夢蝶床前何所有，一盞朮湯聊代酒。", "煨芋室中殊可憐，半椀草茶不直錢。", "登車出門尚回盼，隣媼巷童驚走看。", "雪寒水際正蕭條，安得騶呼連改觀。", "世上塵勞忙若鑽，想欲跳身脫羈絆。", "只堪告訴向梅花，我是梅花千樹伴。", "春風不覺園中換，刺字交馳煩則亂。", "狂歌愈見野人真，巨筆掀空合有神。"]'),
('5d813a0c-078b-4083-80e8-ba2c4c05410d','秋風','張鎡','宋','宋诗','song-poetry','','[]','秋風本自佳，豈直令人悲。',110,'全唐诗/poet.song.171000.json','["秋風本自佳，豈直令人悲。", "連宵天上送好月，我病偶失登樓時。", "長安城中少人詠，風月似厭空相隨。", "凌晨吹雲滿虛際，却向山頭移雨至。", "老夫識破不生愁，黄葉階前從委地。", "人生三萬六千日，何苦區區論得失。", "定將印綬棄擲歸南湖，秋風與我還相娛。"]'),
('c6e0b7b8-0497-45a4-827f-a0121c9c4818','同魏茂先潘茂洪泛湖終日','張鎡','宋','宋诗','song-poetry','','[]','天將奇觀留東南，波織翡翠山堆藍。',192,'全唐诗/poet.song.171000.json','["天將奇觀留東南，波織翡翠山堆藍。", "仙廬佛剎互入望，漁篷游舫遥相銜。", "清愁閉戶孤晴色，試逐薰風領佳客。", "平生行處後杯盤，枯淡自甘先筆墨。", "放船何處芙蓉開，綠幢翠葆從天來。", "凌波生塵想遺珮，撫檻徙倚心悠哉。", "秦關將種身九尺，鬚繞茶烟閒虎戟。", "潘君高隠百不知，酒酣慷慨乾坤窄。", "空濛暮氣收斜陽，柳色轉岸參差香。", "南漪杜鵑易檜海，公子愛客邀舉觴。", "畢逋棲烏噭城上，登車攬轡歸相望。", "乘閒結伴須數來，與往不煩拘定向。"]'),
('f60ffab9-80d2-4178-b81f-cee0de5087e2','次茂洪韻','張鎡','宋','宋诗','song-poetry','','[]','披嵐長嘯和巖洞，衣汗未冷毛髮知。',96,'全唐诗/poet.song.171000.json','["披嵐長嘯和巖洞，衣汗未冷毛髮知。", "貪奇甘戀足欲駐，擁鼻將返心還疑。", "清音來賢祇過目，亭下樹邊俱欠詩。", "歸輿漸受雨沾灑，客蓋轉適風傾欹。", "出門倚澗得雄觀，放泉出匱供遊嬉。", "勉賡新句未爲報，他年共隠非公誰。"]'),
('022c0c4b-f643-4c7f-964d-20ac7c11408a','戲贈楊伯時','張鎡','宋','宋诗','song-poetry','','[]','楊侯相逢復見寒梅開，鬢色不带濃霜來。',128,'全唐诗/poet.song.171000.json','["楊侯相逢復見寒梅開，鬢色不带濃霜來。", "君居山縣適近我先壟，夜半應望靈氣勃鬰纏崔嵬。", "去年竹寺傾樽罍，官來急救老眼饑。", "西樞相公喜人物，搜材剔抉英雄窟。", "蒼松腴硬久陰崖，此亦鶡冠寧肯忽。", "近聞一飯蒙異恩，快劄好闕休馳奔，我詩安得達相門。", "春風後日自東起，太歲無緣只桃李。"]'),
('7b3e34e1-b3b0-4bf2-bc93-7b1062c58f9f','以道學諭鳳口有感詩寫物記事備極詞情不容繼和矣既辱珍示可無奉酬輒抒鄙懷次韻且名以溪婦吟末章反正不忘風人之義也','張鎡','宋','宋诗','song-poetry','','[]','人間盛衰理甚明，勢去有如湯沃冰。',208,'全唐诗/poet.song.171000.json','["人間盛衰理甚明，勢去有如湯沃冰。", "聽言一事足歎惋，恐君亦復傷中情。", "行都赫奕名王第，列屋珠璣多秀慧。", "主翁五十二本兵，寵冠諸家當盛世。", "其間屬意字以端，姿品高妍兼妙藝。", "燕開雲幄萃親友，艷陣香藂嘗竊睨。", "轉眼陳迹俱已休，西風葉飛東水流。", "相逢應怪我鬢改，貪情省認俄驚羞。", "波明藏淚尚剪月，山淺带恨猶橫秋。", "失身何心養兒女，啁啾耳厭山蠻語。", "困居村店少人沽，飣餖腥鹹污盤俎。", "無言脈脈話最深，爲君寫作溪婦吟。", "人生榮悴由分定，有夫不必萌他心。"]'),
('9d67b8df-1c1d-4439-a310-65fddc092e33','贈道士張易','張鎡','宋','宋诗','song-poetry','','[]','道人生長清淮西，地荒戰血孤鬼啼。',176,'全唐诗/poet.song.171000.json','["道人生長清淮西，地荒戰血孤鬼啼。", "飽知濁世一朝菌，擺落羈馽全天倪。", "穿霞踏月半區宇，山水名勝隨攀躋。", "我來欣逢大條左，握手便許論刀圭。", "蕊珠七言素探討，敷析秘奧開羣迷。", "綿綿玄牝斡兩曜，夜半虛室騰虹霓。", "同居蜀客話清簡，物理返笑莊生齊。", "坳堂燭暗坐頃刻，石頭路浄緣高低。", "傾壺隨意薦巖果，不假沆瀣求交梨。", "他年相就養靈液，肯復自棄淪塵泥。", "蓬洲閬苑恣遊宴，有句更繼肩吾題。"]'),
('bacfb9df-1220-4055-85ee-61bd66e3a149','一日','張鎡','宋','宋诗','song-poetry','','[]','一日不炷香，已若神不清。',80,'全唐诗/poet.song.171000.json','["一日不炷香，已若神不清。", "一日不覓句，更覺身不輕。", "是身天地間，假物舒其情。", "君看屐與鍛，自可了一生。", "世上紛紛蠻與觸，兩眼看渠憐不足。", "爐煙未斷詩已成，更肯愁吟頭白曲。"]'),
('c311e8b6-bac2-4977-b41e-a7e0407bfb77','次叔祖閣學暑中過清寒堂韻','張鎡','宋','宋诗','song-poetry','','[]','人材掄選何時停，高者棟負卑薪蒸。',192,'全唐诗/poet.song.171000.json','["人材掄選何時停，高者棟負卑薪蒸。", "我家忠烈定社稷，任大豈但懲與膺。", "不毛夏渡瀘濰水，裂面夜踏滹沱冰。", "强敵坐致九頓首，和議姑隨三折肱。", "至今耆舊話曩昔，白髮相對搔鬅鬙。", "堂堂傳業翁克紹，中宸委寄恩重仍。", "禁林延閣望隆積，邊瑣輔鎮才優勝。", "知閒未數持燭照，神專端與承蜩凝。", "會堂風雲趣健步，人則父子功儕朋。", "從容中的仰文翰，仁者如射弓須弸。", "爲山簷外六月冷，興到不忍無詩登。", "袖歸鎡得正法眼，此事肯許參禪僧。"]'),
('be93ed2a-8a60-4740-82da-427fd1e1e816','宿吳江縣','張鎡','宋','宋诗','song-poetry','','[]','既望月輪遲未上，更深闊港喧輕浪。',160,'全唐诗/poet.song.171000.json','["既望月輪遲未上，更深闊港喧輕浪。", "舟人慣夜自牽撐，却嫌炬火光摇晃。", "長橋千柱過頃刻，良久陰輝弄雲黑。", "漁家裹鮓縛蟹來，波繫松鱸取艱得。", "堤平步散情初適，此去垂虹纔咫尺。", "登輿風力透衣綿，俯檻波聲卷沙磧。", "商船魚貫昏煙隔，天水難分但空碧。", "三賢遠矣英爽存，來往頻年定相識。", "興亡慨嘆終何益，愚智俱爲百年客。", "劃然長嘯起蛟龍，共向吟牋飛霹靂。"]'),
('c781a467-7493-4cfe-b54d-bc4c5e33182f','玉霄花','張鎡','宋','宋诗','song-poetry','','[]','虛皇清晏仙班朝，寶花隨現非根苗。',96,'全唐诗/poet.song.171000.json','["虛皇清晏仙班朝，寶花隨現非根苗。", "璆林瑶樹振靈響，飛彩燦蒨輝蒼霄。", "下憐人宇厭凡卉，特許福地生芳條。", "細看纖潔謝丹粉，仿像翠鬢森珠翹。", "移來泉石助蕭爽，暗麝不必絺衣飄。", "玉簪失素萱讓葉，倚牆豈獨麾芭蕉。"]'),
('758c4fcf-17f8-43e3-9547-cca47bb2453b','撤移舊居小假山過桂隠','張鎡','宋','宋诗','song-poetry','','[]','頃年疊石規制陿，大類堆沙戲成塔。',160,'全唐诗/poet.song.171000.json','["頃年疊石規制陿，大類堆沙戲成塔。", "一株蟠桂兩穉松，便愛清陰蔓藤匝。", "階前指作嵩華樣，引賓紀詠紛酬答。", "遷巢城北倏兩期，慣有真山坐延納。", "人生最怕眼見廣，到處卑凡意難合。", "每還舊舍覺荒陋，草樹雖添漫稠雜。", "林塘移植勢定增，未成已想風煙颯。", "朝晴夕晦各異狀，倚杖閒看更鋪榻。", "園中勝賞亦甚富，此獨宜茶兼酒榼。", "載來非敢傚奇章，甲乙題朱旋塗蠟。"]'),
('180dc2da-f2aa-424b-b3de-5c60191139cb','崔慤畫雙鵝引雛','張鎡','宋','宋诗','song-poetry','','[]','橫塘暮煙吹雨來，白鵝叫風雙毰毸。',64,'全唐诗/poet.song.171000.json','["橫塘暮煙吹雨來，白鵝叫風雙毰毸。", "鵝兒力小立未定，偎母戀哺忘驚猜。", "炎歊生欲逃天垓，虛堂有此新圖開。", "蘆梢荷葉亦動蕩，茹句未吐愁難裁。"]'),
('7796c18e-8d5a-46db-9ba5-a8a377abb76d','震澤戲書鵝鶴','張鎡','宋','宋诗','song-poetry','','[]','市梢茅廠三兩間，旁有數鵝行復還。',96,'全唐诗/poet.song.171000.json','["市梢茅廠三兩間，旁有數鵝行復還。", "適從何來令威老，矯首便覺高情閒。", "群鵝不度風姿少，罷亞相隨過汀草。", "令威流盼略無言，寄與誰知自瀛島。", "少焉戛然鳴一聲，豈暇更顧兒童驚。", "直上青天三萬丈，鵝在人間誇字樣。"]'),
('835d5ca8-9dc2-4911-ba90-6894ad105491','程堯仲以楊秘監所贈詩見示因走筆次韻約觀園中桂花','張鎡','宋','宋诗','song-poetry','','[]','我家城中煙雲鄉，秋風晴日千桂香。',128,'全唐诗/poet.song.171000.json','["我家城中煙雲鄉，秋風晴日千桂香。", "交遊半是漁樵郎，門前水深通潮江。", "和詩到此推硯牘，必不能教鬼神哭。", "何如且向桂花中，快瀉鵝黄入杯玉。", "去年試君當夏初，知君直氣非狂夫。", "平生批龍編虎鬚，千言萬言長短書。", "誠齋許人以文字，須待其人有餘味。", "君今莫問且速來，不醉明朝花滿地。"]'),
('8dc12729-eb9a-485d-a0a4-443511a0243a','真珠園和浄慈僧韻','張鎡','宋','宋诗','song-poetry','','[]','冒寒畦菜青黄色，意到春風纔一息。',64,'全唐诗/poet.song.171000.json','["冒寒畦菜青黄色，意到春風纔一息。", "踏雪山僧折簡來，不學渡江携履隻。", "我方開樽酒如泉，浩然得味無中邊。", "何須隨喜楞伽講，始似閒行白樂天。"]'),
('375306a4-95b3-4e3d-9644-933fb4baeb15','浮菴潔疾戲呈','張鎡','宋','宋诗','song-poetry','','[]','黄埃簸空吹赫日，白鳥不度瘖蟬聲。',64,'全唐诗/poet.song.171000.json','["黄埃簸空吹赫日，白鳥不度瘖蟬聲。", "先生出門數有礙，陋巷糞壤愁逢迎。", "家山望斷圍修竹，常說携書伴鳴犢。", "心無揀擇自清凉，臭腐神奇總超俗。"]'),
('cdc7eea5-acd0-4ac7-8a4a-a74468730563','蔬飯','張鎡','宋','宋诗','song-poetry','','[]','夜虹照飯光如玉，春甌飣菜肥於肉。',64,'全唐诗/poet.song.171000.json','["夜虹照飯光如玉，春甌飣菜肥於肉。", "周郎赤米太寒酸，潘令紫薑徒記錄。", "饑創塞罷忘貪欲，氣定徐行手摩腹。", "更能運任著衣裳，聽爾計高三十六。"]'),
('46f93f20-af28-4bf5-b6cb-2a3ecd87d431','病起見缾中蠟梅偶書','張鎡','宋','宋诗','song-poetry','','[]','南湖地勝無凡木，只說寒梅誇不足。',160,'全唐诗/poet.song.171000.json','["南湖地勝無凡木，只說寒梅誇不足。", "四般風韻兩般高，黄如蜂蠟白如玉。", "餘品緗紅亦總嘉，早開最喜黄白花。", "去年樹下看不厭，吟興被壓空長嗟。", "今冬一病恰半月，未暇尋梅踏殘雪。", "數枝蠟蕊忽先來，吹香大慰經年別。", "道人不作羣兒癡，三嗅喚醒勝良醫。", "黄絹幼婦語難辨，一默自有無窮詩。", "此機亦似維摩老，何曾真難文殊倒。", "從茲不病是談禪，命花却爲金色仙。"]'),
('d4bcadf7-ac11-436a-a190-81f115c02b51','春前一日賦呈誠齋覓荆溪詩編且邀看玉照堂花','張鎡','宋','宋诗','song-poetry','','[]','頗訝蓬萊主，相忘不寄詩。',48,'全唐诗/poet.song.171000.json','["頗訝蓬萊主，相忘不寄詩。", "荆溪雖有集，桂隠未容窺。", "地勝人難老，春回律自移。", "梅花如有語，莫似去年時。"]'),
('00c69322-3304-4b61-af93-a86f7ebce36a','次韻答潘茂洪桂花見懷','張鎡','宋','宋诗','song-poetry','','[]','藉使音書少，何妨好尚通。',48,'全唐诗/poet.song.171000.json','["藉使音書少，何妨好尚通。", "看花雖各自，覓句却相同。", "嚼蕊晨煙裏，搴枝夜月中。", "亦曾湖上坐，香底水精宮。"]'),
('8fa2c505-bb28-4682-89ac-e02d786f2d69','次韻酬喻工部雪中見懷','張鎡','宋','宋诗','song-poetry','','[]','坐厭增冰地，遥思勝熱城。',48,'全唐诗/poet.song.171000.json','["坐厭增冰地，遥思勝熱城。", "忘名全道用，遠俗養詩情。", "枕病憐幽獨，心交阻合并。", "晴春開徑在，自斷學淵明。"]'),
('a50aa13b-e44d-4e90-a5d3-496560121963','雪霽','張鎡','宋','宋诗','song-poetry','','[]','山負紅銅日，雲披綠玉天。',48,'全唐诗/poet.song.171000.json','["山負紅銅日，雲披綠玉天。", "一晴聊餞臘，三白已迎年。", "貴氣樓臺滿，春聲松竹先。", "詩成緣底事，鳥跡印篷船。"]'),
('72a48a2d-6d6b-4c00-b1a7-e0c82a576134','詩本','張鎡','宋','宋诗','song-poetry','','[]','詩本無心作，君看蝕本蟲。',48,'全唐诗/poet.song.171000.json','["詩本無心作，君看蝕本蟲。", "旁人無鼻孔，我輩豈神通。", "風雅難齊駕，心胸未發蒙。", "吾雖知此理，恐墮見聞中。"]'),
('4d12e457-3698-4294-89af-c8c7133675de','讀樂天詩','張鎡','宋','宋诗','song-poetry','','[]','讀到香山老，方無斧鑿痕。',48,'全唐诗/poet.song.171000.json','["讀到香山老，方無斧鑿痕。", "目前能轉物，筆下盡逢源。", "學博才兼裕，心平氣自溫。", "隨人稱白俗，真是小兒言。"]'),
('0bf62767-1f5c-46f8-8ae6-c6a6ad3e335a','覓放翁劍南詩集','張鎡','宋','宋诗','song-poetry','','[]','見說詩并賦，嚴陵已盡刊。',48,'全唐诗/poet.song.171000.json','["見說詩并賦，嚴陵已盡刊。", "未能親去覓，猶喜借來看。", "紙上春雲湧，燈前夜雨闌。", "莫先朝路送，政好遺閒官。"]'),
('0bd07115-2769-47d6-950c-e19b4e377e05','楊伯子見訪惠示兩詩因次韻併呈誠齋  其一','張鎡','宋','宋诗','song-poetry','','[]','自作詩中祖，翁難子更難。',48,'全唐诗/poet.song.171000.json','["自作詩中祖，翁難子更難。", "波瀾千偈闊，光焰九霄寒。", "覓著由來遠，成時自好看。", "頭頭見成字，誰道要吟安。"]'),
('6f81a760-fc4c-4b7e-ab38-db7ed46e20c1','楊伯子見訪惠示兩詩因次韻併呈誠齋  其二','張鎡','宋','宋诗','song-poetry','','[]','別去常關夢，書來意已强。',48,'全唐诗/poet.song.171000.json','["別去常關夢，書來意已强。", "那看多竹地，相對兩繩床。", "壯志霜空鶻，禪心古廟香。", "糠爐熟黄獨，待子數分嘗。"]'),
('4f0700dd-7375-40a0-8cd1-ff961809ae08','次韻羅端規二首  其一','張鎡','宋','宋诗','song-poetry','','[]','世態從渠變，前山只麽新。',48,'全唐诗/poet.song.171000.json','["世態從渠變，前山只麽新。", "關門便嬾退，遇事少躬親。", "和我詩何益，知公道不貧。", "兩旬纔識面，枉是自由身。"]'),
('468f7356-aac6-4d07-a5cf-42a766979cb1','次韻羅端規二首  其二','張鎡','宋','宋诗','song-poetry','','[]','雪窗吾畏友，稱譽滿中邊。',48,'全唐诗/poet.song.171000.json','["雪窗吾畏友，稱譽滿中邊。", "往矣非喬木，生乎仗老天。", "肯來丹桂裏，須醉白鷗前。", "百計安流好，紛紛急水船。"]'),
('c8b61f81-b83f-4ff0-bc3a-36073590f55e','次武子韻','張鎡','宋','宋诗','song-poetry','','[]','宇內張夫子，詩如孟浩然。',48,'全唐诗/poet.song.171000.json','["宇內張夫子，詩如孟浩然。", "安心從太末，借屋近平泉。", "眼裏彈冠手，生來種芋田。", "相投忽離席，佳月戀𦨻船。"]'),
('43bb6260-d263-4d43-a0a5-a166a69dfc08','暑中楊伯虎見訪翌日有詩來因走筆次韻','張鎡','宋','宋诗','song-poetry','','[]','領取無多話，頻年頓不疎。',48,'全唐诗/poet.song.171000.json','["領取無多話，頻年頓不疎。", "幽尋塵土外，高韻笑談餘。", "既悟蕉中鹿，寧求木上魚。", "論詩能避暑，此意復誰如。"]'),
('74605a3e-1867-4b7c-a148-c446c064c206','早飯菴中次張以道韻','張鎡','宋','宋诗','song-poetry','','[]','豈是幽人眼，從來可慣山。',48,'全唐诗/poet.song.171000.json','["豈是幽人眼，從來可慣山。", "有時纔得見，覓句不曾閒。", "野日光尤暖，溪梅信尚慳。", "飯餘行便去，休待暮雲還。"]'),
('19425aaa-8940-4b82-9ed9-6c41857a0bfb','次韻楊廷秀左司見贈','張鎡','宋','宋诗','song-poetry','','[]','願得誠齋句，銘心祗舊嘗。',48,'全唐诗/poet.song.171000.json','["願得誠齋句，銘心祗舊嘗。", "一朝三昧手，五字百般香。", "絃絕今何苦，衣傳擬自强。", "草玄非近效，舉世漫匆忙。"]'),
('6442b68f-e573-4a39-8777-1ee69843f7e6','即席次吳季行韻','張鎡','宋','宋诗','song-poetry','','[]','昔逢欣把袂，三歎說吳鈎。',48,'全唐诗/poet.song.171000.json','["昔逢欣把袂，三歎說吳鈎。", "共醉虛堂晚，還興故國愁。", "花黄思靖節，鬢綠傲浮丘。", "世濟王門業，洪流萬斛舟。"]'),
('d50ba10b-8ff2-4d59-b550-9c241aeca9d8','連日雪未能多曾無逸見惠二首遵歐蘇律禁體物語及用故事走筆次韻  其一','張鎡','宋','宋诗','song-poetry','','[]','鵲凍聽無語，鷗饑望不飛。',48,'全唐诗/poet.song.171000.json','["鵲凍聽無語，鷗饑望不飛。", "從饒居士愛，亦自到園稀。", "入幕燈生暈，飄池水長肥。", "何能巧模寫，吟思欠幽微。"]'),
('66944c68-6d34-4d54-8314-ce6d5825c8e4','連日雪未能多曾無逸見惠二首遵歐蘇律禁體物語及用故事走筆次韻  其二','張鎡','宋','宋诗','song-poetry','','[]','待伴猶虛夜，羞明或遇朝。',48,'全唐诗/poet.song.171000.json','["待伴猶虛夜，羞明或遇朝。", "但依歌袖舞，休向鬢絲飄。", "有句清堪比，令人意自消。", "暖寒林下具，相就可須招。"]'),
('b16ec2b5-3765-47cf-a549-e83e73e3e89f','簡陳監倉二首  其一','張鎡','宋','宋诗','song-poetry','','[]','自到南湖日，鄰翁識長方。',48,'全唐诗/poet.song.171000.json','["自到南湖日，鄰翁識長方。", "一官甘寂寞，萬事絕思量。", "疎見祇緣嬾，頻來政不妨。", "松林渾似舊，相伴踞胡床。"]'),
('e1fd973d-b6d0-458b-a6ea-84657af58eb3','簡陳監倉二首  其二','張鎡','宋','宋诗','song-poetry','','[]','因病詩全少，春中忽夏深。',48,'全唐诗/poet.song.171000.json','["因病詩全少，春中忽夏深。", "清幽百畝地，安靜六時心。", "樹茂晴方好，荷新雨未禁。", "泥乾容後日，閒步酒隨斟。"]'),
('73be723c-98db-44e9-80d7-e93b592bcd69','簡周晞稷','張鎡','宋','宋诗','song-poetry','','[]','塵土真堪畏，君髯美亦衰。',48,'全唐诗/poet.song.171000.json','["塵土真堪畏，君髯美亦衰。", "登樓纔會面，促坐便論詩。", "社日休持酒，秋香待滿枝。", "客塗書旋習，猶似向來癡。"]'),
('49b8b8e7-7281-40e8-b292-f90f069d28fb','北山早興','張鎡','宋','宋诗','song-poetry','','[]','出郭涼輿穩，山晨氣自濃。',48,'全唐诗/poet.song.171000.json','["出郭涼輿穩，山晨氣自濃。", "寺園逢水斷，塔路過烟重。", "啄木聲穿竹，凌霄色映松。", "世歡吾儻泥，那遂此從容。"]'),
('f9e727d5-72e3-4ae7-91e0-102a81052ef3','冬至後五日約客晨往極樂精舍因尋梅湖山作詩紀事  其一','張鎡','宋','宋诗','song-poetry','','[]','烟重山彌遠，林高日倍鮮。',48,'全唐诗/poet.song.171000.json','["烟重山彌遠，林高日倍鮮。", "抱雞趨野店，𣂏水入冰田。", "未有三冬雪，渾如二月天。", "梅花應早慧，著眼竹籬前。"]'),
('f6e021a9-fd43-41a5-adaa-4d4684989b9d','冬至後五日約客晨往極樂精舍因尋梅湖山作詩紀事  其二','張鎡','宋','宋诗','song-poetry','','[]','未苦撩清興，騎馿故遶山。',48,'全唐诗/poet.song.171000.json','["未苦撩清興，騎馿故遶山。", "松篁高下處，雲日往來間。", "要是從今後，休教枉却閒。", "烏巾風弄影，畫出我詩孱。"]'),
('2a81a211-6e65-4ac4-808e-0d25e657174d','寄呈尤侍郎二首  其一','張鎡','宋','宋诗','song-poetry','','[]','卧疾睽人事，逾旬只掩扉。',48,'全唐诗/poet.song.171000.json','["卧疾睽人事，逾旬只掩扉。", "野情添懶惰，宗伯極瞻依。", "籬落尋黄獨，簷楹接翠微。", "健來方數日，詩又不教肥。"]'),
('9c91be10-48d6-47b4-8964-9b2d9d83a81c','寄呈尤侍郎二首  其二','張鎡','宋','宋诗','song-poetry','','[]','珍重尤夫子，逢人問死生。',48,'全唐诗/poet.song.171000.json','["珍重尤夫子，逢人問死生。", "掃門那憚遠，出戶真須晴。", "爲國鬢先白，因官名更清。", "何時容卜夜，燈畔聽文衡。"]'),
('b76be50c-0994-4814-95ff-0ba99929c2f4','宿治平院長老善忍自紹興癸酉四月住持余是年三月生','張鎡','宋','宋诗','song-poetry','','[]','治平前代寺，幽勝占唐昌。',48,'全唐诗/poet.song.171000.json','["治平前代寺，幽勝占唐昌。", "我始生彌月，師初踞上方。", "百年雖未半，三紀獨偏忙。", "一事尤堪哂，相隨兩鬢蒼。"]'),
('395ac47f-8caf-46db-98a5-322b8c9896c0','野芳亭偶書','張鎡','宋','宋诗','song-poetry','','[]','歲歲閒爲福，今朝命最通。',48,'全唐诗/poet.song.171000.json','["歲歲閒爲福，今朝命最通。", "看蒲逢紫燕，弄柳得青蟲。", "但願詩妥帖，何心技拙工。", "山林過軒紱，誰謂只相同。"]'),
('6df6fee8-3839-43df-a81a-7c467604bbcb','春晚','張鎡','宋','宋诗','song-poetry','','[]','湖遠慵呼艇，春歸只閉門。',48,'全唐诗/poet.song.171000.json','["湖遠慵呼艇，春歸只閉門。", "樹高應翠合，竹靜自黄昏。", "軒冕情終薄，詩書好益尊。", "人間難辦事，夜氣要長存。"]'),
('ab6787fd-6e12-4917-afd7-d4c9cae1537a','潘茂洪出疆回以汴都畫山水扇見遺報之五言','張鎡','宋','宋诗','song-poetry','','[]','嵩華平生夢，騎馿未得遊。',48,'全唐诗/poet.song.171000.json','["嵩華平生夢，騎馿未得遊。", "橐中分雅惠，掌上起新秋。", "報國何能早，需時莫漫憂。", "祗應長近眼，過夏亦慵收。"]'),
('4408f808-b9f1-4e22-ab55-e24de01ad930','代書回寄楊伯虎','張鎡','宋','宋诗','song-poetry','','[]','僧舍匆匆別，飛花雨過春。',48,'全唐诗/poet.song.171000.json','["僧舍匆匆別，飛花雨過春。", "水村居自樂，城市嬾尤真。", "載酒青油舫，傳書白錦鱗。", "訪君須及早，非是久閒人。"]'),
('e738a79d-0033-4987-ac22-90320e611585','過楊伯虎即席書事','張鎡','宋','宋诗','song-poetry','','[]','四面圍疎竹，中間著小臺。',48,'全唐诗/poet.song.171000.json','["四面圍疎竹，中間著小臺。", "有時將客到，隨意看花開。", "拂拭莓苔石，招携碼碯杯。", "昏鴉歸欲盡，數箇入詩來。"]'),
('0d1084ec-1346-4649-a60c-c56bd0b2e9a6','春在','張鎡','宋','宋诗','song-poetry','','[]','春在將回暑，晴開尚带陰。',48,'全唐诗/poet.song.171000.json','["春在將回暑，晴開尚带陰。", "佳時從易過，閒日儘能禁。", "卧室宜重立，浮魚樂又沉。", "有詩無亦好，爭似有時心。"]'),
('d812b0a6-9089-4d84-9788-1bba0d9113e7','遊大中乾元寺','張鎡','宋','宋诗','song-poetry','','[]','突兀前朝寺，維舟又一來。',48,'全唐诗/poet.song.171000.json','["突兀前朝寺，維舟又一來。", "殿空金像暗，徑斷石幢摧。", "物相依成壞，塵緣漫樂哀。", "僧殘無悟語，猶幸結宗雷。"]'),
('02908011-b44d-422f-8513-b00394a617d8','次韻酬張仲思高郵見寄二首  其一','張鎡','宋','宋诗','song-poetry','','[]','春來慵把酒，間日伴僧齋。',48,'全唐诗/poet.song.171000.json','["春來慵把酒，間日伴僧齋。", "風雨梅花夢，谿山老子懷。", "有人非吏俗，同好任天涯。", "歸上青雲日，幽期孰與偕。"]'),
('a0f1409d-f64b-40d9-962d-a1f126083446','次韻酬張仲思高郵見寄二首  其二','張鎡','宋','宋诗','song-poetry','','[]','便欲相尋去，山光看水光。',48,'全唐诗/poet.song.171000.json','["便欲相尋去，山光看水光。", "野航因挾策，春韭自炊粱。", "踽踽吾才短，翩翩子意長。", "文翁他日譽，不但勸農桑。"]'),
('7483f97f-01ce-40a8-920b-10e6943ecc76','次韻酬楊伯子兼呈誠齋  其一','張鎡','宋','宋诗','song-poetry','','[]','我固有詩癖，憐君尤苦心。',48,'全唐诗/poet.song.171000.json','["我固有詩癖，憐君尤苦心。", "自聞非爲俗，異處却同音。", "病後閒方乞，湖邊秋漸深。", "排門聽車騎，相與話幽襟。"]'),
('be74b282-bba1-4e13-ac42-92e712338dad','次韻酬楊伯子兼呈誠齋  其二','張鎡','宋','宋诗','song-poetry','','[]','見說聰明早，童年便與玄。',48,'全唐诗/poet.song.171000.json','["見說聰明早，童年便與玄。", "細看今日句，宛似乃翁篇。", "家譜無他姓，文星聚此邊。", "何須待千首，一首已堪傳。"]'),
('520f85ec-1c12-4cbe-a4a7-c6aab0967c9d','清暉閣在柳洲寺舊址二首  其一','張鎡','宋','宋诗','song-poetry','','[]','去市無多地，重遊浄客心。',48,'全唐诗/poet.song.171000.json','["去市無多地，重遊浄客心。", "何人偏種柳，今日屢鳴禽。", "浩興生孤槳，歸情戀遠岑。", "梁間滿題詠，寧欠我窺臨。"]'),
('5ffb44ab-6efe-433a-8c73-6cc16ad2b167','清暉閣在柳洲寺舊址二首  其二','張鎡','宋','宋诗','song-poetry','','[]','幽寺知何處，風鐘送遠撞。',48,'全唐诗/poet.song.171000.json','["幽寺知何處，風鐘送遠撞。", "孤花明几席，陰樹惜軒窗。", "喚渡輕舟競，窺人白鳥雙。", "寸心方自適，肯易利榮降。"]'),
('7e428cae-e763-47c8-b202-e7c3f1039d5d','買書','張鎡','宋','宋诗','song-poetry','','[]','自笑從來癖，詩書滿屋藏。',48,'全唐诗/poet.song.171000.json','["自笑從來癖，詩書滿屋藏。", "不充饑鼠喙，即飽蠹魚腸。", "插架牙籤整，開編竹簡香。", "他年林下去，誰與記山房。"]'),
('312c01c5-b460-452a-bf2a-480784dc28c5','寒食','張鎡','宋','宋诗','song-poetry','','["\u5bd2\u98df\u8282"]','地僻人稀到，簷虛燕未過。',48,'全唐诗/poet.song.171000.json','["地僻人稀到，簷虛燕未過。", "清愁詩酒少，寒食雨風多。", "名字因農具，襟懷屬釣蓑。", "莫驚時節換，安分看如何。"]'),
('56bc06ce-0172-4aec-980f-e9c880357bf5','山茶花','張鎡','宋','宋诗','song-poetry','','[]','翠翼高攢葉，朱纓澹拂花。',48,'全唐诗/poet.song.171000.json','["翠翼高攢葉，朱纓澹拂花。", "來從山塹側，開稱畫簷牙。", "影薄誰停繡，香清似煮茶。", "幾多輕斂態，月動夾窗紗。"]'),
('8407a51a-8415-47a9-8e03-293b56820aae','楊伯子過訪翌日以兩詩見貽因次韻答  其一','張鎡','宋','宋诗','song-poetry','','[]','晴色今朝好，春光恰半頭。',48,'全唐诗/poet.song.171000.json','["晴色今朝好，春光恰半頭。", "波情如釣渭，圃事勝封留。", "瘦覺中黄合，閒宜大白浮。", "無端同志侶，相過結詩愁。"]'),
('b006d179-935a-4247-9c77-b960f767e784','楊伯子過訪翌日以兩詩見貽因次韻答  其二','張鎡','宋','宋诗','song-poetry','','[]','句業誠淵海，愚方一葦航。',48,'全唐诗/poet.song.171000.json','["句業誠淵海，愚方一葦航。", "空成由也瑟，難應女媧簧。", "擬易乾坤別，傳家父子香。", "整翰從此去，拭眥望朝陽。"]'),
('7c408a16-31e1-4e4c-9200-966457b7f72b','過翔鸞院留題僧房','張鎡','宋','宋诗','song-poetry','','[]','頻年雖並住，今日偶能來。',48,'全唐诗/poet.song.171000.json','["頻年雖並住，今日偶能來。", "水檻因蓮設，風窗爲客開。", "詩凡慙鮑謝，社近憶宗雷。", "莫問通衢隔，輕舟自往回。"]'),
('5b922f32-eaf8-40fe-a16f-e66d235a42c9','宿八尺月色陡明','張鎡','宋','宋诗','song-poetry','','[]','將謂無佳月，貪程過上湖。',48,'全唐诗/poet.song.171000.json','["將謂無佳月，貪程過上湖。", "纔來八尺住，却見一輪孤。", "带露寒於水，和烟白似酥。", "江天空想望，高下兩明珠。"]'),
('08d42975-fc68-4cd1-aa21-30352bfcf218','送酒誠齋將以五字','張鎡','宋','宋诗','song-poetry','','[]','不應楊秘監，無暇問南湖。',48,'全唐诗/poet.song.171000.json','["不應楊秘監，無暇問南湖。", "桂樹又花發，蓮池和葉枯。", "雨聲秋最好，尊酒客非無。", "寄去撩詩眼，深慙句法粗。"]'),
('3eba4cd9-5206-43bd-9ae1-ba99ac5bcd7c','過湖至郭氏菴','張鎡','宋','宋诗','song-poetry','','[]','山色棱層出，荷花浪漫開。',48,'全唐诗/poet.song.171000.json','["山色棱層出，荷花浪漫開。", "只如平日看，自喜此時來。", "楊柳侵船影，蜻蜓傍酒杯。", "僧廬須過夜，城禁莫催回。"]'),
('79387ce3-3513-4b1e-a855-598fc6ea7963','因過張郎中識孫才翁教授時徐衡仲亦在坐成四韻送呈','張鎡','宋','宋诗','song-poetry','','[]','邂逅如相約，新交會舊知。',48,'全唐诗/poet.song.171000.json','["邂逅如相約，新交會舊知。", "軒窗渾未暑，賓主總能詩。", "小草浮冰楮，初篁映錦葵。", "星郎風韻殺，我輩盍幽期。"]'),
('e4c345e7-1d05-40a3-89a2-3fbe9c82f855','挽叔祖戶部侍郎詩四首  其一','張鎡','宋','宋诗','song-poetry','','[]','從此無因見，南園老叔翁。',48,'全唐诗/poet.song.171000.json','["從此無因見，南園老叔翁。", "朝廷世臣少，文獻我家窮。", "達宦誰無分，全材不易逢。", "先王勳第一，號慟仰天公。"]'),
('c4d46560-7c11-4913-ae54-90ecd3cc214f','挽叔祖戶部侍郎詩四首  其二','張鎡','宋','宋诗','song-poetry','','[]','八郡恢成績，江山入壯圖。',48,'全唐诗/poet.song.171000.json','["八郡恢成績，江山入壯圖。", "風流羊叔子，才術管夷吾。", "絕筆詩猶在，酬君志不渝。", "經綸如有位，肯墮淺規摹。"]'),
('0afe8efa-9a43-4258-8e7a-71559cd4a412','挽叔祖戶部侍郎詩四首  其三','張鎡','宋','宋诗','song-poetry','','[]','小小爲知己，常常說向人。',48,'全唐诗/poet.song.171000.json','["小小爲知己，常常說向人。", "論情宗族異，問事見聞新。", "囊錦將誰管，湖園看未真。", "傷心嘯菴路，不復送親賓。"]'),
('3ceda65a-68ed-4d93-a415-bc833df10719','挽叔祖戶部侍郎詩四首  其四','張鎡','宋','宋诗','song-poetry','','[]','內典存心久，家居戒行僧。',48,'全唐诗/poet.song.171000.json','["內典存心久，家居戒行僧。", "同塵聊且爾，著相亦何曾。", "脫却當來袴，傳將不盡燈。", "欲知歸甚處，一月萬波澄。"]'),
('549f6449-115b-4e1e-a8f8-32d2d77893bb','次韻王耘之秋興二首  其一','張鎡','宋','宋诗','song-poetry','','[]','妙墨真連草，清辭角應商。',48,'全唐诗/poet.song.171000.json','["妙墨真連草，清辭角應商。", "襟期容汗漫，興致入蒼茫。", "派自王摩詰，才分馬子長。", "宦途休嘆滯，眉宇見新黄。"]'),
('7df71cd6-529d-442c-95c9-a295421f805f','次韻王耘之秋興二首  其二','張鎡','宋','宋诗','song-poetry','','[]','多士寧王室，中宸夢傅巖。',48,'全唐诗/poet.song.171000.json','["多士寧王室，中宸夢傅巖。", "如何兩京客，猶挂五湖帆。", "落落雲松節，飄飄霜葉杉。", "深藏草檄手，端欲取殽函。"]'),
('5010ce43-d945-4f52-8950-57665308d9c1','夜飲呈葉司戶  其一','張鎡','宋','宋诗','song-poetry','','[]','欲薄交難古，心親話許深。',48,'全唐诗/poet.song.171000.json','["欲薄交難古，心親話許深。", "更長銀燭夜，院靜石雲陰。", "冷夢多孱骨，修程費老襟。", "松壺梅並插，投醉且高吟。"]'),
('32c7649d-b0b3-4bc2-8d8d-af3e8cf43c84','夜飲呈葉司戶  其二','張鎡','宋','宋诗','song-poetry','','[]','僂指摳衣日，于今歲六移。',48,'全唐诗/poet.song.171000.json','["僂指摳衣日，于今歲六移。", "步趨徒願學，憂患亦何爲。", "窗曉鴉同起，天寒鴈引悲。", "依仁方再幸，小耐了康時。"]'),
('d38682c1-a664-4124-b50f-c9a27a5d5483','題畫二首  其一','張鎡','宋','宋诗','song-poetry','','[]','幾欲疏方沼，泓澄豢小魚。',48,'全唐诗/poet.song.171000.json','["幾欲疏方沼，泓澄豢小魚。", "畫屏先我意，覓句爲君書。", "扇舉萍疑動，紗明水一如。", "林塘能早就，肯但植芙蕖。"]'),
('027cdc1c-c0aa-4912-a946-340fa783960d','題畫二首  其二','張鎡','宋','宋诗','song-poetry','','[]','草樹秋聲合，乾坤夜氣生。',48,'全唐诗/poet.song.171000.json','["草樹秋聲合，乾坤夜氣生。", "念閒無復夢，坐久屢閒更。", "未試從長劍，相親幸短檠。", "欠伸聊覓枕，誰會此時情。"]'),
('19fec821-5191-47c3-84a3-f23c17af7050','次韻酬曾無逸宗教  其一','張鎡','宋','宋诗','song-poetry','','[]','自識閒中趣，常嫌閙處行。',48,'全唐诗/poet.song.171000.json','["自識閒中趣，常嫌閙處行。", "湖山真富貴，花鳥小聲名。", "有客金蘭好，貽詩徵角鳴。", "相期耐霜露，斯事豈凡情。"]'),
('769985dc-e996-4518-896a-ea4393840712','次韻酬曾無逸宗教  其二','張鎡','宋','宋诗','song-poetry','','[]','地秀溪通邑，山高寺矗雲。',48,'全唐诗/poet.song.171000.json','["地秀溪通邑，山高寺矗雲。", "望殊驚乍見，景勝厭前聞。", "鷄犬人家樂，風煙釣艇紛。", "奔程船徑過，雖雨未西曛。"]'),
('c8fc9c4b-55e5-46a2-97ac-6100fea6e69b','徇俗','張鎡','宋','宋诗','song-poetry','','[]','徇俗非能事，便幽定宿緣。',48,'全唐诗/poet.song.171000.json','["徇俗非能事，便幽定宿緣。", "躍泉新作雨，裝樹巧留煙。", "雀喜頻頻下，蜂知小小穿。", "疎風奏簷珮，無夢到鈞天。"]'),
('3b11875b-153f-4e06-ad07-f9a4a8deaeb0','奉寄淮西總領張少卿并呈建康留守章侍郎二首  其一','張鎡','宋','宋诗','song-poetry','','[]','湖隠門連草，宗盟肯屢尋。',48,'全唐诗/poet.song.171000.json','["湖隠門連草，宗盟肯屢尋。", "長才明主眷，直道古人心。", "又引皇華去，誰憐白髮侵。", "官居兼靜樂，賢帥復朋吟。"]'),
('54929174-f53f-4664-bc6c-571bc1698468','奉寄淮西總領張少卿并呈建康留守章侍郎二首  其二','張鎡','宋','宋诗','song-poetry','','[]','別來秋易過，幽桂兩番開。',48,'全唐诗/poet.song.171000.json','["別來秋易過，幽桂兩番開。", "去歲人同賞，今宵夢自回。", "飛雲遥楚岫，斜照直秦淮。", "地念曾遊處，春行或許陪。"]'),
('5d448e71-54da-49bc-ba42-fafbd636a04f','伏日','張鎡','宋','宋诗','song-poetry','','[]','未曉雨先驟，過朝風更鮮。',48,'全唐诗/poet.song.171000.json','["未曉雨先驟，過朝風更鮮。", "誰知初伏日，全是早秋天。", "洗盞嘗新酒，臨池摘嫩蓮。", "平生丘壑意，不受暑寒遷。"]'),
('9364364d-4a4f-491e-ba3f-69e07b922d9b','稍負','張鎡','宋','宋诗','song-poetry','','[]','稍負園亭約，新篁带可圍。',48,'全唐诗/poet.song.171000.json','["稍負園亭約，新篁带可圍。", "看山真耐久，臨水易忘機。", "野角呼蛇出，輕舟趁鶩歸。", "還家欣未晚，池藻弄晴暉。"]'),
('c6877e20-8548-4b16-830d-392e89e1fef1','送葉正則秘郎參議湖北帥幕','張鎡','宋','宋诗','song-poetry','','[]','桂隠無期報，朝賢去却知。',48,'全唐诗/poet.song.171000.json','["桂隠無期報，朝賢去却知。", "累年艱特薦，一事必憂時。", "盛世未應爾，重來猶可爲。", "相過非爲數，公論合勤思。"]'),
('a983b997-a322-4be6-9964-d81bebb970e8','問鶴','張鎡','宋','宋诗','song-poetry','','[]','鶴也來多日，今朝認筍輿。',48,'全唐诗/poet.song.171000.json','["鶴也來多日，今朝認筍輿。", "繖斜聊引避，路轉亦前驅。", "俗遠眼寧白，年初頂漸朱。", "古囊能背否，勝用小奚奴。"]'),
('5a018d91-af5a-4852-bc67-39cb195761d8','送喻叔奇工部知括蒼二首  其一','張鎡','宋','宋诗','song-poetry','','[]','三見中朝入，徐行每後人。',48,'全唐诗/poet.song.171000.json','["三見中朝入，徐行每後人。", "功庸身較晚，名譽衆常新。", "有句須同詠，今離似所親。", "政成應必報，山郡易回春。"]'),
('622393f2-614e-4b3a-bf01-b0a3dc7ff8e7','送喻叔奇工部知括蒼二首  其二','張鎡','宋','宋诗','song-poetry','','[]','自復林湖隠，相從却恨稀。',48,'全唐诗/poet.song.171000.json','["自復林湖隠，相從却恨稀。", "梅花年後白，江水去邊肥。", "世態紛紛改，交心特特違。", "暖晴當送別，敢望款柴扉。"]'),
('52eb597a-e9a8-478b-9e6d-be3c75824257','山寺漫興','張鎡','宋','宋诗','song-poetry','','[]','未到楓林寺，常吟半夜鐘。',48,'全唐诗/poet.song.171000.json','["未到楓林寺，常吟半夜鐘。", "乍來衝路雨，少坐怯廊風。", "潄齒村茶苦，看碑大字工。", "出門山慣見，何事意無窮。"]'),
('2f8e47d5-b666-483f-a649-171502ee4ab8','楊仲子携詩見過次韻酬贈并呈誠齋二首  其一','張鎡','宋','宋诗','song-poetry','','[]','老監過陳實，賢郎似竇羣。',48,'全唐诗/poet.song.171000.json','["老監過陳實，賢郎似竇羣。", "共將奇句了，不許外人分。", "訪我三竿日，縈簾一炷雲。", "當家相見處，那此世情欣。"]'),
('f9a5d4f1-acdf-496f-abc8-469487bd003f','楊仲子携詩見過次韻酬贈并呈誠齋二首  其二','張鎡','宋','宋诗','song-poetry','','[]','愛水移居宅，行藏豈但迂。',48,'全唐诗/poet.song.171000.json','["愛水移居宅，行藏豈但迂。", "若非風月管，枉伴竹松臞。", "野服常寬带，芒鞋亦斷絇。", "請君看此老，堪作貴人無。"]'),
('5761b656-665e-4425-bd20-283a57a1d6f7','重過鳳山高氏','張鎡','宋','宋诗','song-poetry','','[]','屋負山陲晚，籬侵水濼秋。',48,'全唐诗/poet.song.171000.json','["屋負山陲晚，籬侵水濼秋。", "農桑能自力，鵝鴨豈它求。", "逆數曾來日，遮留更覺稠。", "夜歌聽欵乃，催興滿滄洲。"]'),
('c7345472-1883-49a7-8d6d-3d9c07bc45aa','永嘉張仲思相士過訪坐間索詩','張鎡','宋','宋诗','song-poetry','','[]','便靜非形色，相逢子獨知。',48,'全唐诗/poet.song.171000.json','["便靜非形色，相逢子獨知。", "功名槐蟻話，文字壁魚癡。", "剩取朝賢譽，何須隠者詩。", "南湖鷗正狎，休誤鳳凰池。"]'),
('cc2a6395-e247-4276-8022-5e34f10a4dcb','園桂初發邀同社小飲','張鎡','宋','宋诗','song-poetry','','[]','故故論年賞，新看惜未多。',48,'全唐诗/poet.song.171000.json','["故故論年賞，新看惜未多。", "一香參衆樹，千月下纖娥。", "今雨胡能阻，秋蟲亦復歌。", "有情毋恡醉，斯世合婆娑。"]'),
('20493eb5-2193-4e62-8865-9996180ee0d8','桂樹下作','張鎡','宋','宋诗','song-poetry','','[]','芳桂年年種，今秋兩倍開。',48,'全唐诗/poet.song.171000.json','["芳桂年年種，今秋兩倍開。", "略無蜂敢傍，爲是月中來。", "幸自晴多日，須拚醉幾回。", "便教香殺了，猶勝別人獃。"]'),
('f1d9669b-f877-4545-939f-74ff6c6b2b4e','過冷泉','張鎡','宋','宋诗','song-poetry','','[]','未喜亭陰坐，先貪樹畔行。',48,'全唐诗/poet.song.171000.json','["未喜亭陰坐，先貪樹畔行。", "谿渾因雨瀑，巖近得風清。", "一飯幽人福，三杯太古情。", "尚須冰月挂，來放雪濤傾。"]'),
('03db4b8d-c5be-44bb-8b3e-4a6ade27fb28','桃花','張鎡','宋','宋诗','song-poetry','','[]','園翁能好客，折贈小春桃。',48,'全唐诗/poet.song.171000.json','["園翁能好客，折贈小春桃。", "却爲開花少，翻成占格高。", "來年紅爛漫，繞澗碧周遭。", "莫忘閶門外，曾將進濁醪。"]'),
('579f14b0-438c-4cd8-a420-5bee9e22977d','楊秘監補外贈送','張鎡','宋','宋诗','song-poetry','','[]','止是尋常月，今宵不愛明。',48,'全唐诗/poet.song.171000.json','["止是尋常月，今宵不愛明。", "江邊有歸客，都下減詩情。", "上自憐公直，人知暫此行。", "賢郎先返舍，應喜候門迎。"]'),
('5ecc8ce4-ab48-4f15-ad29-d4a16746063c','名新釀曰白鷗波以一尊送佑聖觀劉高士','張鎡','宋','宋诗','song-poetry','','[]','酒熟將何字，白鷗波正如。',48,'全唐诗/poet.song.171000.json','["酒熟將何字，白鷗波正如。", "一瓢誰合飲，高士觀中居。", "汗漫涵無象，鴻濛洽太初。", "醒來松戶曉，應念臭於帤。"]'),
('c240e900-9d6a-473f-bce9-712de2d6a283','湖南舟中贈日者','張鎡','宋','宋诗','song-poetry','','[]','坐上君但笑，人間我最愚。',48,'全唐诗/poet.song.171000.json','["坐上君但笑，人間我最愚。", "百年休較命，今日且航湖。", "地曠山霏薄，風薰水葉粗。", "寸陰方解惜，總是己工夫。"]'),
('df1b1050-c503-4f0f-9735-a8cb1ba047e5','題方竹杖松根枕二首  其一','張鎡','宋','宋诗','song-poetry','','[]','鶴骨何能爾，龍姿或果然。',48,'全唐诗/poet.song.171000.json','["鶴骨何能爾，龍姿或果然。", "鋒稜四面峻，節操一生堅。", "界紙書堪使，敲針釣最便。", "從教方有礙，終不效規圓。"]'),
('30b39699-8aaa-4361-b600-19cb4c0e12fa','題方竹杖松根枕二首  其二','張鎡','宋','宋诗','song-poetry','','[]','鬰鬰凌寒色，來宜此地蟠。',48,'全唐诗/poet.song.171000.json','["鬰鬰凌寒色，來宜此地蟠。", "解衣輕盾日，假蓋得秦官。", "香宿風微墮，青留雨未乾。", "通宵巖側夢，根竅手藏丹。"]'),
('b68c0a10-3b19-4b17-8269-bea318213011','夢覺  其一','張鎡','宋','宋诗','song-poetry','','[]','夢覺西窗曉，聽風過曲廊。',48,'全唐诗/poet.song.171000.json','["夢覺西窗曉，聽風過曲廊。", "好詩非易辨，閒坐盡無妨。", "人靜鳥烏喜，雨來花草香。", "寸心經患難，况復近秋涼。"]'),
('6dcc5499-7dea-42a6-b905-9d830e7eee55','夢覺  其二','張鎡','宋','宋诗','song-poetry','','[]','二十年前事，渾如夢覺時。',48,'全唐诗/poet.song.171000.json','["二十年前事，渾如夢覺時。", "漫行荒路逕，難認舊亭基。", "尚記因逃暑，曾來學賦詩。", "如今無可好，植杖欲耘籽。"]'),
('d95de3bb-121c-4390-a97e-5ef73998b4af','夜半浴','張鎡','宋','宋诗','song-poetry','','[]','濁熱不成睡，起看宵過中。',48,'全唐诗/poet.song.171000.json','["濁熱不成睡，起看宵過中。", "繁星珠結網，片月玉爲弓。", "賦鵲情何有，驅蚊計頗窮。", "猶欣湯浴後，膚受綠蘋風。"]'),
('4a8e2ee2-73db-422a-bbc8-acc7c3f30bb9','次韻答曾司法','張鎡','宋','宋诗','song-poetry','','[]','精神由日就，格律忌雷同。',48,'全唐诗/poet.song.171000.json','["精神由日就，格律忌雷同。", "我匪從它入，君應自此工。", "多岐憐世路，力學振家風。", "莫易朱絃絕，千年論最公。"]'),
('b5f8e06f-5a60-4524-b348-080d99ef7abf','命鹿','張鎡','宋','宋诗','song-poetry','','[]','雙鹿林泉友，新居後我成。',48,'全唐诗/poet.song.171000.json','["雙鹿林泉友，新居後我成。", "角低方長旺，斑嫩未分明。", "濯濯菰塘晚，呦呦草逕晴。", "仙疇吾種玉，汝輩耦而耕。"]'),
('24397218-eba1-479a-a376-7190a394c73e','正月三日同諸親從叔祖閣學登寧壽觀東西山尋至鄰園次叔祖韻','張鎡','宋','宋诗','song-poetry','','[]','超曠欣便靜，紛譁厭處濃。',48,'全唐诗/poet.song.171000.json','["超曠欣便靜，紛譁厭處濃。", "客親非外約，地勝適新逢。", "詩興驂黄鶴，仙情寄赤松。", "烟平千萬戶，此處認歌鐘。"]'),
('abd23516-5a40-4ad1-8006-fcf620596b56','次韻寄齋贈竹居','張鎡','宋','宋诗','song-poetry','','[]','振俗還風雅，乾坤覓句中。',48,'全唐诗/poet.song.171000.json','["振俗還風雅，乾坤覓句中。", "夔臯渠合遇，郊島我甘同。", "浩蕩投鷗水，清和翻燕風。", "相投兩無語，聲遠莫摩空。"]'),
('19f345eb-f921-4f7f-93db-2fe17838818e','安樂泉亭上午憇','張鎡','宋','宋诗','song-poetry','','[]','脩竹有風處，道人無事時。',48,'全唐诗/poet.song.171000.json','["脩竹有風處，道人無事時。", "諸公難入眼，不用總如眉。", "得價婆娑重，投閒懶散宜。", "三年何足道，堅判百年期。"]'),
('98e0fb92-9a79-4070-b4d4-ac262a07e7b4','暮色','張鎡','宋','宋诗','song-poetry','','[]','暮色雲端合，晴光天際慳。',48,'全唐诗/poet.song.171000.json','["暮色雲端合，晴光天際慳。", "鳥羣科斗字，山態倦螺鬟。", "寂寂功名會，紛紛車馬間。", "拍欄情倍極，烟老罩魚灣。"]'),
('7f8c2f8b-26da-499e-94ef-b74484a99f8c','夜坐示客','張鎡','宋','宋诗','song-poetry','','[]','身世長歌裏，于今得好朋。',48,'全唐诗/poet.song.171000.json','["身世長歌裏，于今得好朋。", "露階秋到竹，風屋夜吹燈。", "菱芡供饞口，圖書伴曲肱。", "頭顱知自揣，顧影笑鬅鬙。"]'),
('7317242c-b496-4343-af33-c3cc94b594be','表兄劉東玉提幹挽詩二首  其一','張鎡','宋','宋诗','song-poetry','','[]','王祖扶天日，同聲外氏翁。',48,'全唐诗/poet.song.171000.json','["王祖扶天日，同聲外氏翁。", "功勳俱卓越，門戶合穹隆。", "諸舅今何在，唯兄命亦窮。", "賢郎須力學，一綫續家風。"]'),
('125f2456-a162-437c-8339-70e80b755410','表兄劉東玉提幹挽詩二首  其二','張鎡','宋','宋诗','song-poetry','','[]','襁褓予多疾，三年託渭陽。',48,'全唐诗/poet.song.171000.json','["襁褓予多疾，三年託渭陽。", "未能看擊罋，常是戲登床。", "轉首塵埃裏，驚心歲月長。", "挽兄賫志去，傾淚入詩章。"]'),
('bcf6c8e1-f2d6-4350-a640-f95db38db208','老筆贈銛上人二首  其一','張鎡','宋','宋诗','song-poetry','','[]','握手四年別，滿心千偈禪。',48,'全唐诗/poet.song.171000.json','["握手四年別，滿心千偈禪。", "清燈纔軟語，新雪尚幽眠。", "了了翻身訣，寥寥斷臂緣。", "我懷吾自會，惡句莫多傳。"]'),
('b9db33d8-84dd-40bb-865c-b097e1643ae6','老筆贈銛上人二首  其二','張鎡','宋','宋诗','song-poetry','','[]','已事殷然急，江湖第一流。',48,'全唐诗/poet.song.171000.json','["已事殷然急，江湖第一流。", "才高樓五鳳，伎進刃全牛。", "可惜梅花節，忙回竹葉舟。", "老師應賞棒，碑巨壓東州。"]'),
('c51273eb-a36c-49ac-9053-a2c9136f5a27','自詠','張鎡','宋','宋诗','song-poetry','','[]','事業新來別，賢愚久自知。',48,'全唐诗/poet.song.171000.json','["事業新來別，賢愚久自知。", "作文時似呪，寫字忽如錐。", "賣屋因爲宅，謀官本近醫。", "有來評世務，好好只相隨。"]'),
('7d59b810-f6d1-438b-a415-3c03ba591b47','道院書壁','張鎡','宋','宋诗','song-poetry','','[]','約客探名勝，停輈得所欣。',48,'全唐诗/poet.song.171000.json','["約客探名勝，停輈得所欣。", "山寒多作雨，洞古不收雲。", "夜宿聽鳴鹿，晨齋飣野芹。", "黄冠尤喜事，添注石爐熏。"]'),
('7cbd0aaa-b1aa-460d-8628-4bd84902743d','次韻叔祖閣學題逸村亭壁','張鎡','宋','宋诗','song-poetry','','[]','橋迥有牛過，村深無馬嘶。',48,'全唐诗/poet.song.171000.json','["橋迥有牛過，村深無馬嘶。", "哨風驚客袂，膏雨慰耕犁。", "遊目花通野，吟情絮著泥。", "幽坊愜虛眺，况復見新題。"]'),
('130e49a8-50e6-4735-9d4d-d9991e7da09f','野芳亭書壁','張鎡','宋','宋诗','song-poetry','','[]','山向林間出，船從草外撐。',48,'全唐诗/poet.song.171000.json','["山向林間出，船從草外撐。", "行來風數刻，坐待月三更。", "政自安閒散，誰能管愛憎。", "新功喜今夏，陰滿蒲萄棚。"]'),
('6b80f75a-9f7a-4cdf-9d6d-7ee2b2c23ccb','客舍夜聞吳謳有懷南湖','張鎡','宋','宋诗','song-poetry','','[]','屋漏燈垂粟，牆欹螾唱叢。',48,'全唐诗/poet.song.171000.json','["屋漏燈垂粟，牆欹螾唱叢。", "斷編非徑捷，隅座且丞聾。", "歌聽魚蠻子，盟寒水勃公。", "明知今夜夢，清殺葦間篷。"]'),
('a292827e-4a0b-483d-a7bb-aaef88f3a5a8','牡丹','張鎡','宋','宋诗','song-poetry','','[]','分數論春物，都應讓牡丹。',48,'全唐诗/poet.song.171000.json','["分數論春物，都應讓牡丹。", "幾枝單葉紫，滿擔夕香寒。", "除我知心切，從人得句難。", "肯辭回櫂日，多瓣剪來看。"]'),
('ee895eb4-946b-4825-954e-0af6ad31443b','湖邊夜興','張鎡','宋','宋诗','song-poetry','','[]','夜月雖愆約，秋雲却薦凉。',48,'全唐诗/poet.song.171000.json','["夜月雖愆約，秋雲却薦凉。", "橋明緣水浄，樹近覺風香。", "衆論輕閒適，幽懷貴老狂。", "從今無復病，處處養生方。"]'),
('66bbb883-877e-4825-aa97-38c7713bfb8c','夜述','張鎡','宋','宋诗','song-poetry','','[]','客去情宜獨，宵長睡未忺。',48,'全唐诗/poet.song.171000.json','["客去情宜獨，宵長睡未忺。", "露多應冒砌，香重欲蒸簾。", "較利真誰得，耽書肯自嫌。", "爐存金粟火，煨蕷不須添。"]'),
('530c5446-1360-4d07-989f-364204dfd2b2','寄呈史太師二首  其一','張鎡','宋','宋诗','song-poetry','','[]','昔爲金闕相，曾是玉皇師。',48,'全唐诗/poet.song.171000.json','["昔爲金闕相，曾是玉皇師。", "近即維垣拜，還從彭祖期。", "傳聞風景勝，多賦洞天詩。", "肯示漁樵否，林間要勒碑。"]'),
('6f336056-6c54-47c4-b513-068b5f0a1735','寄呈史太師二首  其二','張鎡','宋','宋诗','song-poetry','','[]','自憐冰氏子，父祖已登門。',48,'全唐诗/poet.song.171000.json','["自憐冰氏子，父祖已登門。", "屏跡千官外，馳書一品尊。", "華戎心處活，經傳語前論。", "欲理西風棹，因瞻祇樹園。"]'),
('e4824367-569b-4106-81b7-a29923509b66','誰謂','張鎡','宋','宋诗','song-poetry','','[]','誰謂閒無事，閒中事日生。',48,'全唐诗/poet.song.171000.json','["誰謂閒無事，閒中事日生。", "和香雕印脫，記石假雲名。", "水取從龍井，花移自馬城。", "若將朝市比，忙處却多爭。"]'),
('e9611812-0a39-48af-9a0c-45a23a529947','問訊家林蠟梅','張鎡','宋','宋诗','song-poetry','','[]','蠟梅吾甚愛，園種未能多。',48,'全唐诗/poet.song.171000.json','["蠟梅吾甚愛，園種未能多。", "旋去東南竹，新添二十窠。", "離家俄半月，放蕾想盈柯。", "前日丁寧句，花神記得麽。"]'),
('36041e07-8bdb-4102-83ab-572688778a01','行次鶑脰湖','張鎡','宋','宋诗','song-poetry','','[]','震澤匆匆過，胥塘漸漸來。',48,'全唐诗/poet.song.171000.json','["震澤匆匆過，胥塘漸漸來。", "風高多罨岸，船側屢翻盃。", "積草攤漁網，疎林聚客桅。", "景逢宜急寫，句過恐難裁。"]'),
('d16a6d56-a7e7-474c-a92e-272629185b2d','皇太子生辰詩','張鎡','宋','宋诗','song-poetry','','[]','慶協丁年應，祥開甲觀雄。',288,'全唐诗/poet.song.171000.json','["慶協丁年應，祥開甲觀雄。", "九霞光絢爛，重日彩曈矓。", "根本千齡固，元良萬口同。", "文孫覿堯法，聖子奉虞聰。", "視膳長遵度，怡顔但飭躬。", "形容歌玉粹，瞻仰見淵沖。", "象輅陳儀肅，鸞旌定制崇。", "承祧雖位震，寶儉只扉銅。", "典學勤無斁，談經異必攻。", "性天元啟闢，講席更磨礱。", "以貴釐京兆，維禋禮昊穹。", "理繁情畢見，陪祝敬彌隆。", "善政邦人洽，純誠帝賚通。", "澄源基廣大，主鬯福延洪。", "綺甪從遊盛，應劉藻思工。", "德尊謀不用，唱古和無功。", "八法誰云易，前朝論亦公。", "規模傳聖上，意韻出胸中。", "草軸方翔鳳，真題復起鴻。", "聯翩來殿戟，焜燿到門蓬。", "雨足湖山秀，秋成黍稷豐。", "菊香金錯豔，橙嫩玉垂叢。", "五學懽聲合，三宮喜氣充。", "駢蕃恩莫紀，洋溢譽無窮。"]'),
('436e7494-c00a-45ca-b5d1-07e3f9f2bef5','對雪','張鎡','宋','宋诗','song-poetry','','[]','漫記今年雪，先慳半月晴。',288,'全唐诗/poet.song.171000.json','["漫記今年雪，先慳半月晴。", "乍飄偏有熊，猛下却無聲。", "水繞長春圃，人居不夜城。", "弄寒羣犬戲，驚曉獨鷄鳴。", "橋凍泥添滑，窗虛紙借明。", "冷妨梅早慧，高妬柳輕生。", "瀹茗嘗深鼎，臨書厭短檠。", "鵝邊鷳失素，鷗混鷺爭盟。", "日壑銀烹出，龍沙粉築成。", "歌鹽唐按譜，聚米漢談兵。", "曳履需公詔，吞氈感使旌。", "初平羊變石，白起甲填坑。", "賈舶停珠浦，朝驂萃玉京。", "駝銅誇北錄，馬瑞遇東瀛。", "雲凝情俱淡，風旋力驟獰。", "藕邊侵緯宿，酥畔比螺蟶。", "敞坐詩牋接，歡筵舞袖迎。", "緣甍方盼轉，入幌忽縈盈。", "煙滿空翔鶴，潮翻海縱鯨。", "藍田難愛寶，月窟助蜚英。", "甕罩杯誰覆，盆冰鏡不傾。", "瑶隨王粲珮，璣綴李彪纓。", "豹舄宜分色，麻衣浪擬清。", "齊腰休更舉，巴曲試煩賡。"]'),
('1cbf380a-aed6-45f4-890b-6b172d1531cc','巾車','張鎡','宋','宋诗','song-poetry','','[]','聽說小巾車，形模似竹輿。',171,'全唐诗/poet.song.171000.json','["聽說小巾車，形模似竹輿。", "雙輪氈裹去，三壁帽開舒。", "僮矮行携硯，鬟嬌坐奉書。", "岢峩回徑處，轣{車录}度橋初。", "鶴引青莎軟，鶑看翠柳疎。", "袖爐香正噴，背榼酒多儲。", "過愛凉軒敞，停因燕館虛。", "直須教畫看，全似出塵居。", "緩駕終調鹿，忙牽莫命馿。", "只緣心蕩蕩，自到境如如。", "剩有真堪寫，時無憤可攄。", "尚慙銷粟帛，何事免繰鋤。", "命駟邀朋客，籠鵝謝里閭。", "屏星前日夢，不枉賦歸歟。"]'),
('e3f1f633-a21c-4150-a0d5-8c4cd399490c','庚戌歲旦次張以道韻','張鎡','宋','宋诗','song-poetry','','[]','農家正旦喜占晴，老圃觀風趁早春。',64,'全唐诗/poet.song.171000.json','["農家正旦喜占晴，老圃觀風趁早春。", "兩事欲尋强健日，一生常作太平民。", "紹熙初歲新開曆，典冊崇儀極奉親。", "詞拙固難傳樂府，水邊閒示釣魚人。"]'),
('44634215-689b-4df9-a6c3-d1af177d1971','立春日訪梅裴氏園','張鎡','宋','宋诗','song-poetry','','[]','下馬東風恰到來，午煙沙際日烘開。',64,'全唐诗/poet.song.171000.json','["下馬東風恰到來，午煙沙際日烘開。", "長松寂歷寒聲少，遠柳葱蘢綠意回。", "零落歡遊逢故地，寅緣幽勝逐深杯。", "湖邊不使儂先詠，枉却今年處士梅。"]'),
('9f0bb217-be51-44bf-b8b9-77965557871d','正月八日喜霽','張鎡','宋','宋诗','song-poetry','','[]','未春天氣已佳晴，病起光風滿意明。',64,'全唐诗/poet.song.171000.json','["未春天氣已佳晴，病起光風滿意明。", "竹色舞簾金翠活，鳥聲穿戶角宮成。", "黄麻天上登周召，濁酒林間慕綺榮。", "從此尋芳繞阡陌，野翁相遇詫時平。"]'),
('7940af45-33b7-4c13-8aba-1e27af2f3fcd','燈夕','張鎡','宋','宋诗','song-poetry','','[]','插花呼酒少年場，爛賞花燈十里香。',64,'全唐诗/poet.song.171000.json','["插花呼酒少年場，爛賞花燈十里香。", "璧月當天星緯少，珠簾排戶樂聲長。", "非緣風景今殊昔，自是情懷老不狂。", "贏得安禪心似水，碧琉璃照佛龕旁。"]'),
('934aecd7-17ca-47e7-9162-7aaa40a05370','次韻潘茂洪春日書懷','張鎡','宋','宋诗','song-poetry','','[]','東風漸放柳遮門，隔水人家聚似村。',64,'全唐诗/poet.song.171000.json','["東風漸放柳遮門，隔水人家聚似村。", "漁艇遠來誇甫里，僧隣閒過講慈恩。", "花繁慣識蜂情性，晝靜初聞燕語言。", "病起適逢春正好，莫教詩思却塵昏。"]'),
('ad0a14ae-d78e-4668-a974-5e9e46846cf7','春晴獨坐次叔祖閣學韻','張鎡','宋','宋诗','song-poetry','','[]','䰐鬖綠柳拂垣衣，課蜜蜂忙踏蕊歸。',64,'全唐诗/poet.song.171000.json','["䰐鬖綠柳拂垣衣，課蜜蜂忙踏蕊歸。", "須趁一春隨意適，極知萬事轉頭非。", "添罏麝餠遮殘火，擁案塵編絕故韋。", "便當清歡忘肉味，况安淡泊少甘肥。"]'),
('0e7b13e5-3fd5-4378-99b5-f4d24fa06af6','三月十四夜觀月思南湖','張鎡','宋','宋诗','song-poetry','','[]','期會紛然不到詩，拙哉前計只心知。',64,'全唐诗/poet.song.171000.json','["期會紛然不到詩，拙哉前計只心知。", "縱當吏散庭空後，爭似山行水泛時。", "柳影半籠明處路，葦聲輕窣暗邊籬。", "波神擅此三更月，定訝今宵欠笛吹。"]'),
('f42468f3-e8a5-4485-8d22-f5f041548daf','寒食不出遨','張鎡','宋','宋诗','song-poetry','','[]','南湖寒食又今年，宿雨連朝洗舊烟。',64,'全唐诗/poet.song.171000.json','["南湖寒食又今年，宿雨連朝洗舊烟。", "竹葉酒邊閒鑿落，杏梢牆畔出秋千。", "游歡殆類前生事，老態惟思白晝眠。", "明日水邊晴更好，只愁歸思渺秦川。"]'),
('bc7dff1f-03da-4479-8b0f-e36bfd17323d','五日滎陽郡王餉酒','張鎡','宋','宋诗','song-poetry','','[]','閒中滋味諳來慣，懶費心情爲節辰。',64,'全唐诗/poet.song.171000.json','["閒中滋味諳來慣，懶費心情爲節辰。", "丹篆但期詩祟去，紅泥俄見酒壺新。", "移船遣送隨魚信，洗盞開嘗對鶴賓。", "絕勝淵明過重九，東籬空伴白衣人。"]'),
('d9a62f93-2a49-4ff8-830f-83172a5895e2','重五日不飲偶成長句','張鎡','宋','宋诗','song-poetry','','[]','林墅光陰日日新，不因時節强隨人。',64,'全唐诗/poet.song.171000.json','["林墅光陰日日新，不因時節强隨人。", "青紅雨砌戎葵柳，金玉風池荇菜蘋。", "千載是非均似夢，一朝醒醉肯沈身。", "綵絲昌歜喧兒女，誰信清吟興獨真。"]'),
('d776ff68-7608-4f6a-ad4e-48e34e2c3d4b','五月十六日夜南湖觀月','張鎡','宋','宋诗','song-poetry','','[]','良宵觀月豈無人，未必能看到四更。',64,'全唐诗/poet.song.171000.json','["良宵觀月豈無人，未必能看到四更。", "山載塔燈金筆立，水摇亭檻玉簾橫。", "歌從菡萏香中起，酒向玻瓈盞內明。", "誰信南湖當暑夜，葛衣風透覺寒生。"]'),
('e910bc05-95ff-4a00-9478-fac443b73611','對月','張鎡','宋','宋诗','song-poetry','','[]','景奇天遣助詩豪，意快慚無鍊句勞。',64,'全唐诗/poet.song.171000.json','["景奇天遣助詩豪，意快慚無鍊句勞。", "一夜月暉金碗出，萬波風擺玉鱗高。", "衣冠城裏多新貴，酒脯船中自老饕。", "未著叢書追笠澤，此行扶路且遊遨。"]'),
('af0187c9-eb97-4978-a9f3-c8b7d961c8cc','煙波觀觀月示客','張鎡','宋','宋诗','song-poetry','','[]','半年殊少夜間來，湖上今宵絕點埃。',64,'全唐诗/poet.song.171000.json','["半年殊少夜間來，湖上今宵絕點埃。", "人老縱教過百歲，月圓難保看千回。", "舒眉酒飲休辭滿，衝口詩成不待催。", "自有一般堪樂處，却言山水近亭臺。"]'),
('54e84ad1-67b6-4dc9-9d41-0e0beb5f9392','七夕前一夜翠樾堂設醮','張鎡','宋','宋诗','song-poetry','','[]','矯首千尋古杏簷，遠林空處月鈎纖。',64,'全唐诗/poet.song.171000.json','["矯首千尋古杏簷，遠林空處月鈎纖。", "龍蛇藪澤秋聲起，牛女虛空夜氣添。", "滿蕩荷開從北看，危欄塔立向西瞻。", "綠牋封事精忱達，髴鬰天香羽袖沾。"]'),
('eee3a8f7-ddb3-47f8-9b9b-4d787a19cadb','七夕','張鎡','宋','宋诗','song-poetry','','[]','秋近疏飈未轉凉，綵盤珠閣已傳觴。',64,'全唐诗/poet.song.171000.json','["秋近疏飈未轉凉，綵盤珠閣已傳觴。", "佳期天上頻逢節，却老人間未有方。", "蟾魄嫩明情繾綣，鵲河斜界色滄浪。", "瓜盤華錦空兒劇，禱旱于今仰聖皇。"]'),
('e8ea6eeb-b2b8-46ce-9ade-59df40d2e09a','秋暖','張鎡','宋','宋诗','song-poetry','','[]','秋暖渾如水上春，意行幽徑散衣巾。',64,'全唐诗/poet.song.171000.json','["秋暖渾如水上春，意行幽徑散衣巾。", "海棠突過色尤好，荷葉打空芽更新。", "焉得便遭田父飲，不須真現宰官身。", "今朝涉趣初懸榜，爭覩何妨走四隣。"]'),
('98885684-fea0-478e-8243-06bbcbbac37c','秋夜','張鎡','宋','宋诗','song-poetry','','[]','疎星歷歷間銀河，天澹渾疑瀉素波。',64,'全唐诗/poet.song.171000.json','["疎星歷歷間銀河，天澹渾疑瀉素波。", "牆角影低遮月少，樹頭聲壯著風多。", "平生但念長閒好，萬事從教若夢過。", "要足一詩添故藁，小山池畔更婆娑。"]'),
('9b102884-85f5-474c-9dd7-543b4beddcb6','次夜月色復佳遊霞川錦池二首  其一','張鎡','宋','宋诗','song-poetry','','[]','倚欄看月興難平，載酒還須入澗行。',64,'全唐诗/poet.song.171000.json','["倚欄看月興難平，載酒還須入澗行。", "竹頂有時翻鵲翅，草根隨處閙蟲聲。", "城中豈是無人賞，船裏何曾卧地撐。", "遊遍一池心未足，亂荷叢底聽三更。"]'),
('6a529f0c-b3ff-4b87-9755-7e36411088af','次夜月色復佳遊霞川錦池二首  其二','張鎡','宋','宋诗','song-poetry','','[]','畫橋烟重柳垂垂，露濕衣裳透始知。',64,'全唐诗/poet.song.171000.json','["畫橋烟重柳垂垂，露濕衣裳透始知。", "丹桂花香牆畔起，水葓枝影席間移。", "思量究竟都如夢，戀著休閒煞不癡。", "夜半江潮聲正熟，歸來纔是欲眠時。"]'),
('0a6ad4ea-77ef-45a4-ab63-75998479464c','秋聲','張鎡','宋','宋诗','song-poetry','','[]','林居多解識秋聲，豈是松篁耳慣經。',64,'全唐诗/poet.song.171000.json','["林居多解識秋聲，豈是松篁耳慣經。", "桐雜蟬鳴愁易起，蕉和蛩響夢頻醒。", "琅琅急雨喧荷港，戛戛清風戰葦亭。", "一事古人猶可恨，不言楊柳最堪聽。"]'),
('94b6d436-ac8f-4611-a85c-df84bf027aac','秋風','張鎡','宋','宋诗','song-poetry','','[]','策策驚飈戰素秋，夢回衾幔亦颼飀。',64,'全唐诗/poet.song.171000.json','["策策驚飈戰素秋，夢回衾幔亦颼飀。", "不傳鴻雁秦關信，可柰蘋蘅楚客愁。", "作賦未須悲落木，掛帆方喜助歸舟。", "何須更借摶扶便，自是層霄九萬遊。"]'),
('4f827e94-9794-4151-bf4d-0f59cbaa9284','贈鴈','張鎡','宋','宋诗','song-poetry','','[]','我自江鄉有姓名，相逢契合義相親。',64,'全唐诗/poet.song.171000.json','["我自江鄉有姓名，相逢契合義相親。", "連行幾宿來棲草，戢翼常時想避人。", "石岸風高難到縣，今宵船住定爲鄰。", "南湖若肯尋幽隠，却把衷腸自縷陳。"]'),
('7645896f-c707-4089-83cb-ff7666b749a2','重九前一日領客登城即席次張以道韻','張鎡','宋','宋诗','song-poetry','','[]','未倒花前鑿落金，登携那怕嫩寒侵。',64,'全唐诗/poet.song.171000.json','["未倒花前鑿落金，登携那怕嫩寒侵。", "歸牛下隴爭浮水，宿鳥隨山不過林。", "衰鬢預吹明日帽，放歌時带故園音。", "菊烟桂露雖情物，須索高蟾管夜深。"]'),
('dc5e249a-0454-4e34-b794-a6d925d99ea2','冬日','張鎡','宋','宋诗','song-poetry','','[]','半空飛雨整還斜，翳日遊雲散復遮。',64,'全唐诗/poet.song.171000.json','["半空飛雨整還斜，翳日遊雲散復遮。", "七字吟情書柿葉，一年心事約梅花。", "關門人識陶潛室，靜坐自疑龐藴家。", "紙帳蒲龕方用事，更須何物作生涯。"]'),
('b7733eb0-c3e2-46d7-aa5c-676c6b6d08db','十月菊','張鎡','宋','宋诗','song-poetry','','[]','幽芳何事獨開遲，寂寞寒金照短籬。',64,'全唐诗/poet.song.171000.json','["幽芳何事獨開遲，寂寞寒金照短籬。", "老子樽罍方欠此，春風景物最相宜。", "要隨得暖南枝發，肯趁登高九日悲。", "翻笑陶家門外柳，夜深零落舞腰肢。"]'),
('10b4116d-120d-401f-8103-90b9292accae','冬至日曉雪庭桂一枝著花戲成長句','張鎡','宋','宋诗','song-poetry','','[]','居士歸來百事嘉，木樨雪裏也開花。',64,'全唐诗/poet.song.171000.json','["居士歸來百事嘉，木樨雪裏也開花。", "麩金一掬枝頭小，藥玉千溝屋上斜。", "境界許奇非浪得，色香俱靜更何加。", "高寒似我休拈出，微笑從來少作家。"]'),
('71160274-a7b2-4779-ab5f-241db8007d32','侵晨飛霰薄暮雪未成','張鎡','宋','宋诗','song-poetry','','[]','呃喔花冠夢易呼，凍天應遍色模糊。',64,'全唐诗/poet.song.171000.json','["呃喔花冠夢易呼，凍天應遍色模糊。", "旋聽索索敲松瓦，便擬翩翩傍酒觚。", "一白要從高砌看，雙清先喜小山俱。", "晚簷坐斷違消息，待問林深寺有無。"]'),
('f59f4302-fa96-4315-a2d1-b13abc140d41','園中梅有開者寄呈當塗叔祖','張鎡','宋','宋诗','song-poetry','','[]','春到林梅得重權，首冬疎萼已爭先。',64,'全唐诗/poet.song.171000.json','["春到林梅得重權，首冬疎萼已爭先。", "移栽尚記陪深斝，靜看因思覓近篇。", "佐世勳庸金鼎味，貪閒懷抱竹籬烟。", "臨風欲寄橫斜去，夢繞江城暮角邊。"]'),
('2fe52ed0-d11b-4825-9703-cff9cda799ca','昨探梅冒寒伏枕病起聞花已開尚苦雨阻因成長句','張鎡','宋','宋诗','song-poetry','','[]','小園春事果如何，分數梅花最占多。',64,'全唐诗/poet.song.171000.json','["小園春事果如何，分數梅花最占多。", "貪看滿梢初的皪，病妨連日繞婆娑。", "鳩聲喚雨風還至，鶴骨棲愁夢獨過。", "豔陣香天翻霽色，明早拚取醉顔酡。"]'),
('338dfddb-6770-45fb-b97d-db4c239a8fab','寓舍聽雨憶園中梅花','張鎡','宋','宋诗','song-poetry','','[]','陰霏非是妬春華，薄命詩人带累花。',64,'全唐诗/poet.song.171000.json','["陰霏非是妬春華，薄命詩人带累花。", "烟逼艷低侵竹冷，風攔香橫逐溪斜。", "開時數日曾邀客，別後連旬阻到家。", "簷溜可堪聲徹曉，夢中餘恨亦無涯。"]'),
('ea739232-2103-4dd0-9c78-a1c7a33976cb','曉探晴觀梅','張鎡','宋','宋诗','song-poetry','','[]','天雞催日界窗橫，躡屐看花興便成。',64,'全唐诗/poet.song.171000.json','["天雞催日界窗橫，躡屐看花興便成。", "正爾飛霞舒綵珮，儘渠宿雨結珠纓。", "飄零未带溪邊笛，縹緲如臨海上城。", "身世長吟誰會得，華祠梅市總逃名。"]'),
('1dc39e1d-0643-4d2a-8841-6b447a7d50f7','次韻周昭禮見寄兼約觀園梅','張鎡','宋','宋诗','song-poetry','','[]','沙頭晴了便回春，已覺青蘋媚暖津。',64,'全唐诗/poet.song.171000.json','["沙頭晴了便回春，已覺青蘋媚暖津。", "但課澆畦園內叟，何心說劍里中人。", "超情耐久寧拘遠，合處無多頗復伸。", "待得梅開醉香海，健呼重看老精神。"]'),
('c62f136e-3b6a-4716-88f0-1c946dec7ab7','約齋西窗先有垂柳臘後四日闢地增植花數十輩','張鎡','宋','宋诗','song-poetry','','[]','經年規畫種酴醿，柳際春將一再歸。',64,'全唐诗/poet.song.171000.json','["經年規畫種酴醿，柳際春將一再歸。", "蔓草藩牆纔放遠，海棠桃杏得成圍。", "連宵冷月知予樂，數日條風挾鳥飛。", "盡寫前人題品句，誦聲時撼綠窗扉。"]'),
('db96e965-505c-4b82-b4f8-16ee2c15c0c8','雪','張鎡','宋','宋诗','song-poetry','','[]','闔夜驚飈落樹巢，平明溝瓦漸迷坳。',64,'全唐诗/poet.song.171000.json','["闔夜驚飈落樹巢，平明溝瓦漸迷坳。", "鍪函靜聽來千騎，珪璧遥知委四郊。", "再白呈祥矜大稔，積陰噓氣遏方苞。", "池邊廢沼邀閒立，乍合冰澌怯杖敲。"]'),
('44d0cfa5-4dba-49f4-9ccd-9c0a7efdc881','雪晴希稷次韻再賦爲答','張鎡','宋','宋诗','song-poetry','','[]','凍枿歸禽易辨巢，燭龍分燿入堂坳。',64,'全唐诗/poet.song.171000.json','["凍枿歸禽易辨巢，燭龍分燿入堂坳。", "長須喜戒鋤荒圃，小隊閒思獵近郊。", "坐許剛筠全直節，行看弱柳發新苞。", "僧爐遥想煨松柮，犬逐應門認客敲。"]'),
('1152b7f0-ce62-431c-97e7-bf15fa22a3c0','丙午十二月晦日雪霽','張鎡','宋','宋诗','song-poetry','','[]','曉愛晴暉萬瓦融，近山春意便葱蘢。',64,'全唐诗/poet.song.171000.json','["曉愛晴暉萬瓦融，近山春意便葱蘢。", "敲冰踏雪三旬裏，送臘迎年此夜中。", "仁政果能銷運厄，閒家何幸樂時豐。", "明朝掃徑看桃柳，要識天公兩樣風。"]'),
('0b882e62-4beb-4301-a8bf-53b193e9a87e','守歲','張鎡','宋','宋诗','song-poetry','','[]','寒缸孤照聽更遲，情緒斟量睡却宜。',64,'全唐诗/poet.song.171000.json','["寒缸孤照聽更遲，情緒斟量睡却宜。", "春向歲前三日到，老緣頭上二毛知。", "朱泥逐疫燒靈藥，桃板書符換舊詩。", "但願明年更閒散，無災無難復何疑。"]'),
('d88d4cfc-673f-4b85-82f7-3036d3bb3fc3','夕霽','張鎡','宋','宋诗','song-poetry','','[]','霜雪連朝作勁威，暮來吹散景偏宜。',64,'全唐诗/poet.song.171000.json','["霜雪連朝作勁威，暮來吹散景偏宜。", "未開璧月千秋鏡，已建金雲十丈旗。", "脫帽漸看山峍屼，襲裘須判酒淋漓。", "乘閒書紙休嫌數，簿領叢中怕說詩。"]'),
('f858c3f2-8485-400e-87ae-3240d766f907','春分後一日山堂述事  其一','張鎡','宋','宋诗','song-poetry','','[]','永日柴扉手自關，不驚時序若循環。',64,'全唐诗/poet.song.171000.json','["永日柴扉手自關，不驚時序若循環。", "鍊成黄土爲真藥，守得青苔遍假山。", "戊己燕知隨鳥歷，西南櫻喜趁花斑。", "春光莫恨中分過，能使時長始是閒。"]'),
('6304709b-649a-4a13-b844-d4b5f6d4396e','春分後一日山堂述事  其二','張鎡','宋','宋诗','song-poetry','','[]','每到山堂懶作詩，今朝詩興覺偏宜。',64,'全唐诗/poet.song.171000.json','["每到山堂懶作詩，今朝詩興覺偏宜。", "層林颯還陰填戶，亂石巃嵷翠繞池。", "猛欲近前聞紫燕，忽聽高處囀黄鸝。", "風鈴不必簷間語，境界非凡我熟知。"]'),
('f4164007-1e5f-4ddb-b0ed-ed129ac6b330','春分後一日山堂述事  其三','張鎡','宋','宋诗','song-poetry','','[]','老圃工夫愈可嘉，種藤縈樹盡開花。',64,'全唐诗/poet.song.171000.json','["老圃工夫愈可嘉，種藤縈樹盡開花。", "人間似我能閒少，石上看雲到日斜。", "樵徑有苔休埽葉，茅菴無客亦煎茶。", "兩邊最喜添新竹，夕照斜時漸可遮。"]'),
('e18fee2d-129a-4d36-9581-9af382cfdff5','春分後一日山堂述事  其四','張鎡','宋','宋诗','song-poetry','','[]','巖通道院碧桃妍，別號琅華小洞天。',64,'全唐诗/poet.song.171000.json','["巖通道院碧桃妍，別號琅華小洞天。", "香火微官方稱職，軒裳閒夢自無緣。", "星壇夜禮魁罡列，丹室朝存震兌全。", "絕粒飛昇休漫語，不求人已是神仙。"]'),
('734716c5-9b51-4b9b-a585-e3aa3826f3e5','閒課','張鎡','宋','宋诗','song-poetry','','[]','居閒投課熟爲優，似此工夫盡不愁。',64,'全唐诗/poet.song.171000.json','["居閒投課熟爲優，似此工夫盡不愁。", "量澗打船輕似盞，轉牆開逕曲如鈎。", "已令山圃收黄犢，又蓋湖亭記白鷗。", "春水畫橋桃四百，新年那羨武陵遊。"]'),
('e4b7a874-f7e6-474f-95ad-3c3d1dfa3767','自詠','張鎡','宋','宋诗','song-poetry','','[]','南湖老子太汗漫，第一生來懶做官。',64,'全唐诗/poet.song.171000.json','["南湖老子太汗漫，第一生來懶做官。", "錢物用多常是解，權門路便不曾鑽。", "紅裙遣去如僧榻，白髮梳來稱道冠。", "若沒祖財教飯飽，定應餓作壁魚乾。"]'),
('8f885523-6a98-400f-b1ff-33f6b6d1a755','自嘆','張鎡','宋','宋诗','song-poetry','','[]','居士年來更覺癡，竹梢雲過望移時。',64,'全唐诗/poet.song.171000.json','["居士年來更覺癡，竹梢雲過望移時。", "曉窗倦櫛猶思夢，夜榻忘眠尚改詩。", "匹馬未能隨李廣，一丘端欲效元規。", "客談休訝無心對，貪看蜘蛛結網絲。"]'),
('d0474221-23d2-40b0-ae6d-2ed21b17aeeb','山堂晚興','張鎡','宋','宋诗','song-poetry','','[]','小堂清占景無譁，不向階前種俗花。',64,'全唐诗/poet.song.171000.json','["小堂清占景無譁，不向階前種俗花。", "過雨家茶脫黄玉，近霜天竹綴丹沙。", "靜眠寧羨蟻來夢，孤坐屢諳蜂報衛。", "萬事一身安分定，關河休用發長嗟。"]'),
('49a357cb-14f2-443e-bd3c-98893eceec39','園中晚興','張鎡','宋','宋诗','song-poetry','','[]','滿襟斜日澹如秋，烟竹湘花結暮愁。',64,'全唐诗/poet.song.171000.json','["滿襟斜日澹如秋，烟竹湘花結暮愁。", "幾樹蟬清新抱葉，一灣魚樂舊忘鈎。", "蔬盤飽去山家飯，楚調吹來水園謳。", "此事不教千載識，苦諧時輩祗貽羞。"]'),
('4cc0840e-bb44-49d3-9c45-5e2ddb55ea9c','竹軒詩興','張鎡','宋','宋诗','song-poetry','','[]','柴門風捲却吹開，陿徑初成竹旋栽。',64,'全唐诗/poet.song.171000.json','["柴門風捲却吹開，陿徑初成竹旋栽。", "梢影細從茶椀入，葉聲輕逐篆烟來。", "暑天倦卧星穿透，冬晝閒吟雪壓摧。", "預想此時應更好，莫移牆下一株梅。"]'),
('cbc997cd-749f-44db-a99a-9723f7586c87','偶書  其一','張鎡','宋','宋诗','song-poetry','','[]','移居桂隠詩全少，半爲支離半爲慵。',64,'全唐诗/poet.song.171000.json','["移居桂隠詩全少，半爲支離半爲慵。", "今日一盃纔引興，便成七字不求工。", "鶴來池畔閒尋水，蟬在松梢快語風。", "門外車塵紅似火，喚渠不應囁嚅翁。"]'),
('882029f9-f6fb-4204-9c78-dd4ac24efa3b','偶書  其二','張鎡','宋','宋诗','song-poetry','','[]','花柳無情浪占春，浴鵝波暖草方熏。',64,'全唐诗/poet.song.171000.json','["花柳無情浪占春，浴鵝波暖草方熏。", "催畊野曠鳴黄犢，瞰客籬疎立茜裙。", "拚睡工夫便日永，得閒滋味苦愁分。", "行行快趁風煙閣，蓴鱠詩壇要策勳。"]'),
('cc236b1a-a3c4-43ca-a777-f63e2373efbd','偶書  其三','張鎡','宋','宋诗','song-poetry','','[]','清曉啁啾響衆禽，共忻暄色上穹林。',64,'全唐诗/poet.song.171000.json','["清曉啁啾響衆禽，共忻暄色上穹林。", "已如料峭春初景，不作蕭條歲暮心。", "堆徑尚看桐葉在，遶籬那顧菊叢深。", "秦正嘉月將何祝，長壽新芽當酒斟。"]'),
('46fc8679-797c-4acb-8122-4b0c847a56a6','偶書  其四','張鎡','宋','宋诗','song-poetry','','[]','野水因晴自少文，淡雲當晝不容昏。',64,'全唐诗/poet.song.171000.json','["野水因晴自少文，淡雲當晝不容昏。", "夾泥船小纔通港，洗菜人歸定入村。", "布穀飛鳴隨燕去，舂鋤俛啄得魚吞。", "春風有得詩如許，妙處從來復細論。"]'),
('b4879a1b-7ded-4bac-aba1-1af6220fad73','客有折秋香來桂隠者喜成七言呈以道','張鎡','宋','宋诗','song-poetry','','[]','半紀移居野水旁，年年嘗爲木樨忙。',64,'全唐诗/poet.song.171000.json','["半紀移居野水旁，年年嘗爲木樨忙。", "若非老樹從頭發，安得西風徹骨香。", "數朶折來猶甚愛，滿林開後得無狂。", "今番莫把尋常比，一段清香兩主張。"]'),
('e6e16f59-8704-46c8-a2c3-6e277cbd63d7','南湖書齋','張鎡','宋','宋诗','song-poetry','','[]','雨深愁入樹花飄，盡際翻晴現帝霄。',64,'全唐诗/poet.song.171000.json','["雨深愁入樹花飄，盡際翻晴現帝霄。", "目力壯時蒼岫長，心情閒處戲魚跳。", "秋雲總是詩家物，夜市今連里陌橋。", "船子不來同載我，却驚翡翠出蘭苕。"]'),
('31638326-b612-4511-89d3-c4ea98172768','題尚友軒','張鎡','宋','宋诗','song-poetry','','[]','作者無如八老詩，古今模軌更求誰。',64,'全唐诗/poet.song.171000.json','["作者無如八老詩，古今模軌更求誰。", "淵明次及寒山子，太白還同杜拾遺。", "白傅東坡俱可法，涪翁無己總堪師。", "胸中活底仍須悟，若泥陳言却是癡。"]'),
('10357002-2104-40cc-a00b-185d60de0727','次韻叔祖閣學秋興','張鎡','宋','宋诗','song-poetry','','[]','歲序推流感世浮，樂閒宜早向農疇。',64,'全唐诗/poet.song.171000.json','["歲序推流感世浮，樂閒宜早向農疇。", "修梧綠減俄過夏，短髮絲添剝得秋。", "千古是非歸嘯傲，一門酬唱勝交遊。", "祗因名句多難數，常笑區區趙倚樓。"]'),
('bc97d30c-7ca5-4879-934e-855bbea5c6e0','桂隠花正開得誠齋木樨七言次韻奉酬','張鎡','宋','宋诗','song-poetry','','[]','未說香高衆卉林，清名先已入人深。',64,'全唐诗/poet.song.171000.json','["未說香高衆卉林，清名先已入人深。", "衣青萼綠不見珮，屋貯阿嬌純用金。", "久恨酒腸慳似琖，更輸詩字響如砧。", "公能爲辦歸休計，肯向花前嘆陸沉。"]'),
('4b35206a-32a8-4190-b017-ce9f8b303686','誠齋再韵見遺走筆復和并邀尤檢正京右司觀花','張鎡','宋','宋诗','song-poetry','','[]','要趁清霜未染林，小山同賞桂叢深。',64,'全唐诗/poet.song.171000.json','["要趁清霜未染林，小山同賞桂叢深。", "已拚醉後纏頭錦，莫待風前布地金。", "蘭槳遡流歌客櫂，麝材勻搗付香砧。", "戈揮就借如椽筆，不信湖邊日易沉。"]'),
('dcd13a18-1ff6-49db-bb53-7670ac4ca0ec','誠齋三用韻因更和呈以堅顧臨之約','張鎡','宋','宋诗','song-poetry','','[]','不比先賢傲竹林，鳴騶許過徑蓬深。',64,'全唐诗/poet.song.171000.json','["不比先賢傲竹林，鳴騶許過徑蓬深。", "瑰詞走送驚聯璧，鈍思追酬漫注金。", "巖底幽人矜社甕，閨中幼婦感秋砧。", "何如醉袖淋漓墨，一笑人間百慮沉。"]'),
('0143dbf5-f33b-4d66-90d4-b68fcd838302','尤丈京丈和篇沓至四用前韻爲謝','張鎡','宋','宋诗','song-poetry','','[]','江南從識桂花林，歲歲逢秋屬意深。',64,'全唐诗/poet.song.171000.json','["江南從識桂花林，歲歲逢秋屬意深。", "夜氣未添承露掌，曉光先上辟寒金。", "玉笙殿迥應留月，鐵杵巖高不用砧。", "爭似吾家種流水，擁香亭榭綠沉沉。"]'),
('dda75366-9d32-429d-b047-9c850ae89544','五用前韻詠丹桂花','張鎡','宋','宋诗','song-poetry','','[]','遍看韶淑萬花林，誰似秋風巧力深。',64,'全唐诗/poet.song.171000.json','["遍看韶淑萬花林，誰似秋風巧力深。", "點注紅泥千日酒，剪裁紫磨十分金。", "色迷仙令疑勾漏，香醉姮娥忘藁砧。", "莫把釣竿烟外去，珊瑚休道海中沉。"]'),
('5731e88e-ab7c-4f7e-a642-8113a5e911e2','安溪山間尋桂得之','張鎡','宋','宋诗','song-poetry','','[]','心期經歲只秋芳，况有溪山近好凉。',64,'全唐诗/poet.song.171000.json','["心期經歲只秋芳，况有溪山近好凉。", "天宇蕩開暄濁意，巖花催就泬寥香。", "招尋擬把深枝折，愛護休令背蕊傷。", "三五冰輪行散影，仙凡同異要平章。"]'),
('355e003e-dcc9-4d69-a54c-0c6319687a31','晚步池上','張鎡','宋','宋诗','song-poetry','','[]','藤杖徐穿竹徑凉，地寬那更水雲鄉。',64,'全唐诗/poet.song.171000.json','["藤杖徐穿竹徑凉，地寬那更水雲鄉。", "山明屋背髻鬟聳，蟬奏樹頭絲吹長。", "蓑笠釣船家自有，軒裳朝路夢俱忘。", "英雄本志今朝得，十畝香荷著醉狂。"]'),
('a9795533-e61f-4da7-8555-058e1813ff81','納凉至夜深','張鎡','宋','宋诗','song-poetry','','[]','積潦斜陽忽射階，夜深穿樹雨還來。',64,'全唐诗/poet.song.171000.json','["積潦斜陽忽射階，夜深穿樹雨還來。", "披襟徑放清凉入，倚扇微教嬾困催。", "出草亂螢時自照，叫空孤鳥暗飛回。", "貪吟四鼓猶妨寢，除此人間念總灰。"]'),
('02bb2d61-85f1-4024-a11b-a32cdd1a0bb6','遊石湖','張鎡','宋','宋诗','song-poetry','','[]','幾年飛夢越來城，試扣柴荆恰快晴。',64,'全唐诗/poet.song.171000.json','["幾年飛夢越來城，試扣柴荆恰快晴。", "松菊正酬閒客意，烟波真似主人情。", "黑頭據要方行志，綠野當年浪得名。", "我亦鄰鄉植桑柘，訪公非爲憶蓴羹。"]'),
('a0161b68-76cb-4f97-85c2-a07c274eac0b','泛湖','張鎡','宋','宋诗','song-poetry','','[]','駮雲飛去見晴嵐，疊巘平湖影共涵。',64,'全唐诗/poet.song.171000.json','["駮雲飛去見晴嵐，疊巘平湖影共涵。", "景與新詩爭上下，天將真賞冠東南。", "頻來但覺如初到，得侶何妨縱劇談。", "歸路一彎明月好，閙花風裏躍華驂。"]'),
('324945a7-2d30-45f8-b782-417f8f4bd44c','曲廊','張鎡','宋','宋诗','song-poetry','','[]','曲廊桐樹綠陰陰，簷珮風來奏玉琴。',64,'全唐诗/poet.song.171000.json','["曲廊桐樹綠陰陰，簷珮風來奏玉琴。", "但有疎簾知獨立，更無塵事惱閒心。", "雪霜鬢畔誰能免，城府胸中枉自深。", "二六時辰真快樂，坐禪纔罷即行吟。"]'),
('d808d7d8-941c-433e-af6e-60b7ac48dce9','自橫山歸偶成','張鎡','宋','宋诗','song-poetry','','[]','杖藜如向碧空行，路轉松杉面面聲。',64,'全唐诗/poet.song.171000.json','["杖藜如向碧空行，路轉松杉面面聲。", "遺廟香殘人少到，古臺仙去草閒生。", "都緣世念多時絕，不但塵襟逐境清。", "却上小輿歸寓舍，晚峰明暗紫烟橫。"]'),
('5b20b81f-207e-4738-88ef-128f852378a4','秋日登集仙臺','張鎡','宋','宋诗','song-poetry','','[]','地荒無處可追遊，頼有茲山景頗幽。',64,'全唐诗/poet.song.171000.json','["地荒無處可追遊，頼有茲山景頗幽。", "遠水一隅橫雪練，喬松千丈舞雲虬。", "飄颻霞想生來僻，膠擾塵心老更休。", "不向是中觀月去，城中那可度中秋。"]'),
('20a17412-df8e-400a-8d4d-4caaf40f27c2','聖井亭','張鎡','宋','宋诗','song-poetry','','[]','重到虛亭意豁然，望高容易覺秋天。',64,'全唐诗/poet.song.171000.json','["重到虛亭意豁然，望高容易覺秋天。", "山邊曠野全無水，樹雜輕煙間有田。", "極目幾時忘去路，西風何日送歸船。", "殘蟬更喚斜陽好，襯出金剛翠篠邊。"]'),
('8a1eaad1-c141-4315-911d-133bd9e33aac','離城中','張鎡','宋','宋诗','song-poetry','','[]','雨後溪流爾許深，枕堤樓閣靜沉沉。',64,'全唐诗/poet.song.171000.json','["雨後溪流爾許深，枕堤樓閣靜沉沉。", "暫來殊鬰登臨恨，欲別難禁去住心。", "倚檻乍離橋百尺，繫船猶戀柳千尋。", "黄昏最喜林端月，影掠波寒徹底金。"]'),
('318c5e49-3086-409f-ab64-7eec57b83380','野芳亭寫望','張鎡','宋','宋诗','song-poetry','','[]','晚雨凄微葉未斑，小亭非但揖西山。',64,'全唐诗/poet.song.171000.json','["晚雨凄微葉未斑，小亭非但揖西山。", "船行半出青蒲末，塔立參排雜樹間。", "了事兒癡妨劇醉，澹陰天氣合清閒。", "幽居不與紅塵隔，退食何能一往還。"]'),
('89ffe852-de03-4633-ad17-9af6075ddc8a','汎錦池霞川呈張以道二首  其一','張鎡','宋','宋诗','song-poetry','','[]','夕風輕颺一池香，遥爲荷花泛短航。',64,'全唐诗/poet.song.171000.json','["夕風輕颺一池香，遥爲荷花泛短航。", "俗子幾曾貪韻勝，閒人贏得放清狂。", "幽棲野鶴林松黑，亂撲流螢水葉凉。", "會取渭川當日意，不將終老俟周王。"]'),
('2ab789bb-2d00-4444-906e-668930e95e1f','汎錦池霞川呈張以道二首  其二','張鎡','宋','宋诗','song-poetry','','[]','戲選嬋娟結伴來，畫橋低處側鸞釵。',64,'全唐诗/poet.song.171000.json','["戲選嬋娟結伴來，畫橋低處側鸞釵。", "媧簧靜試醒鬆響，魯酒聊傾曠蕩懷。", "萬事亦須從使便，百年無過任天排。", "憐君近許同心友，分取湖光到竹齋。"]'),
('fdf54d60-62cf-49a0-82f0-7d5b09de9c51','以道次韻因再和二首  其一','張鎡','宋','宋诗','song-poetry','','[]','秋林何翅一般香，楚思無窮屬野航。',64,'全唐诗/poet.song.171000.json','["秋林何翅一般香，楚思無窮屬野航。", "不必再參龐老語，要須先會接輿狂。", "青燈漸向韋編熟，白露初添玉井凉。", "久矣蕩除人我相，莫疑高尚鄙侯王。"]'),
('57b9f88d-4684-453b-accc-ed2342942a9e','以道次韻因再和二首  其二','張鎡','宋','宋诗','song-poetry','','[]','頃年尋地喜初來，牆下松飄滿逕釵。',64,'全唐诗/poet.song.171000.json','["頃年尋地喜初來，牆下松飄滿逕釵。", "屈指五經寒暑候，教人一掃利榮懷。", "南湖又共詩翁住，東寺須連單位排。", "觸景未嘗瞞昧得，肯從顔氏學心齋。"]'),
('eec63325-6337-4d16-8831-9211219d15a6','蒲龕','張鎡','宋','宋诗','song-poetry','','[]','紛華嘗遍氣豪粗，未到衰年一點無。',64,'全唐诗/poet.song.171000.json','["紛華嘗遍氣豪粗，未到衰年一點無。", "行幛不施機上錦，坐龕祇葺水中蒲。", "斜斜策杖隨椶屨，寂寂聞香對瓦鑪。", "若昧那伽常在定，結跏徒費鈍工夫。"]'),
('eb379972-31fe-414a-a8d3-9c4c9b6ed4c5','雨中約梅再賦','張鎡','宋','宋诗','song-poetry','','[]','寄語堂前萬玉枝，未須開盡等人歸。',64,'全唐诗/poet.song.171000.json','["寄語堂前萬玉枝，未須開盡等人歸。", "行雲佩雜衣從濕，濺水裙輕步自微。", "關塞垂楊橫槊賦，禁津芳草掞毫揮。", "爲君豈復仍關念，看到清陰碧實肥。"]'),
('bd7ed80f-a2f5-48b9-bdb6-199ae536568e','寒堂夢松','張鎡','宋','宋诗','song-poetry','','[]','堂成初喜豢髯龍，肯夢當年十八公。',64,'全唐诗/poet.song.171000.json','["堂成初喜豢髯龍，肯夢當年十八公。", "寶樹未穿煙際雪，鈞天先聽日邊風。", "成丹得所從春首，棲鵠無聲過夜中。", "誰遣牆陰接芝徑，月晴應是費拖筇。"]'),
('e6f291fd-49eb-4349-baac-8ad27ee46eed','蒼寒堂','張鎡','宋','宋诗','song-poetry','','[]','短橋斜路入松林，何止能銷利欲心。',64,'全唐诗/poet.song.171000.json','["短橋斜路入松林，何止能銷利欲心。", "眼悟一真清浄色，耳通千古泰和音。", "尺量梢影邀僧記，竹護根莖恐鶴侵。", "莫訝塼爐多宿火，春晴猶似處雲深。"]'),
('36a53802-886f-45c7-851d-b68daef11c0c','約周希稷遊湖上園','張鎡','宋','宋诗','song-poetry','','[]','句法參同李翰林，風流依約謝宣城。',64,'全唐诗/poet.song.171000.json','["句法參同李翰林，風流依約謝宣城。", "放懷應喜醉三日，聽曲知無誤一聲。", "箬葉露方高石室，桂枝香譜度銀笙。", "西清東觀遲歸去，相就盤跚勃窣行。"]'),
('bf0a9c13-35e2-4305-99af-47f29f3b1542','夜自叔祖北園歸','張鎡','宋','宋诗','song-poetry','','[]','夕靄生凉竹徑迂，快風吹馬出通衢。',64,'全唐诗/poet.song.171000.json','["夕靄生凉竹徑迂，快風吹馬出通衢。", "疎星落落連城闕，擊鼓闐闐雜笑呼。", "竟日浪追河朔飲，幾時真在輞川圖。", "歸來小憩松棚下，繞燭飛蟲索扇驅。"]'),
('092e671b-8ee4-4fd3-9f23-dc1407759ca6','出寂照行至書館','張鎡','宋','宋诗','song-poetry','','[]','茅屋雞聲過日中，熱雲蒸雨轉無風。',64,'全唐诗/poet.song.171000.json','["茅屋雞聲過日中，熱雲蒸雨轉無風。", "形勞自背當年說，句快全誇近日工。", "破院未成投宿計，枯田猶覬入秋豐。", "情知必沒揚雄宅，看竹何妨揖主翁。"]'),
('72c426ee-b0e2-4a99-99ca-a609eded1664','清夏堂','張鎡','宋','宋诗','song-poetry','','[]','去歲臨池未蓋堂，暑天來看已多凉。',64,'全唐诗/poet.song.171000.json','["去歲臨池未蓋堂，暑天來看已多凉。", "穿花鷺立青爲繖，放櫂人眠錦作床。", "今夏好風簾影動，良宵閒坐月華香。", "低頭笑向闌干說，有汝詩中味更長。"]'),
('8b8e4fbf-c53e-4ac0-98e6-4e066174090d','碧宇書興','張鎡','宋','宋诗','song-poetry','','[]','非關鄙性泥林泉，境熟由來意自便。',64,'全唐诗/poet.song.171000.json','["非關鄙性泥林泉，境熟由來意自便。", "童子靜看煎藥竈，鷺鷥閒上釣魚船。", "隈叢野石雲蒸黑，带雨堤花錦壓偏。", "辦取一生無別事，饑時喫飯困時眠。"]'),
('2a43502f-b845-4cb5-9421-bc2e6681f24c','卧疾連日殊無聊頼客有送二省闈試題者因成四韻','張鎡','宋','宋诗','song-poetry','','[]','春恨都緣少得晴，雨聲渾是落梅聲。',64,'全唐诗/poet.song.171000.json','["春恨都緣少得晴，雨聲渾是落梅聲。", "新愁多病易投隙，薄命壯懷難抗衡。", "人世只宜常放逸，杏花多愛逼清明。", "青袍白紵紛然夢，自笑生來入念輕。"]'),
('e1cf2e2c-406d-4128-9257-dbf5fb18fd18','述興','張鎡','宋','宋诗','song-poetry','','[]','履聲幾月到園稀，雪後煙香特地宜。',64,'全唐诗/poet.song.171000.json','["履聲幾月到園稀，雪後煙香特地宜。", "已見新晴巢喜鵲，更添垂柳客黄鸝。", "人來有話亦大好，酒不酬春奚以爲。", "今日正晴休怕冷，笑中天地角巾欹。"]'),
('a21b6204-2d17-4d90-8c53-33d240eb3fc2','睡起述興','張鎡','宋','宋诗','song-poetry','','[]','功用今年百倍加，圃中添就好生涯。',64,'全唐诗/poet.song.171000.json','["功用今年百倍加，圃中添就好生涯。", "大於榿樹夜合樹，肥似桃花巴欖花。", "煮酒未嘗先問日，裌衣初製漸裁紗。", "起來不是貪眠在，齋後僧憐未瀹茶。"]'),
('0fa87824-492a-4a5b-a7ba-c77d7dfa938f','自料','張鎡','宋','宋诗','song-poetry','','[]','自料躬耕體力微，他年爲圃雅相宜。',64,'全唐诗/poet.song.171000.json','["自料躬耕體力微，他年爲圃雅相宜。", "植茶要是依桑蔭，種芋先須納豆萁。", "藥愛金櫻長林薄，花因木槿作藩籬。", "祗應分絕陶朱富，不願魚繁六畝池。"]'),
('c9f66dd3-552b-41e0-aa9b-d5bc1614aea4','遣興','張鎡','宋','宋诗','song-poetry','','[]','笛簟疎明壓砌窗，重陰經日閉脩廊。',64,'全唐诗/poet.song.171000.json','["笛簟疎明壓砌窗，重陰經日閉脩廊。", "黄梅未長先愁雨，翠樹將成擬納凉。", "藏袖好書多便看，伏瓶生酒漸堪嘗。", "誰能自縛無涯事，早辦風漪百畝塘。"]'),
('affa0bac-5021-4b3d-87b0-efa8704244d2','晝寒一杯輒欲酩酊因靜坐道室','張鎡','宋','宋诗','song-poetry','','[]','歲晏常多白晝陰，軟簾氈帳禦寒侵。',64,'全唐诗/poet.song.171000.json','["歲晏常多白晝陰，軟簾氈帳禦寒侵。", "觀書偶要得天隠，作傳定難題醉吟。", "犬吠遠聞風綽散，葉凋誰顧雨堆深。", "湖邊莫道春回未，紫草依稀動絕岑。"]'),
('41bff0a7-16da-4bef-ae7b-52c078a1b5d9','曉寢喜成','張鎡','宋','宋诗','song-poetry','','[]','人間一事最幽奇，病醉皆非半睡時。',64,'全唐诗/poet.song.171000.json','["人間一事最幽奇，病醉皆非半睡時。", "經紙屏低心正愜，木綿衾暖足慵移。", "蘧蘧蝶夢縈孤枕，呃呃雞聲過短籬。", "無奈衝寒早朝客，不知疎拙是便宜。"]'),
('af24bd02-fca7-4e0c-b4e6-4e2a6e85dee9','戲題','張鎡','宋','宋诗','song-poetry','','[]','人前一語撞翻牆，直氣西秦本故鄉。',64,'全唐诗/poet.song.171000.json','["人前一語撞翻牆，直氣西秦本故鄉。", "雪野射麋輕隊馬，杏園移象矮交床。", "詩忙渴硯酒磨墨，睡足趄廊花奪香。", "矯揉盡歸官樣去，有時閒笑錯商量。"]'),
('becc9579-3852-40a2-9624-03f2b59d3f0f','改舊詩戲成','張鎡','宋','宋诗','song-poetry','','[]','不作新詩只改詩，當家功用亦幾希。',64,'全唐诗/poet.song.171000.json','["不作新詩只改詩，當家功用亦幾希。", "全牛迎刃未能解，六鶂遇風先退飛。", "欲脫規模還似舊，枉教軀幹不曾肥。", "何如盡付紅爐火，免使羣公說是非。"]'),
('1422e393-8b7a-4c08-be51-e6a0653f2479','次韻張唐卿','張鎡','宋','宋诗','song-poetry','','[]','邇來衰鬢漸當箝，杖策投繻感壯年。',64,'全唐诗/poet.song.171000.json','["邇來衰鬢漸當箝，杖策投繻感壯年。", "得失暮三朝必四，才能人百己難千。", "顧形真是臞仙薄，琢句何堪大手聯。", "紈袴紛紛能索我，勞君眼力世情邊。"]'),
('bd2d1b3b-e992-4742-aa54-1447889199db','次韻酬唐老見贈','張鎡','宋','宋诗','song-poetry','','[]','菊邊莎處坦平居，危逕吾知勉覆車。',64,'全唐诗/poet.song.171000.json','["菊邊莎處坦平居，危逕吾知勉覆車。", "爭似即時三盞酒，何曾得力半行書。", "魚鄉坐占真清矣，蜂戶行看亦宴如。", "過我不疎君始信，向來猶恐壓荒墟。"]'),
('161bc7e2-2415-4fc6-9ae8-f29065935da8','次韻譚德春見寄','張鎡','宋','宋诗','song-poetry','','[]','端的公宜語箇中，對山縈碧照清冬。',64,'全唐诗/poet.song.171000.json','["端的公宜語箇中，對山縈碧照清冬。", "鶴毛雨漬苔錢古，蟻穴風堆橡斗重。", "已乏尖新陪世話，斷無闊匾拆書封。", "一軒煨芋方題榜，時過松扉慰我慵。"]'),
('30cf9e64-90e3-4f93-89d7-6971b6bc69f6','即席次韻器之相贈','張鎡','宋','宋诗','song-poetry','','[]','會閒須是莫論年，直把浮生付且然。',64,'全唐诗/poet.song.171000.json','["會閒須是莫論年，直把浮生付且然。", "桂隠欲爲山宰相，漆園曾是地神仙。", "看抄妙句行催酒，更向清流卧泛船。", "但喜相從得真樂，何心玩世學前賢。"]'),
('0453b002-3a56-452f-a0cd-e97b34326abd','次張以道韻','張鎡','宋','宋诗','song-poetry','','[]','無愁便是樂無涯，看破紛紛眼裏花。',64,'全唐诗/poet.song.171000.json','["無愁便是樂無涯，看破紛紛眼裏花。", "旋洗杯盂將酒試，重糊窗戶把風遮。", "丹房火鼎頻添水，衣柜香爐就焙茶。", "判却一生閒理會，共君難數第三家。"]'),
('c5c6e5b2-27aa-45dc-b7a6-e7d2d2d7f23c','次韻奉酬張野夫見贈','張鎡','宋','宋诗','song-poetry','','[]','謀身堪笑若舂鋤，甓社棲寒水滿湖。',64,'全唐诗/poet.song.171000.json','["謀身堪笑若舂鋤，甓社棲寒水滿湖。", "近寺偶成蓮社似，爲園非效輞川圖。", "清樽酒好詩中聖，古塚珠存念大儒。", "久矣自求無所用，喜君能好柏楸株。"]'),
('82efe1fb-cf2d-4ab3-8175-4ac196a7a916','次韻陳秀才','張鎡','宋','宋诗','song-poetry','','[]','規模渾是野人居，剪結蒼松蔭屋除。',64,'全唐诗/poet.song.171000.json','["規模渾是野人居，剪結蒼松蔭屋除。", "閒把欹眠酬懶架，靜便徐步當安輿。", "青精飯好終延老，紫石潭空總付渠。", "玩世從來畏人覺，他年方信此心初。"]'),
('f3502484-9e8e-4b63-ba54-9a724293549e','玉照堂觀梅二首  其一','張鎡','宋','宋诗','song-poetry','','[]','絕憐一見一番新，短直長斜意總真。',64,'全唐诗/poet.song.171000.json','["絕憐一見一番新，短直長斜意總真。", "繞屋便能雲態度，問春誰更雪精神。", "栽花十畝猶嫌少，與我多生定是親。", "爲惜生香怕閒却，折歸聊當散花人。"]'),
('bee0c4e3-e736-4986-a3ea-abdbe12b843f','玉照堂觀梅二首  其二','張鎡','宋','宋诗','song-poetry','','[]','未辦當春句法工，坐來花下泥春風。',64,'全唐诗/poet.song.171000.json','["未辦當春句法工，坐來花下泥春風。", "山高水遠須人領，玉潔珠光喜日烘。", "越女信知天下白，屈平那是澤邊窮。", "明朝風雨從教有，老眼今年已不空。"]'),
('98005ac5-c3ac-4c20-bfcb-4b6057764578','送陳同父','張鎡','宋','宋诗','song-poetry','','[]','事因前定漫驅馳，諳盡人間合似癡。',64,'全唐诗/poet.song.171000.json','["事因前定漫驅馳，諳盡人間合似癡。", "萬卷經綸大儒業，一生忠憤上天知。", "長安又見垂楊老，淮甸將興故國悲。", "雞彘竹籬歸夢否，會閒方稱是男兒。"]'),
('9ac2fb87-5f93-45cb-b389-e427e3516da9','立春日園梅未花書呈尤檢正','張鎡','宋','宋诗','song-poetry','','[]','凍禽先自起多時，暖戀衾重曉不知。',64,'全唐诗/poet.song.171000.json','["凍禽先自起多時，暖戀衾重曉不知。", "栩栩夢回思樹繞，綿綿息動離床支。", "十行猶用午年曆，數首初編丁藁詩。", "臘雪已多春定好，願求名名檄南枝。"]'),
('49c65a32-04f6-4e27-9672-1e8aa0958c07','靧櫛','張鎡','宋','宋诗','song-poetry','','[]','澡灌新宜白氎巾，睡餘臞面滌昏塵。',64,'全唐诗/poet.song.171000.json','["澡灌新宜白氎巾，睡餘臞面滌昏塵。", "三薰衣潤乘沉麝，一沃湯柔和芷辛。", "衰髮任從清鏡脫，壯心不逐故書陳。", "消平孤悶將何事，燕坐移時定谷神。"]'),
('713400f0-ce66-4402-af2b-5de5a436d2c7','遊臞庵','張鎡','宋','宋诗','song-poetry','','[]','入門黄葉擁危橋，竹裏山茶刺亂梢。',64,'全唐诗/poet.song.171000.json','["入門黄葉擁危橋，竹裏山茶刺亂梢。", "釣雪亭修人未坐，浮天閣廢鷺應巢。", "百年勞役終奚爲，一段風流忍獨拋。", "寄語王家早營葺，他時相對我衡茅。"]'),
('772c4654-3d36-46f1-9ff8-66af5ee2e244','湖上呈虞仲房','張鎡','宋','宋诗','song-poetry','','[]','謁客衝泥路有聲，筍輿風裏轉高城。',64,'全唐诗/poet.song.171000.json','["謁客衝泥路有聲，筍輿風裏轉高城。", "秋山正要一意看，曉日倍添雙目明。", "淺濼鴟盤思腐啄，孤汀鶴立念遐征。", "世間似我詩多有，莫漫逢人道姓名。"]'),
('11159b24-f123-4336-8d5c-dc68453294ae','簡馬架閣','張鎡','宋','宋诗','song-poetry','','[]','江浙聞人馬少伊，識公因誦雪窗詩。',64,'全唐诗/poet.song.171000.json','["江浙聞人馬少伊，識公因誦雪窗詩。", "交馳刺字休嫌阻，一見人生自有期。", "城郭村翁誰問我，親王嬌客罕如斯。", "雞聲風雨相望處，情致先多會面時。"]'),
('4361b9ae-9444-41d0-b5b1-61800cea8811','皇太子生辰二首  其一','張鎡','宋','宋诗','song-poetry','','[]','無射吹銅恰四萱，紫微深處粲前星。',64,'全唐诗/poet.song.171000.json','["無射吹銅恰四萱，紫微深處粲前星。", "木行襲慶聯三合，火德流光共一丁。", "玩鶴怡神資葆毓，聞雞爲善想儀刑。", "豐年在在歌華黍，鴻鵠高飛萬宇寧。"]'),
('7b795479-2ad4-4623-ba7c-1fd16db64c42','皇太子生辰二首  其二','張鎡','宋','宋诗','song-poetry','','[]','歡聲叶氣藹乾坤，榮觀于今貳極尊。',64,'全唐诗/poet.song.171000.json','["歡聲叶氣藹乾坤，榮觀于今貳極尊。", "天予聰明屬文子，人推勇智實湯孫。", "百寮銀筆松椿祝，三殿瑶觴雨露恩。", "久託重暉無以報，蕪音常是愧雷門。"]'),
('41b204b4-0928-484b-99c7-7d7d38eaea7a','即席次潘茂洪韻','張鎡','宋','宋诗','song-poetry','','[]','我恨填胸三斗塵，略無警句可留春。',64,'全唐诗/poet.song.171000.json','["我恨填胸三斗塵，略無警句可留春。", "煙雲空外吹成鶴，梅杏枝頭長就人。", "但解時中心獨廢，自然隨處樂常新。", "諸公要識居園法，第一先教懶是真。"]'),
('ff87ace0-e048-43f7-8e6a-7ac7555e5efa','過鳳山高氏以榴實薦酒','張鎡','宋','宋诗','song-poetry','','[]','灣洄綠處得雞聲，俯檻山宜柳外明。',64,'全唐诗/poet.song.171000.json','["灣洄綠處得雞聲，俯檻山宜柳外明。", "京洛漲塵衣半黑，邯鄲炊黍夢曾驚。", "榴皮就爲翁題好，竹葉能邀我興成。", "辦此一廛歸老計，弄孫相對說春耕。"]'),
('35dbc905-d246-45f1-b156-c3f92b15d80e','以洞庭橘寄楊祕監','張鎡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','橘色渾如柿色黄，誠齋有句合分嘗。',64,'全唐诗/poet.song.171000.json','["橘色渾如柿色黄，誠齋有句合分嘗。", "豈爲都市頗難得，要是洞庭親寄將。", "雨露山中今有味，星辰天上舊無香。", "遥知老監開奩處，爲釂椒花雨一觴。"]'),
('56d7a21f-b703-4fcb-a56b-40fc5c39d23f','呈吳居甫待制','張鎡','宋','宋诗','song-poetry','','[]','挺挺風規軼輩流，肯因官譽揜清脩。',64,'全唐诗/poet.song.171000.json','["挺挺風規軼輩流，肯因官譽揜清脩。", "南宮妙畫多時見，北固新篇去歲收。", "每念小人同話此，曾知閒客到門不。", "平生自笑迂疎甚，趨造纔頻更覺愁。"]'),
('bfc021f2-6968-4041-8646-ab1884697122','送吳季行監丞知簡州','張鎡','宋','宋诗','song-poetry','','[]','兩門情義一鄉中，祖業還同社稷功。',64,'全唐诗/poet.song.171000.json','["兩門情義一鄉中，祖業還同社稷功。", "賃舍偶隣逢事少，訪余時幸慰詩窮。", "割符忽爲榮親去，橫槊多因得地雄。", "强飯肯隨官職禱，故家當勉報文風。"]'),
('6e38a123-6979-49c3-b087-a6bd232ce724','長至前夕書寄陸嚴州','張鎡','宋','宋诗','song-poetry','','[]','銅爐熟火暖無烟，一盞清燈紙帳邊。',64,'全唐诗/poet.song.171000.json','["銅爐熟火暖無烟，一盞清燈紙帳邊。", "遲睡頗如除夜景，新陽方幸好晴天。", "詩成水閣梅堪折，信斷山城鴈不傳。", "莫待扁舟敘暌隔，歸來身作紫微仙。"]'),
('b56bee7f-12c9-4321-84e5-aa2a8fac5160','送趙季言知撫州','張鎡','宋','宋诗','song-poetry','','[]','同寅心契每難忘，林野投閒話最長。',64,'全唐诗/poet.song.171000.json','["同寅心契每難忘，林野投閒話最長。", "自是文華兼政術，非徒神秀出天潢。", "臨岐暫送魚符客，指日歸來畫省郎。", "詩社不應常寂寞，頼君搜奬出江鄉。"]'),
('1dd77077-c471-423a-ba0e-d976a06512a8','余家兄弟未嘗久別今夏送平父之官山口冬仲朔又送深父爲四明船官因成長句','張鎡','宋','宋诗','song-poetry','','[]','遵渚霜鴻散漫飛，江天分序益凄悲。',64,'全唐诗/poet.song.171000.json','["遵渚霜鴻散漫飛，江天分序益凄悲。", "孤生只合羣居樂，半歲那禁兩別離。", "發軔固知期遠到，望船猶怕獨歸時。", "書來豈是寒暄語，盡寫衷情慰渴饑。"]'),
('9c59f3b4-5486-41e8-b93a-9597effe94e2','呈毛崇夫司直','張鎡','宋','宋诗','song-poetry','','[]','春到深時味更長，草晴勝似雜花香。',64,'全唐诗/poet.song.171000.json','["春到深時味更長，草晴勝似雜花香。", "清陰漸次迷天綠，白髮依稀照領光。", "逐婦牆鳩知雨近，生兒梁燕補巢忙。", "擘牋謾記今朝景，朝路歸時肯易忘。"]'),
('027d2f82-505d-4965-a7c2-da0f479e0455','次韻酬新九江使君趙明達二詩仍送自製香餠白鷗波酒  其一','張鎡','宋','宋诗','song-poetry','','[]','紛紛金珮與瑶環，骨相如吾敢妄攀。',64,'全唐诗/poet.song.171000.json','["紛紛金珮與瑶環，骨相如吾敢妄攀。", "居處何曾離城郭，襟期終不負湖山。", "杉旁試履拖雲濕，石上敲鈎破蘚斑。", "衝曉樵童便來往，思量誰是我投閒。"]'),
('13a689e7-1b3d-4602-b499-072eaffcdbbe','次韻酬新九江使君趙明達二詩仍送自製香餠白鷗波酒  其二','張鎡','宋','宋诗','song-poetry','','[]','歲晏懷人水一湄，歸鴻去鴈各參差。',64,'全唐诗/poet.song.171000.json','["歲晏懷人水一湄，歸鴻去鴈各參差。", "寒風不解頻吹夢，疾置何妨數寄詩。", "釀酒改名聊濟勝，和香因譜更求奇。", "路遥不暇多缾送，一炷同參日漸遲。"]'),
('33167d05-f72b-46bc-9a74-8cc5af4d29be','酬張子立投贈','張鎡','宋','宋诗','song-poetry','','[]','論文嘗到愛山前，屢費金猊冰麝煙。',64,'全唐诗/poet.song.171000.json','["論文嘗到愛山前，屢費金猊冰麝煙。", "舉世無人憐易絕，今年有子得詩傳。", "慵隨肥馬輕裘俗，要結高山流水緣。", "淺拙固難酬妙寄，漫撩春夢草池邊。"]'),
('98ad4469-caa6-4e03-abf4-6513ea97998b','次韻酬潘茂洪見寄','張鎡','宋','宋诗','song-poetry','','[]','懷人非特爲能詩，襟抱如君坦復怡。',64,'全唐诗/poet.song.171000.json','["懷人非特爲能詩，襟抱如君坦復怡。", "三徑許時無地覓，一生高處只天知。", "江湖老夢疎篷慣，燈火凉秋細字宜。", "此興未嘗殊往歲，水邊唯欠詠黄葵。"]'),
('16cecf0f-5c20-42d6-ada8-52c8d0d15dc1','酬曾無逸架閣見寄','張鎡','宋','宋诗','song-poetry','','[]','貪閒常怕拆人書，今日開緘病已無。',64,'全唐诗/poet.song.171000.json','["貪閒常怕拆人書，今日開緘病已無。", "數紙雲情動金石，一篇天籟集笙竽。", "心交物類相感志，願在衣冠盛事圖。", "稍稍斯文振吾黨，快來青鬢躐華途。"]'),
('20abbc67-5e55-4c9f-a42d-335f1c68d651','次韻酬鄭唐老見寄','張鎡','宋','宋诗','song-poetry','','[]','黄葉歸根靜不風，迴塘雪後正浟溶。',64,'全唐诗/poet.song.171000.json','["黄葉歸根靜不風，迴塘雪後正浟溶。", "山林有分吾當去，簪紱方興子未慷。", "點檢寒榮梅又動，思量暖事李將穠。", "橋南水北來還往，露布詩篇不必封。"]'),
('249c7956-1b8f-438f-91ec-a2f83784dbf8','次韻王耘之','張鎡','宋','宋诗','song-poetry','','[]','白汗翻漿九市人，清風誰似此論心。',64,'全唐诗/poet.song.171000.json','["白汗翻漿九市人，清風誰似此論心。", "壯遊淮上官聲起，重會都城句法深。", "久矣求才膠柱瑟，老來逢事不徽琴。", "漫湖又見香荷發，煮餠須同近寺林。"]'),
('9d4281dc-17eb-480d-a81d-2ccc9fdb3526','次韻酬杜材卿','張鎡','宋','宋诗','song-poetry','','[]','樓寒鶴骨舊竛竮，別後溪山夢不扃。',64,'全唐诗/poet.song.171000.json','["樓寒鶴骨舊竛竮，別後溪山夢不扃。", "世事益知推去好，鬢毛渾減向來青。", "詩篇又見聲諧律，才興何疑刃照硎。", "愁裏不妨同茗酌，古梅園種百龍形。"]'),
('189790e9-2a55-47d1-8ce2-bb094e5ae0df','呈張左曹郎中','張鎡','宋','宋诗','song-poetry','','[]','持節江湘公去久，浙西風月我孤吟。',64,'全唐诗/poet.song.171000.json','["持節江湘公去久，浙西風月我孤吟。", "相逢未敘三年話，此事先拋一寸心。", "風調不因通宦汩，世塗尤見故情深。", "隨人一錯終能復，林墅應勞得得尋。"]'),
('cfcf37c1-0a36-4c50-9720-61f4e738e5a7','離蘇州回寄太守袁起岩郎中','張鎡','宋','宋诗','song-poetry','','[]','吳中佳地舊長洲，來往空回信宿留。',64,'全唐诗/poet.song.171000.json','["吳中佳地舊長洲，來往空回信宿留。", "泰伯廟存那暇問，麗娃鄉近未曾遊。", "詩翁燕坐迎香閣，閒客歸乘釣月舟。", "想見名章已成集，韋郎何得擅蘇州。"]'),
('b5a13d9c-83b9-498c-b3bb-a6d46261bc1c','伴書回寄建康張總卿','張鎡','宋','宋诗','song-poetry','','[]','湖上初晴擅曉凉，一緘俄墜讀書床。',64,'全唐诗/poet.song.171000.json','["湖上初晴擅曉凉，一緘俄墜讀書床。", "月卿星使年年憶，雪白蘭薰字字香。", "聞道江邊勤叱馭，也知鷗外靜鳴榔。", "新君未識詩人在，早覲楓宸荷紫囊。"]'),
('ceabeef3-d457-4ea9-b502-b8a2bced71c5','種蠟梅喜成時欲暫往梁溪','張鎡','宋','宋诗','song-poetry','','[]','出得荆扉喜欲顛，園夫撐到蠟梅船。',64,'全唐诗/poet.song.171000.json','["出得荆扉喜欲顛，園夫撐到蠟梅船。", "包封山土根微脫，束縛溪藤葉尚鮮。", "搬處側從新逕裏，種時圍向舊臺邊。", "叮嚀等待吾歸看，切莫開花小至前。"]'),
('1d0070cd-4cbb-4ef2-842c-a7320855e91f','時賢有爵高名重而不自由者再念閒居之可樂爲賦長句','張鎡','宋','宋诗','song-poetry','','[]','多幸因愚得養恬，林扃風變陡寒天。',64,'全唐诗/poet.song.171000.json','["多幸因愚得養恬，林扃風變陡寒天。", "杯傳蕉葉溫成酒，襖織梅花軟入綿。", "經室爐添羊脛炭，道床屏護鷓斑烟。", "遥思病叟頭如雪，冒冷遐征想自憐。"]'),
('1d282fab-6bee-453a-99e5-238fc1f911ad','送鶴還建康章德茂侍郎因成兩詩  其一','張鎡','宋','宋诗','song-poetry','','[]','來時雪羽带緇塵，養得摧殘病離身。',64,'全唐诗/poet.song.171000.json','["來時雪羽带緇塵，養得摧殘病離身。", "曉浴池寬薝蔔遶，夜棲籠闊海棠隣。", "吟詩屢聽狂居士，入夢應思舊主人。", "且喜載隨千騎去，不妨乘勢長精神。"]'),
('2011c164-91e0-4c8d-abbe-97e165507905','送鶴還建康章德茂侍郎因成兩詩  其二','張鎡','宋','宋诗','song-poetry','','[]','風儀不稱汩泥塵，清向亨衢快舉身。',64,'全唐诗/poet.song.171000.json','["風儀不稱汩泥塵，清向亨衢快舉身。", "魚鑰麟符行作伴，鷺洲燕巷得爲隣。", "華亭清唳如前日，蜀道高風過昔人。", "他日侍郎登鳳沼，却來湖畔靜怡神。"]'),
('97e18c06-1e29-4e2f-876f-43f629f14433','入園聞鶴唳','張鎡','宋','宋诗','song-poetry','','[]','解事昂藏兩令威，叫晴隔水要人知。',64,'全唐诗/poet.song.171000.json','["解事昂藏兩令威，叫晴隔水要人知。", "喜渠飛舞開籠日，值我行歌出戶時。", "梅院共期清月上，芝田休費碧雪思。", "長閒便是延年法，鶴不同謀更與誰。"]'),
('0618e115-fec6-48df-8e03-83d4691a8a79','送徐衡仲歸侍次福建帥屬二首  其一','張鎡','宋','宋诗','song-poetry','','[]','三年林曲喜談叢，交薦俄聞得數公。',64,'全唐诗/poet.song.171000.json','["三年林曲喜談叢，交薦俄聞得數公。", "竟覓一官蓮幕下，漫添千詠錦囊中。", "時乖豈但馮唐老，性癖甘如叔夜慵。", "應是黄花過江路，笑垂雙袖立西風。"]'),
('5a530621-c05e-4e04-820b-f39769dfa3d7','送徐衡仲歸侍次福建帥屬二首  其二','張鎡','宋','宋诗','song-poetry','','[]','和篇猶未忽成行，無奈離情雜愧情。',64,'全唐诗/poet.song.171000.json','["和篇猶未忽成行，無奈離情雜愧情。", "風雨連朝難遠送，湖山何日再尋盟。", "飽參屢見從頭舉，識破懸知到處輕。", "疎懶祗愁書問少，望君因便却傳聲。"]'),
('d754008b-bf13-46c2-952e-2b642035c464','登梅橋望桂隠','張鎡','宋','宋诗','song-poetry','','[]','常日居園不自奇，今朝勝處上橋知。',64,'全唐诗/poet.song.171000.json','["常日居園不自奇，今朝勝處上橋知。", "平湖百畝橫當戶，茂樹千章翠繞籬。", "隣寺鐘魚初歷歷，里閭雞犬亦熙熙。", "隔城更有青山在，朝揖吾家出好詩。"]'),
('80e8d2b8-ee12-4ca6-bfaa-0fb2ae6c84a3','喜楊誠齋赴召','張鎡','宋','宋诗','song-poetry','','[]','病中何事却懽欣，聞召高安老使君。',64,'全唐诗/poet.song.171000.json','["病中何事却懽欣，聞召高安老使君。", "碧落豈容留綺夏，紫微端要著卿雲。", "朝天續集開新詠，解易玄談記古文。", "應笑清臞約齋子，湖邊猶戀白鷗羣。"]'),
('b4aa7aa3-46d7-4ffb-bd0c-abab8cdf5ee1','誠齋以南海朝天兩集詩見惠因書卷末','張鎡','宋','宋诗','song-poetry','','[]','筆端有口古來稀，妙悟奚煩用力追。',64,'全唐诗/poet.song.171000.json','["筆端有口古來稀，妙悟奚煩用力追。", "南紀山川題欲遍，中朝文物寫無遺。", "後山格律非窮苦，白傅風流造坦夷。", "霜鬢未聞登翰苑，緩公高步或因詩。"]'),
('2ab60463-6507-4a6f-95bd-041d58e7a125','南湖有懷遂初尤公侍郎寄贈七言','張鎡','宋','宋诗','song-poetry','','[]','停驂曾送柳邊舟，忽忽今冬病故秋。',64,'全唐诗/poet.song.171000.json','["停驂曾送柳邊舟，忽忽今冬病故秋。", "望遠溪山常入夢，寫殘書信只成愁。", "明心坐斷三千佛，謁帝行歸十二樓。", "臨水憶君誰復信，亂烟凄暮白蘆洲。"]'),
('4f549a20-16db-4ceb-b4a4-f0dd013bc274','呈曾仲躬侍郎','張鎡','宋','宋诗','song-poetry','','[]','公道欣從禁路開，世家今有偉人來。',64,'全唐诗/poet.song.171000.json','["公道欣從禁路開，世家今有偉人來。", "共推掌學文清手，突過談兵杜牧才。", "老眼知人明月鏡，時情薦士冷稭灰。", "詩章活法從公了，要使諸方聽若雷。"]'),
('a25265af-38a9-4aa3-9fdd-2591d530fd53','次韻叔祖題詠澤亭','張鎡','宋','宋诗','song-poetry','','[]','疆塞聲威昔據鞍，築亭聊此水雲看。',64,'全唐诗/poet.song.171000.json','["疆塞聲威昔據鞍，築亭聊此水雲看。", "地連牛斗東南勝，心體鳶魚上下觀。", "一節愛君通表裏，百年耽句置炎寒。", "莫疵緣岸規模淺，幽潔從來極怕寬。"]'),
('c363bcef-99f2-4e78-8b27-f9c86bebf9b9','有懷參政范公因書桂隠近事奉寄二首  其一','張鎡','宋','宋诗','song-poetry','','[]','石湖仙伯住吳門，事業文章兩足尊。',64,'全唐诗/poet.song.171000.json','["石湖仙伯住吳門，事業文章兩足尊。", "南北東西曾遍歷，焉哉乎也敢輕論。", "桂園柳色金絲織，笠澤桃花錦浪翻。", "小大風烟俱自適，鷦巢終莫擬雲鯤。"]'),
('dff68ab6-39ca-4431-80f9-4e858a12d422','有懷參政范公因書桂隠近事奉寄二首  其二','張鎡','宋','宋诗','song-poetry','','[]','迂疎那可作治中，閒事歸來却不慵。',64,'全唐诗/poet.song.171000.json','["迂疎那可作治中，閒事歸來却不慵。", "曉炷佛香聊作觀，晚投社飲亦稱儂。", "荷花製就身宜著，菰米收成手自舂。", "最是今春多偉績，萬叢蘭四百株松。"]'),
('30ea3ca9-7b58-4325-84a9-c124d1fc570e','行近湖州不果入城寄王成之使君','張鎡','宋','宋诗','song-poetry','','[]','江左風流燕子家，有人襟度渺雲涯。',64,'全唐诗/poet.song.171000.json','["江左風流燕子家，有人襟度渺雲涯。", "謳歌馮翊今分竹，詞藻西垣舊判花。", "相望每居形迹外，投閒常動別離嗟。", "因行一見還成阻，誰謂人遐自室遐。"]'),
('cd3efcb2-bd38-4895-98a8-23f2028e1c8e','過臨安海會寺東長橋有懷蘇文忠公','張鎡','宋','宋诗','song-poetry','','[]','竦踴峰環碧玉城，亂蟬爭送夕陽明。',64,'全唐诗/poet.song.171000.json','["竦踴峰環碧玉城，亂蟬爭送夕陽明。", "飛橋預快登山足，壞塔遥增弔古情。", "陳迹幾年驚夢幻，清文隨處振英莖。", "胡床等到三更看，閒過桐鄉或駕鯨。"]'),
('5fef6394-82ff-46f0-af58-2e8f216a2f15','許深甫宰分宜','張鎡','宋','宋诗','song-poetry','','[]','崢嶸飛藻妙無前，廓廓披懷萬丈淵。',64,'全唐诗/poet.song.171000.json','["崢嶸飛藻妙無前，廓廓披懷萬丈淵。", "久矣願交嗟跡異，茲焉覿面實心先。", "雪窗政握持盃手，風溆驚排轉柁船。", "名宦祝君誠長語，安心西去試鳴弦。"]'),
('1233d597-5581-473a-8783-26f17a7c24f5','因過田倅坐間得姜堯章所贈詩卷以七字爲報','張鎡','宋','宋诗','song-poetry','','[]','京廛輿馬競揚埃，何礙騷人獨往回。',64,'全唐诗/poet.song.171000.json','["京廛輿馬競揚埃，何礙騷人獨往回。", "我住水邊奚自識，詩如雲外寄將來。", "一從風袖携歸看，屢向松亭靜展開。", "應是冰清逢玉潤，只因佳句不因媒。"]'),
('f86635e8-1aed-45fa-a3f0-1073d5cbeac2','賀蕭參政','張鎡','宋','宋诗','song-poetry','','[]','向來投謁未嘗頻，今日尤宜後衆賓。',64,'全唐诗/poet.song.171000.json','["向來投謁未嘗頻，今日尤宜後衆賓。", "先世年家登政府，時情禮數到閒人。", "只將忠實酬明主，果見推遷作大臣。", "何用撫孤多軫念，園花開勝去年春。"]'),
('7ec3f21c-482d-4e36-b895-16bd051118e9','叔祖閣學座間請觀詩編因賦','張鎡','宋','宋诗','song-poetry','','[]','出門何許會初心，家有師儒是學林。',64,'全唐诗/poet.song.171000.json','["出門何許會初心，家有師儒是學林。", "畫古更因金印偉，書叢方稱錦堂深。", "朱橙薦酒隨冬蟹，翠蔓披牆引暮禽。", "每幸酸鹹得同嗜，可令傾耳闕韶音。"]'),
('b6f8e337-01a8-4074-b6a6-b90ac6301cc0','送鄭剛中赴江東參議','張鎡','宋','宋诗','song-poetry','','[]','去程遥指石頭城，秋與鍾山老氣清。',64,'全唐诗/poet.song.171000.json','["去程遥指石頭城，秋與鍾山老氣清。", "紬繹蓬巒曾正字，參陪蓮幕試論兵。", "時平得計甘微祿，學古無心急近榮。", "君豈江淮久遊客，歸來矍鑠上承明。"]'),
('230690d4-8d3b-47c3-aece-6e787b042e3f','回渡荷葉浦','張鎡','宋','宋诗','song-poetry','','[]','宿雨驚眠變早涼，喜成風便放歸航。',64,'全唐诗/poet.song.171000.json','["宿雨驚眠變早涼，喜成風便放歸航。", "山雲野樹水墨暗，蘆葉荷花文繡香。", "藉枕冰藤醒倦思，打簾珠浪發清狂。", "天圍平浦方宜眼，便腹飛帆莫太忙。"]'),
('0624c277-9c0e-40e9-9c51-77d477052607','次以道荷葉浦','張鎡','宋','宋诗','song-poetry','','[]','向來曾愛葉田田，落日荷花擁櫂前。',64,'全唐诗/poet.song.171000.json','["向來曾愛葉田田，落日荷花擁櫂前。", "霜冷不移魚世界，葦殘聊作鴈家緣。", "詩狂頃刻成三首，懶病中間接四邊。", "除此今朝無別事，與君相就樂𦨻船。"]'),
('15302b2d-3574-4d82-be0d-770ed66e2ad6','又呈坐客','張鎡','宋','宋诗','song-poetry','','[]','天假南湖一段奇，賓朋胥會只論詩。',64,'全唐诗/poet.song.171000.json','["天假南湖一段奇，賓朋胥會只論詩。", "人生未老肯閒日，春色無邊方盛時。", "林外好山看獨慣，塵中新事問寧知。", "從來邂逅宜真率，花下杯傳却莫遲。"]'),
('7535ba49-cc96-47ce-b144-441772d9ad1a','客至','張鎡','宋','宋诗','song-poetry','','[]','麝萱沿徑緣抽牙，文杏飄蹊白覆沙。',64,'全唐诗/poet.song.171000.json','["麝萱沿徑緣抽牙，文杏飄蹊白覆沙。", "過半春光須愛惜，沓來人事費攔遮。", "妨尋蟻徑看排陣，阻向蜂筒聽報衛。", "癖性杜門猶憚此，刺頭塵土可堪嗟。"]'),
('a21145df-5a1a-4e31-84c3-7e1ec3246ed6','次韻酬陳伯冶監倉','張鎡','宋','宋诗','song-poetry','','[]','小築才成賜也牆，傳家那是釣徒張。',64,'全唐诗/poet.song.171000.json','["小築才成賜也牆，傳家那是釣徒張。", "非求世上人看好，但要閒中句律昌。", "成陣遊鯈波上暖，打團飛蝶菊初荒。", "隣翁莫厭頻相遇，會見橫翔入未央。"]'),
('92b3cec7-ea9e-4139-a656-f69f18016bb7','送葉景良知嚴陵','張鎡','宋','宋诗','song-poetry','','[]','千古風高仰釣臺，朱輪新擁得通才。',64,'全唐诗/poet.song.171000.json','["千古風高仰釣臺，朱輪新擁得通才。", "政聲易報長安近，家學知從霅水來。", "半載依仁方恨別，雙魚傳信肯慵開。", "分携强飯休頻祝，鋒召需賢定挽回。"]'),
('be81c8a3-3e32-44ad-8fa1-64c233354186','送謝艮齋得閒西歸','張鎡','宋','宋诗','song-poetry','','[]','向來朝列雖知己，臺省山林職事殊。',64,'全唐诗/poet.song.171000.json','["向來朝列雖知己，臺省山林職事殊。", "勇退近聞辭北闕，醉遊唯欠到南湖。", "心傳古學高當代，力把忠言壯晚途。", "競說歸舟賣金带，囊空想見一錢無。"]'),
('d76a4e60-93fb-4701-bfba-ddec5a3922c7','戲呈鄭去華縣丞','張鎡','宋','宋诗','song-poetry','','[]','疊破當年御賜袍，飽看人釣六靈鼇。',64,'全唐诗/poet.song.171000.json','["疊破當年御賜袍，飽看人釣六靈鼇。", "行藏雖似少中節，識趣不妨依舊高。", "入夢傅巖初豈意，上書曼倩本徒勞。", "浮生萬事天都了，愛惜君才祝善刀。"]'),
('3cb8b1bf-1e1c-454b-a900-95dc3033c240','謁客不值夜夢見之','張鎡','宋','宋诗','song-poetry','','[]','澄湖樓畔梵王宮，門外陂塘盡日風。',64,'全唐诗/poet.song.171000.json','["澄湖樓畔梵王宮，門外陂塘盡日風。", "來訪故人嗟未值，絕憐秋色與誰同。", "不遑將母君應嘆，始可言詩我未工。", "須信夢多因境熟，夜深猶在寺門東。"]'),
('c638e00a-dc4e-453d-b4c7-aed4fd30bc10','官舍夢歸南湖','張鎡','宋','宋诗','song-poetry','','[]','林野相望不隔關，夢魂徑到豈爲難。',64,'全唐诗/poet.song.171000.json','["林野相望不隔關，夢魂徑到豈爲難。", "恍如天上飛升客，忘却人間走俗官。", "巖桂直通籠鶴檻，水葓斜倚釣魚竿。", "覺來不忍輕開眼，窗外芭蕉戰曉寒。"]'),
('fa5de6f6-728c-4af8-844c-25d474547bd3','曾無逸餉風瀾十團扇報以七言','張鎡','宋','宋诗','song-poetry','','[]','君才霽月破陰分，因物還將比似君。',64,'全唐诗/poet.song.171000.json','["君才霽月破陰分，因物還將比似君。", "水上風雲真解悟，目前意到便成文。", "輕濤浡突羊頭起，急溜爬髿虎爪分。", "珍重南豐橫別派，洗空浮濁幾人羣。"]'),
('3a67b20e-dcea-4084-9705-9fe7008879f6','許深父送日鑄茶','張鎡','宋','宋诗','song-poetry','','[]','短牋欣見小龍蛇，諫省初頒越嶺茶。',64,'全唐诗/poet.song.171000.json','["短牋欣見小龍蛇，諫省初頒越嶺茶。", "甆缶祕香蒙翠箬，蠟封承印濕丹砂。", "清風灑落曾誰比，正味森嚴更可嘉。", "堪笑雲臺方忍睡，强行松徑嚼新芽。"]'),
('e015d29d-008f-4dad-825a-14d5e9dc8fa6','遊叔祖次對宅南新園詩','張鎡','宋','宋诗','song-poetry','','[]','入門疑是洞中天，有此人間事兩全。',64,'全唐诗/poet.song.171000.json','["入門疑是洞中天，有此人間事兩全。", "深窈高明俱要景，安閒榮盛未衰年。", "軒窗處鶴千層竹，風雨催詩十畝蓮。", "聞道從今畢婚嫁，陰功專爲子孫傳。"]'),
('f317d159-3e2c-4fe6-bb85-bedb2620ce12','五林方沈氏居','張鎡','宋','宋诗','song-poetry','','[]','路轉蒼灣靜者家，抱牆脩竹舞簷斜。',64,'全唐诗/poet.song.171000.json','["路轉蒼灣靜者家，抱牆脩竹舞簷斜。", "佛燈鏡照無盡像，書館池栽成行花。", "粗有田園真可樂，不維車服更何加。", "晚來清致因閒取，非故邀君一煮茶。"]'),
('c365921a-436d-4ddf-9f20-e3bd6c3d5b97','南湖夕泛','張鎡','宋','宋诗','song-poetry','','[]','欲知家住畫圖中，靜向波心漾短篷。',64,'全唐诗/poet.song.171000.json','["欲知家住畫圖中，靜向波心漾短篷。", "粉墨暈開天水色，碧朱堆上柳花叢。", "雲邊鷗影來還去，籬畔雞聲西復東。", "別浦夷猶豈無謂，細看蘋末受清風。"]'),
('bbbcf223-5287-4c46-9af3-f00ee0cf13c6','游新市趙侍郎園','張鎡','宋','宋诗','song-poetry','','[]','步屧沾泥得望新，霽光飛上雜花明。',64,'全唐诗/poet.song.171000.json','["步屧沾泥得望新，霽光飛上雜花明。", "漁篷就向池旁入，山翠盡從窗外橫。", "因想主人持酒興，直須居士詠詩聲。", "浮生果解隨緣足，適意真强爵與名。"]'),
('c4410108-d97d-46cc-a6a4-a10086c4300d','遊韓氏園有客先歸','張鎡','宋','宋诗','song-poetry','','[]','風日催荷作老香，便將新句責胡床。',64,'全唐诗/poet.song.171000.json','["風日催荷作老香，便將新句責胡床。", "重山抱屋臨幽爽，四月邊湖納晚涼。", "扇景不驚蛙黽坐，槃飧還愛筍蔬長。", "佳賓壯論能投俗，歸路誰憐鬢雪光。"]'),
('db849ad5-3ff1-4364-b39f-fa4df2e18c4d','寄題任子嚴漕使盤園','張鎡','宋','宋诗','song-poetry','','[]','身即林園不世功，喜驚今乃有人同。',64,'全唐诗/poet.song.171000.json','["身即林園不世功，喜驚今乃有人同。", "規模內相雄文裏，景物時賢雜詠中。", "前輩風流何敢似，後來評論想能公。", "誰曾寤寐聲形隔，真樂從茲觸處通。"]'),
('128929d6-285d-434e-bd83-815bcf82b131','離無錫夜入溪莊港口','張鎡','宋','宋诗','song-poetry','','[]','出山猶自雨隨車，到得溪橋一點無。',64,'全唐诗/poet.song.171000.json','["出山猶自雨隨車，到得溪橋一點無。", "冷月半明雲未去，垂楊成行葉全枯。", "竹添東墅方清蔭，人在南湖已白鬚。", "應是田翁喜儂至，旋吹燈火競歡呼。"]'),
('d35a3a70-ee4c-4b6a-9ec2-64bb8ff4c386','雨中憶曇少雲奉寄','張鎡','宋','宋诗','song-poetry','','[]','天意今年不惜涼，雨聲秋後恣淋浪。',64,'全唐诗/poet.song.171000.json','["天意今年不惜涼，雨聲秋後恣淋浪。", "單衣已覺生絺薄，細字初便短燭光。", "畫餠功名孤塞路，守株身世老江鄉。", "吾儕政要無人識，黄葉深林氣味長。"]'),
('cf7f21ff-288f-4eb0-875e-6ed199c0ab06','虎斑貓','張鎡','宋','宋诗','song-poetry','','[]','百丈慵參老野狐，一雙俄得小於菟。',64,'全唐诗/poet.song.171000.json','["百丈慵參老野狐，一雙俄得小於菟。", "眈眈肯聽豺聲怯，索索當令鼠輩無。", "既與道人常並坐，何妨童子戲編鬚。", "硬黄新染香如蠟，從此書堂不閉厨。"]'),
('fdffefd9-2865-4eb7-8daa-992e1c2ed758','錦池汎舟贈莊器之二首  其一','張鎡','宋','宋诗','song-poetry','','[]','槐葉鶑聲兩度春，笑言常恨獨參辰。',64,'全唐诗/poet.song.171000.json','["槐葉鶑聲兩度春，笑言常恨獨參辰。", "相過便說幽居好，別後應多秀句新。", "賀監湖邊山作伴，若耶溪上月爲隣。", "凉秋定扣松扉去，一舸從君理釣緡。"]'),
('c01b6d2b-a12a-4f76-a31b-859008539375','錦池汎舟贈莊器之二首  其二','張鎡','宋','宋诗','song-poetry','','[]','翠舫迎涼避日行，只隨風去不須撐。',64,'全唐诗/poet.song.171000.json','["翠舫迎涼避日行，只隨風去不須撐。", "雲移茂樹添層影，魚喜新荷觸嫩莖。", "客有何人從遠至，天憐吾輩太清生。", "功名世上雖爲急，弄水搴芳未可輕。"]'),
('2a32fc91-7f5c-4d13-9a48-83c5b0d692c3','遊俞氏庵次叔祖韻','張鎡','宋','宋诗','song-poetry','','[]','青山穩處衲僧家，得趣應難向客誇。',64,'全唐诗/poet.song.171000.json','["青山穩處衲僧家，得趣應難向客誇。", "春砌浪生金鳳草，夏窗低映木龍花。", "安禪舊日參臨濟，照影新遊愛水涯。", "酩酊詎論歸路晚，壁間貪縱墨翻鴉。"]'),
('710e649d-554f-4244-ac6f-910fcabb893d','賣花','張鎡','宋','宋诗','song-poetry','','[]','種花千樹滿家林，詩思朝昏惱不禁。',64,'全唐诗/poet.song.171000.json','["種花千樹滿家林，詩思朝昏惱不禁。", "擔上青紅要逐定，車中摇兀也教吟。", "雖無蜂過曾偷採，猶恐塵飛數見侵。", "應是花枝亦相望，恨無人似我知音。"]'),
('106822a5-783a-4d6d-8617-635990b7fb29','泊吳江塔院喜霽','張鎡','宋','宋诗','song-poetry','','[]','風雨因何犯曉來，不教閒却好詩材。',64,'全唐诗/poet.song.171000.json','["風雨因何犯曉來，不教閒却好詩材。", "直須船內幽人起，始放天邊暖日開。", "傑閣豈容關一面，長橋渾欲走千回。", "歸時相見逢佳月，忙殺同行鸚鵡杯。"]'),
('c017ba58-406b-4851-9eb1-d15eee448118','舟行','張鎡','宋','宋诗','song-poetry','','[]','經夕舟行路未賒，不須寒夢早還家。',64,'全唐诗/poet.song.171000.json','["經夕舟行路未賒，不須寒夢早還家。", "雲運岡勢通平野，雨溢灘聲走亂沙。", "蘋蓼靜憐魚世界，菰蒲遥想鴈生涯。", "玄真便合苕溪隠，莫待摧頹兩鬢華。"]'),
('a09e8c98-df6a-4a3c-b772-9eeecdb58334','出德清縣','張鎡','宋','宋诗','song-poetry','','[]','天公有意作詩顛，入得苕溪未見蓮。',64,'全唐诗/poet.song.171000.json','["天公有意作詩顛，入得苕溪未見蓮。", "先放水葓圍半里，更將蘆葉界平川。", "明金扇日停蒼渚，碧玉環山吐白煙。", "非是老夫來領略，此中那有地行仙。"]'),
('eb496a4b-c3d7-453f-8d7b-6ba0ebdd5e5e','出餘杭縣','張鎡','宋','宋诗','song-poetry','','[]','暑劇中宵枕屢移，夙興猶得趁涼時。',64,'全唐诗/poet.song.171000.json','["暑劇中宵枕屢移，夙興猶得趁涼時。", "平衝露氣籃輿穩，遥雜星芒篠炬隨。", "觸景有詩聊記述，爲人無術漫驅馳。", "須臾假寐誰驚覺，隔岸清風叫子規。"]'),
('10ddafe8-3a37-4ed2-8365-2e255021d11d','之官離桂隠','張鎡','宋','宋诗','song-poetry','','[]','坎止流行總付天，好閒初志獨茫然。',64,'全唐诗/poet.song.171000.json','["坎止流行總付天，好閒初志獨茫然。", "巢成不去憐林鳥，門外空維念釣船。", "老矣春容聊索漠，薰兮風序向清妍。", "雨聲未易催愁得，投暇歸來意最便。"]'),
('70794952-678b-435e-bd72-9ebc15df18e0','題昌化縣雙溪館','張鎡','宋','宋诗','song-poetry','','[]','奔流檻外薄谿鳴，曾入坡仙拄杖聲。',64,'全唐诗/poet.song.171000.json','["奔流檻外薄谿鳴，曾入坡仙拄杖聲。", "天目遠連山勢曲，路頭爭說縣官清。", "林重鳥愛衝煙沒，橋毀人看涉水行。", "忙裏能偷此閒樂，抗塵寧復嘆勞生。"]'),
('a3207e79-45a9-4973-9cd1-b5d4e237555a','題臨川道中玉虛觀','張鎡','宋','宋诗','song-poetry','','[]','拔宅清都去不還，尚留仙事警其頑。',64,'全唐诗/poet.song.171000.json','["拔宅清都去不還，尚留仙事警其頑。", "靈茅歲久香猶發，丹井功成水自閒。", "日轉空庭松影瘦，雨餘幽徑蘚痕斑。", "雲軿鶴駕何曾遠，滿耳天風吹珮環。"]'),
('0bd6ab7e-24a0-4df5-93e5-950fa516fa2d','閒步遊紫極觀','張鎡','宋','宋诗','song-poetry','','[]','青惜高杉覓望寬，仙廬幽占路紆盤。',64,'全唐诗/poet.song.171000.json','["青惜高杉覓望寬，仙廬幽占路紆盤。", "邊花製古裝門榜，老桂枝拳倚醮壇。", "顔色不同輕紫綬，精神常在慕黄冠。", "蜂巢蟻垤非吾樂，終買雲扃種朮餐。"]'),
('70c22006-b230-47ad-8192-5100edaf5ad0','題天台凝真宮陳道士緣化藏經既成求詩還山','張鎡','宋','宋诗','song-poetry','','[]','羽帔褊褼下赤城，燒松禿兔氣尤清。',64,'全唐诗/poet.song.171000.json','["羽帔褊褼下赤城，燒松禿兔氣尤清。", "書成胝手憐心苦，神護頳肩覺擔輕。", "萬笈雲籤來北闕，一朝寶翰得東明。", "明年我欲仙遊去，要聽巖扃曉誦聲。"]'),
('885dd2cf-a7ad-4769-a332-b3137b11de03','水仙花','張鎡','宋','宋诗','song-poetry','','[]','鯉魚程闊海茫茫，照眼瓊標十二行。',64,'全唐诗/poet.song.171000.json','["鯉魚程闊海茫茫，照眼瓊標十二行。", "礬弟梅兄同舊隠，風姨月姊特新粧。", "湘濱人遠難聞瑟，洛浦才高最斷腸。", "何似香嚴真實處，鼻端無竅著猜量。"]'),
('3543187f-03bf-49dc-a2b6-d7624f18fcfd','贈嗣持上人','張鎡','宋','宋诗','song-poetry','','[]','持也眈眈老比邱，吾如松澗瀑春流。',64,'全唐诗/poet.song.171000.json','["持也眈眈老比邱，吾如松澗瀑春流。", "經年欲見渾無便，連日相逢若舊遊。", "柏子軒窗翻梵夾，荷香亭上款茶甌。", "真成此外無餘事，莫說機關向上頭。"]'),
('786e0a87-f5a4-4a5a-a974-1ad11e5de9ed','贈崇先寺長老','張鎡','宋','宋诗','song-poetry','','[]','飛騎原頭快著鞭，暮溪呼艇訪幽禪。',64,'全唐诗/poet.song.171000.json','["飛騎原頭快著鞭，暮溪呼艇訪幽禪。", "霜輕正屬收橙月，雨霽真成種麥天。", "問答因緣隨處是，推敲事業此生專。", "無塵幸有西偏竹，浴罷從師借枕眠。"]'),
('02c1fe0d-472f-4069-af48-c56245e8b9ca','吳江鮓戶獻鱸','張鎡','宋','宋诗','song-poetry','','[]','舊過吳淞屢買魚，未曾專詠四腮鱸。',64,'全唐诗/poet.song.171000.json','["舊過吳淞屢買魚，未曾專詠四腮鱸。", "鱗鋪雪片銀光細，腹點星文墨暈粗。", "西塞鱖肥空入畫，漢江鯿美阻供厨。", "季鷹莫道休官去，只解思渠絕世無。"]'),
('cbd4c62c-2e75-412d-8e0f-b1a898a68fa4','歸南湖喜成','張鎡','宋','宋诗','song-poetry','','[]','路轉斜橋似夢醒，擁衾摇兀亦身輕。',64,'全唐诗/poet.song.171000.json','["路轉斜橋似夢醒，擁衾摇兀亦身輕。", "知期岸鵲如相語，匿笑隣翁欲鬭迎。", "見處青山還委麽，遮回居士太獃生。", "矮籬半路寒毬樹，新種渾如舊種成。"]'),
('7f174cb5-fcbc-4c06-9b6e-6e7f807c6de0','安溪晚泊因到無浄院','張鎡','宋','宋诗','song-poetry','','[]','十丈亭橋穩踔溪，斜陽紅灧入船低。',64,'全唐诗/poet.song.171000.json','["十丈亭橋穩踔溪，斜陽紅灧入船低。", "枯筇徑過荒街北，靜院深尋破廟西。", "遊伴苦無成獨笑，物情諳遍任難齊。", "歸時早是星煩出，影漾波痕上下迷。"]'),
('068cb06b-83a0-451a-8a3a-4ada08c4c75d','遊南山普寧院院中止有數僧別立堂處村僕幾百人號帥翁道友分執薪水負戴掃除苴補之役暇即乞米贍衆溪南二里許名石口聞冬時梅花甚多','張鎡','宋','宋诗','song-poetry','','[]','入港晴蕪遠際山，鷺羣翻處綠迴環。',64,'全唐诗/poet.song.171000.json','["入港晴蕪遠際山，鷺羣翻處綠迴環。", "林隈隠寺僧慵出，橋底通船客正閒。", "乍喜身心俱寂靜，足憐名相惑愚頑。", "興闌猶約寒梅發，月下來觀側近灣。"]'),
('b69941c0-b789-4f76-b105-af5c6afae2de','宿西菩山明智寺詩','張鎡','宋','宋诗','song-poetry','','[]','路轉溪山果大奇，茂林門徑古苔滋。',64,'全唐诗/poet.song.171000.json','["路轉溪山果大奇，茂林門徑古苔滋。", "坐餘沿石閒聽水，茶罷巡簷遍讀碑。", "飛白灑然前輩字，養魚浴却向來池。", "菖蒲葺葺仙人髮，隨我歸來與靜宜。"]'),
('040e0c86-53e7-4a74-9f78-300d93fbbc30','楊伯時李子永潘茂洪同遊安福寺詩','張鎡','宋','宋诗','song-poetry','','[]','湖濱初試暮春衣，緣逕鐘殘到寺遲。',64,'全唐诗/poet.song.171000.json','["湖濱初試暮春衣，緣逕鐘殘到寺遲。", "二月梅花還傍竹，一時遊客總能詩。", "橫欄著硯爭濡墨，斷石緣蒲靜看池。", "莫問隣亭是誰築，山園持酒本幽期。"]'),
('7e17ae66-6cbb-4c09-96b9-f4d3c71e5b2d','蘆山長老慧舉見訪約遊其臨平庵居自號雲邱草堂因贈四韻','張鎡','宋','宋诗','song-poetry','','[]','此客南湖不易逢，幾年塵外願相從。',64,'全唐诗/poet.song.171000.json','["此客南湖不易逢，幾年塵外願相從。", "風流前輩親曾識，興寄高情老未慵。", "行柳映門宜著舫，青燈同坐到聞鐘。", "稻畦蓮渚臨平境，何幸同師覓舊蹤。"]'),
('1eee4789-1b11-45c4-8456-4d866763a722','過紅城子','張鎡','宋','宋诗','song-poetry','','[]','闊港旁邊狹港橫，大橋側畔小橋平。',64,'全唐诗/poet.song.171000.json','["闊港旁邊狹港橫，大橋側畔小橋平。", "吠人黄耳穿籬走，喚子青裾出戶迎。", "寒日樹枯山得勢，順風檣穩浪無聲。", "自知吟寫紅城景，不讓丹青筆作城。"]'),
('b0714164-1f7e-489f-b9e2-7265ebd84116','暫往吳興出城','張鎡','宋','宋诗','song-poetry','','[]','數聲初聽放船鉦，小雨衝涼晚出城。',64,'全唐诗/poet.song.171000.json','["數聲初聽放船鉦，小雨衝涼晚出城。", "遥見人家層蔭合，便無風袖一塵生。", "園林豈乏清閒樂，鷗鷺須尋浩蕩盟。", "秋色此行方到手，快來詩內發精明。"]'),
('937dd7e3-3765-4d0e-9907-4cc45d942324','薝蔔花盛開因賦四韻','張鎡','宋','宋诗','song-poetry','','[]','桃杏空爲澗上霞，移根爭似覺王家。',64,'全唐诗/poet.song.171000.json','["桃杏空爲澗上霞，移根爭似覺王家。", "衆香不復推沉水，六出分明是雪花。", "柳岸風連荷葉上，葛巾人坐竹陰斜。", "題評更得吾詩後，醒睡從今合勝茶。"]'),
('5bc3cce4-553c-4304-b361-9f6cae22e056','靈源精舍小憩舊名龍泉有古井極甘洌','張鎡','宋','宋诗','song-poetry','','[]','姑惡聲催雨不來，暑雲空際只崔嵬。',64,'全唐诗/poet.song.171000.json','["姑惡聲催雨不來，暑雲空際只崔嵬。", "投鞭得地古佛剎，看竹滿窗風葉堆。", "百歲可堪輕日月，一官纔得便塵埃。", "清泉酌罷猶貪戀，更瀹松黄當茗杯。"]'),
('78a9b28b-8a2d-4ac2-b3c1-5109fb25e200','山寺小憩','張鎡','宋','宋诗','song-poetry','','[]','趨寺松杉夾徑栽，解鞍流憩得莓苔。',64,'全唐诗/poet.song.171000.json','["趨寺松杉夾徑栽，解鞍流憩得莓苔。", "塵昏金篆牌猶掛，燈暗紗籠殿不開。", "老鶴就涼臨古井，幽禽尋食下生臺。", "詩成漫記簷間柱，去矣何時復此來。"]'),
('9b077641-f30e-4cd8-ac56-6f5ee89e0d4b','遊昭慶寺','張鎡','宋','宋诗','song-poetry','','[]','招提徐步已身輕，禮懺僧忙不出迎。',64,'全唐诗/poet.song.171000.json','["招提徐步已身輕，禮懺僧忙不出迎。", "側殿掛燈窺塑像，小廊流水愛經聲。", "心安久矣空塵想，夢異當年記宿生。", "目送繞門山更好，肯閒何處不堪行。"]'),
('06a84ff5-5245-493c-ada5-aabfd5fe6b44','夜宿華藏寺','張鎡','宋','宋诗','song-poetry','','[]','蒼檜陰陰未掩門，閒來吹鬢一飛蚊。',64,'全唐诗/poet.song.171000.json','["蒼檜陰陰未掩門，閒來吹鬢一飛蚊。", "香騰廣殿遊雲合，燈繞長廊列宿分。", "般若心華方照耀，毗耶寶雨自繽紛。", "世緣即是棲禪境，居士何嘗別見聞。"]'),
('7df4cad6-e321-4946-9c61-506699230604','與諸弟遊天竺','張鎡','宋','宋诗','song-poetry','','[]','出門殘月带晨鴉，飛蓋相從縱五花。',64,'全唐诗/poet.song.171000.json','["出門殘月带晨鴉，飛蓋相從縱五花。", "風綽敗蘆依岸老，水分洲渚抱山斜。", "櫜鞬未遂書生志，鐘磬聊尋衲子家。", "何物最能舒望眼，曉雲吹霽不成霞。"]'),
('ebe909e3-4ac7-4fe6-8bec-c5702ca5d437','姑蘇懷古','張鎡','宋','宋诗','song-poetry','','[]','昔年宮殿雨苔荒，花徑無人採舊香。',68,'全唐诗/poet.song.171000.json','["昔年宮殿雨苔荒，花徑無人採舊香。", "宰嚭若能容國士，西施那解誤君王。", "輕寒客子垂雙袖，落日啼烏下女牆。", "成壞不將供一笑，爭如烟外{罒/囨}漁郎。"]'),
('2bc4e4d1-d752-459e-999e-b30c41faef22','平望遇風','張鎡','宋','宋诗','song-poetry','','[]','平望陂湖一望平，當年地羣豈虛名。',64,'全唐诗/poet.song.171000.json','["平望陂湖一望平，當年地羣豈虛名。", "微茫遠樹山同出，破碎層雲日鬭明。", "更著百千寒鴈叫，偏宜三四旅帆征。", "疎簾揭起從風入，要洗頻年鬰滯情。"]'),
('d3762421-c6d1-4ba7-afdb-53b435d2c385','曉出海會過新溪渡','張鎡','宋','宋诗','song-poetry','','[]','喧喧人語俶行裝，廣殿燈寒暗古廊。',64,'全唐诗/poet.song.171000.json','["喧喧人語俶行裝，廣殿燈寒暗古廊。", "橋截漫灘收夜色，路經層岫吐朝陽。", "鱗差白石中流見，櫛比蒼筠夾塢香。", "爽氣正濃詩興薄，歸途應愧挈空囊。"]'),
('c910c929-f853-4d3e-8bdc-b84cbee94e01','寫村舍壁','張鎡','宋','宋诗','song-poetry','','[]','路轉溪隅草色蒼，煙霏雲屋带漁鄉。',64,'全唐诗/poet.song.171000.json','["路轉溪隅草色蒼，煙霏雲屋带漁鄉。", "鷄頭葉老陂塘暗，狗脊花繁籬落香。", "景物向人須品藻，太平無地不耕桑。", "何時秋入豐年社，持蟹來聽壓酒牀。"]'),
('c9031b8c-37ea-4e35-84ab-1a1dfe68eed1','書東遷褚氏壁','張鎡','宋','宋诗','song-poetry','','[]','風晴舒望綠吹林，艤櫂蒿田曲逕深。',64,'全唐诗/poet.song.171000.json','["風晴舒望綠吹林，艤櫂蒿田曲逕深。", "淳朴山川追古俗，蕭閒林谷許幽尋。", "籝金不必多留子，種德先須善用心。", "動我耕耘平日興，濁醪歸緩肯辭斟。"]'),
('dc6934fa-a8d0-4853-84b0-864c7200db84','劉子履少卿挽辭二首  其一','張鎡','宋','宋诗','song-poetry','','[]','氣蓋兩峰蚤食牛，堂堂聲譽冠諸劉。',64,'全唐诗/poet.song.171000.json','["氣蓋兩峰蚤食牛，堂堂聲譽冠諸劉。", "直言不愧上方劍，妙句常輕萬戶侯。", "仙藥了無金鼎效，夢魂空繞玉關秋。", "當時若假三千騎，豈但區區活泰州。"]'),
('c9f475b5-1c97-4258-ad3c-cdd042fac4e8','劉子履少卿挽辭二首  其二','張鎡','宋','宋诗','song-poetry','','[]','釋和書上已經年，敵騎南來果犯邊。',64,'全唐诗/poet.song.171000.json','["釋和書上已經年，敵騎南來果犯邊。", "太息龜靈成底事，漫聞鴻寶得家傳。", "平生喜踏天山雪，晚歲愁看瘴浦烟。", "務實褒稱曾未泯，不須凝恨入重泉。"]'),
('6c0343f0-435f-418b-a8cf-d7c150055f87','南湖二亭落成各書長句一首  其一','張鎡','宋','宋诗','song-poetry','','[]','望處陰雲縱復橫，落梅那更兩關情。',64,'全唐诗/poet.song.171000.json','["望處陰雲縱復橫，落梅那更兩關情。", "清愁入夢時飛蝶，遠樹和煙欲囀鶑。", "多病半春詩債滿，經旬無客酒緣輕。", "湖亭記取初成日，正是菖蒲斫水生。"]'),
('dfa7dfe1-3ce8-42a1-92c5-a9d9ede2a83b','南湖二亭落成各書長句一首  其二','張鎡','宋','宋诗','song-poetry','','[]','不負從今浦浦風，柳陰方稱繫疎篷。',64,'全唐诗/poet.song.171000.json','["不負從今浦浦風，柳陰方稱繫疎篷。", "窗前細雨攤魚網，壁上斜陽曬釣筒。", "肯厭隣僧頻見過，有來巢燕亦相容。", "甘心到老無人采，莫比當年渭水翁。"]'),
('7c982a15-217a-4bee-9d31-7b643c77743e','題王恭父校書新闢書軒','張鎡','宋','宋诗','song-poetry','','[]','仙翁眼力信非凡，到處偏工鑒別山。',64,'全唐诗/poet.song.171000.json','["仙翁眼力信非凡，到處偏工鑒別山。", "消得好烏巢屋上，旋移空翠入窗間。", "平生萬卷端能合，從此三杯不等閒。", "莫訝倏來猶屬意，野人日用實相關。"]'),
('9b644f18-7426-4ae9-976c-136c1c19d0c9','書事','張鎡','宋','宋诗','song-poetry','','[]','剩喜居園野趣成，今春添得四橋橫。',64,'全唐诗/poet.song.171000.json','["剩喜居園野趣成，今春添得四橋橫。", "猿猴漸解擎書策，鸚鵡新能喚佛名。", "酒旆靜垂牆杏雨，茶鐺閒試砌莎晴。", "連年固自窮幽討，新試頻伽一兩聲。"]'),
('49e69b27-171b-43a2-b20a-87a5d11025ea','戲題故袍','張鎡','宋','宋诗','song-poetry','','[]','垂髫便衣綠荷衣，兩見龍飛聖主時。',64,'全唐诗/poet.song.171000.json','["垂髫便衣綠荷衣，兩見龍飛聖主時。", "舉世恩榮俱合換，唯吾憂患只該披。", "收藏儘好隨腰带，提掇應堪傲鬢絲。", "試使著來門外立，精神猶勝似鍾馗。"]'),
('2b06f057-2ad6-4d13-89ef-8f04c43c5c4a','榜書軒曰景白以爐香事樂天像因題律詩六韻其上','張鎡','宋','宋诗','song-poetry','','[]','賢如文正及文忠，迂叟東坡盡學公。',96,'全唐诗/poet.song.171000.json','["賢如文正及文忠，迂叟東坡盡學公。", "自願人才雖太遠，仰希閒樂或相同。", "墅邱寺觀遊須遍，臺榭舟橋樂未窮。", "酩酊酒拚猶欠量，平夷詩效竟無功。", "子遲髮白如先約，官達名高定不逢。", "頼有香山類東剎，西方內院各心空。"]'),
('b86196c2-51be-4b5b-b662-23e4f2de6beb','桂隠紀詠 桂隠','張鎡','宋','宋诗','song-poetry','','[]','未說花開好，團看葉自奇。',24,'全唐诗/poet.song.171000.json','["未說花開好，團看葉自奇。", "明朝非願避，愛樹恐相離。"]'),
('469177c7-a8a6-4441-aed6-b8e696382d80','桂隠紀詠 東寺','張鎡','宋','宋诗','song-poetry','','[]','數舉營巢債，纔成作佛廬。',24,'全唐诗/poet.song.171000.json','["數舉營巢債，纔成作佛廬。", "隨堂展單鉢，均是道人居。"]'),
